import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Dashboard } from './components/Dashboard';
import { Pathologies } from './components/Pathologies';
import { Calculators } from './components/Calculators';
import { Assistant } from './components/Assistant';
import { Glossary } from './components/Glossary';
import { GlobalSearch } from './components/GlobalSearch';
import { Pharmacology } from './components/Pharmacology';
import { NursingProcedures } from './components/NursingProcedures';
import { ClinicalFollowUp } from './components/ClinicalFollowUp';
import { Login } from './components/Login';
import { Settings } from './components/Settings';
import { TeamChat } from './components/TeamChat';
import { ViewState, ViewParams, User } from './types';
import { AuthService } from './services/firebaseMock';

const App: React.FC = () => {
  // Acceso directo: isLoggedIn se inicializa en true
  const [isLoggedIn, setIsLoggedIn] = useState(true);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);
  const [viewParams, setViewParams] = useState<ViewParams>({});
  const [isLoading, setIsLoading] = useState(true);

  // Theme State
  const [theme, setTheme] = useState<'light' | 'dark'>('light');

  // Load Session and Theme
  useEffect(() => {
      // 1. Session check - Si no hay usuario, creamos uno invitado para evitar bloqueos
      let savedUser = AuthService.getCurrentUser();
      if (!savedUser) {
          savedUser = {
              id: 'guest_user',
              email: 'invitado@paesys.com',
              name: 'Invitado Profesional',
              role: 'NURSE',
              unit: 'Urgencias Generales',
              collegiateNumber: '000000',
              avatar: 'https://ui-avatars.com/api/?name=Invitado+Profesional&background=0D9488&color=fff'
          };
          AuthService.createSession(savedUser);
      }
      setCurrentUser(savedUser);
      setIsLoggedIn(true);

      // 2. Theme Preference
      const savedTheme = localStorage.getItem('paesys_theme') as 'light' | 'dark';
      if (savedTheme) {
          setTheme(savedTheme);
      } else if (window.matchMedia('(prefers-color-scheme: dark)').matches) {
          setTheme('dark');
      }

      setIsLoading(false);
  }, []);

  // Apply Theme Class
  useEffect(() => {
      if (theme === 'dark') {
          document.documentElement.classList.add('dark');
      } else {
          document.documentElement.classList.remove('dark');
      }
      localStorage.setItem('paesys_theme', theme);
  }, [theme]);

  const toggleTheme = () => {
      setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  const handleLogin = (user: User) => {
      setIsLoggedIn(true);
      setCurrentUser(user);
      setCurrentView(ViewState.DASHBOARD);
  };

  const handleLogout = () => {
      AuthService.logout();
      // En modo "sin acceso", el logout simplemente limpia y recarga con invitado
      window.location.reload();
  };

  const handleUpdateUser = async (updatedUser: User) => {
      setCurrentUser(updatedUser);
      await AuthService.updateProfile(updatedUser);
  };

  const handleNavigate = (view: ViewState, params?: ViewParams) => {
      if (params) setViewParams(params);
      else setViewParams({}); 
      setCurrentView(view);
  };

  const renderView = () => {
    switch (currentView) {
      case ViewState.DASHBOARD:
        return <Dashboard onNavigate={handleNavigate} />;
      case ViewState.PATHOLOGIES:
        return <Pathologies initialQuery={viewParams.query} initialCategory={viewParams.category} onNavigate={handleNavigate} />;
      case ViewState.PHARMACOLOGY:
        return <Pharmacology initialQuery={viewParams.query} />;
      case ViewState.CALCULATORS:
        return <Calculators initialTool={viewParams.tool} />;
      case ViewState.ASSISTANT:
        return <Assistant onNavigate={handleNavigate} />;
      case ViewState.GLOSSARY:
        return <Glossary />;
      case ViewState.PROCEDURES:
        return <NursingProcedures />;
      case ViewState.FOLLOWUP:
        return <ClinicalFollowUp />;
      case ViewState.SEARCH:
        return <GlobalSearch onNavigate={handleNavigate} />;
      case ViewState.CHAT:
        return <TeamChat currentUser={currentUser!} />;
      case ViewState.SETTINGS:
        return <Settings 
            currentUser={currentUser} 
            onUpdateUser={handleUpdateUser} 
            theme={theme}
            toggleTheme={toggleTheme}
            onLogout={handleLogout}
        />;
      default:
        return <Dashboard onNavigate={handleNavigate} />;
    }
  };

  if (isLoading) {
      return <div className="min-h-screen bg-slate-900 flex items-center justify-center"><div className="w-8 h-8 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin"></div></div>;
  }

  // La lógica de !isLoggedIn se mantiene por integridad estructural pero el estado inicial ahora es siempre true
  if (!isLoggedIn) {
      return <Login onLogin={handleLogin} />;
  }

  return (
    <Layout 
      currentView={currentView} 
      onChangeView={(v, params) => handleNavigate(v, params)}
      onBack={() => handleNavigate(ViewState.DASHBOARD)}
      currentUser={currentUser}
    >
      {renderView()}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Patient, Evolution, ClinicalAnalysis, PatientType, DynamicTask, WoundEntry, ChatMessage, FluidEntry, Prescription, InvasiveDevice, PaeEntry } from '../types';
