// Initialization with Gemini 3 capabilities
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// --- IN-MEMORY CACHE LAYER (SPEED OPTIMIZATION) ---
const RESPONSE_CACHE = new Map<string, any>();

const getFromCache = <T>(key: string): T | undefined => {
    if (RESPONSE_CACHE.has(key)) return RESPONSE_CACHE.get(key) as T;
    return undefined;
};

const setCache = (key: string, data: any) => {
    if (RESPONSE_CACHE.size > 100) {
        const firstKey = RESPONSE_CACHE.keys().next().value;
        if (firstKey) RESPONSE_CACHE.delete(firstKey);
    }
    RESPONSE_CACHE.set(key, data);
};

// --- SYSTEM INSTRUCTIONS ---

const TRIAGE_SYSTEM_INSTRUCTION = `
Eres un sistema experto de triaje clínico de alto rendimiento (Manchester/ESI). 
Analiza la sintomatología para clasificar el riesgo.
Responde SIEMPRE en JSON.
Model: gemini-3-flash-preview.
Niveles: RED (Emergencia), YELLOW (Urgencia), GREEN (No Urgente).
`;

const FLORENCE_V3_INSTRUCTION = `
Eres FLORENCE v3.0, una IA Clínica Avanzada y Mentora de Enfermería.
Tu objetivo es guiar el juicio clínico basándote en la seguridad del paciente (Protocolo S.T.O.P).
Usa Google Search para validar protocolos actuales de 2024-2025.
Responde en JSON estructurado.
`;

// --- API FUNCTIONS ---

export const getClinicalTriage = async (caseDescription: string, imageBase64?: string): Promise<TriageResult> => {
  try {
    const parts: any[] = [];
    if (imageBase64) {
        parts.push({ inlineData: { mimeType: "image/jpeg", data: imageBase64.split(',')[1] } });
        parts.push({ text: `Caso: "${caseDescription}". Clasifica riesgo.` });
    } else {
        parts.push({ text: `Analiza: "${caseDescription}"` });
    }

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview", 
      contents: { role: 'user', parts: parts },
      config: {
        systemInstruction: TRIAGE_SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
      },
    });
    return JSON.parse(response.text || "{}") as TriageResult;
  } catch (error) {
    logger.error('AI:Triage', 'Failed', error);
    throw error;
  }
};

