const ShiftTimeline = ({ patients, onNavigate }: { patients: Patient[], onNavigate: any }) => {
    const timelineItems = useMemo(() => {
        const items: any[] = [];
        patients.forEach(p => {
            p.prescriptions?.forEach(rx => {
                if (rx.status === 'ACTIVE' && rx.nextAdmin) {
                    items.push({
                        time: new Date(rx.nextAdmin),
                        label: rx.drugName,
                        patient: p.name,
                        bed: p.bed,
                        patientId: p.id,
                        type: 'MED',
                        dose: rx.dose
                    });
                }
            });
        });
        return items.sort((a, b) => a.time.getTime() - b.time.getTime()).slice(0, 6);
    }, [patients]);

    return (
        <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm overflow-hidden flex flex-col h-full">
            <div className="px-4 py-3 border-b border-slate-100 dark:border-slate-700 flex justify-between items-center bg-slate-50/50 dark:bg-slate-900/50">
