const QuickStat = ({ label, value, icon: Icon, color, active, onClick, sub, gradient }: any) => (
    <button 
        onClick={onClick}
        className={`flex-none w-[42vw] md:w-auto flex flex-col md:flex-row items-start md:items-center justify-between p-4 rounded-2xl border transition-all group relative overflow-hidden snap-start ${active ? `bg-white dark:bg-slate-800 border-${color.split('-')[1]}-500 ring-1 ring-${color.split('-')[1]}-500 shadow-lg` : 'bg-white dark:bg-slate-800 border-slate-100 dark:border-slate-700 hover:border-slate-300 dark:hover:border-slate-600 shadow-sm'}`}
    >
        <div className="flex flex-col md:flex-row items-start md:items-center gap-3 md:gap-4 relative z-10 w-full">
            <div className={`p-2.5 md:p-3 rounded-xl shadow-md shrink-0 ${gradient || 'bg-indigo-600'}`}>
                <Icon className="w-5 h-5 text-white"/>
            </div>
            <div className="text-left">
                <div className="text-2xl font-black text-slate-800 dark:text-white leading-none tracking-tight">{value}</div>
                <div className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wide mt-1 truncate">{label}</div>
            </div>
        </div>
        {sub && <div className="hidden md:block text-[9px] font-bold bg-slate-100 dark:bg-slate-700 px-2 py-0.5 rounded text-slate-500 dark:text-slate-300 relative z-10">{sub}</div>}
    </button>
);

const ShiftTimeline = ({ patients, onNavigate }: { patients: Patient[], onNavigate: any }) => {
    const timelineItems = useMemo(() => {
        const items: any[] = [];
        patients.forEach(p => {
            p.prescriptions?.forEach(rx => {
                if (rx.status === 'ACTIVE' && rx.nextAdmin) {
                    items.push({
                        time: new Date(rx.nextAdmin),
                        label: rx.drugName,
                        patient: p.name,
                        bed: p.bed,
                        patientId: p.id,
                        type: 'MED',
                        dose: rx.dose
                    });
                }
            });
        });
        return items.sort((a, b) => a.time.getTime() - b.time.getTime()).slice(0, 6);
    }, [patients]);

    return (
        <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm overflow-hidden flex flex-col h-full">
            <div className="px-4 py-3 border-b border-slate-100 dark:border-slate-700 flex justify-between items-center bg-slate-50/50 dark:bg-slate-900/50">
                <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center">
                    <Timer className="w-3 h-3 mr-2 text-indigo-500"/> Línea de Tiempo del Turno
                </h3>
            </div>
            <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar">
                {timelineItems.length > 0 ? timelineItems.map((item, i) => {
                    const isLate = item.time < new Date();
                    return (
                        <div key={i} className="flex gap-4 relative">
                            {i !== timelineItems.length - 1 && <div className="absolute left-[11px] top-6 bottom-0 w-0.5 bg-slate-100 dark:bg-slate-700"></div>}
                            <div className={`w-6 h-6 rounded-full border-4 border-white dark:border-slate-800 shrink-0 z-10 ${isLate ? 'bg-rose-500 shadow-[0_0_8px_rgba(244,63,94,0.4)]' : 'bg-indigo-400'}`}></div>
                            <div className="flex-1 min-w-0 pb-2">
                                <div className="flex justify-between items-start">
                                    <span className={`text-[10px] font-black ${isLate ? 'text-rose-600' : 'text-indigo-600'}`}>
                                        {item.time.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                    </span>
                                    <span className="text-[9px] font-bold text-slate-400 bg-slate-100 dark:bg-slate-700 px-1.5 rounded">{item.bed}</span>
                                </div>
                                <h4 className="text-xs font-black text-slate-800 dark:text-white truncate">{item.label} <span className="font-medium text-slate-500 ml-1">{item.dose}</span></h4>
                                <p className="text-[10px] text-slate-400 truncate mt-0.5">{item.patient}</p>
                            </div>
                            <button onClick={() => onNavigate(ViewState.FOLLOWUP, {patientId: item.patientId})} className="p-2 text-slate-300 hover:text-indigo-500 transition-colors">
                                <ArrowUpRight className="w-4 h-4"/>
                            </button>
                        </div>
                    );
                }) : (
                    <div className="h-full flex flex-col items-center justify-center text-slate-300 py-10">
                        <Check className="w-8 h-8 opacity-20 mb-2"/>
                        <p className="text-[10px] font-black uppercase tracking-widest">Sin tareas próximas</p>
                    </div>
                )}
            </div>
        </div>
    );
};

