    { id: 'MEDS', label: 'Medicación', icon: Pill, color: 'text-blue-600', bg: 'bg-blue-50' },
    { id: 'PAE', label: 'Plan (PAE)', icon: BookOpen, color: 'text-violet-600', bg: 'bg-violet-50' },
    { id: 'LABS', label: 'Analíticas', icon: FlaskConical, color: 'text-purple-600', bg: 'bg-purple-50' },
    { id: 'ACCESS', label: 'Vías/Disp.', icon: Cable, color: 'text-orange-600', bg: 'bg-orange-50' },
    { id: 'WOUNDS', label: 'Heridas', icon: Ruler, color: 'text-rose-600', bg: 'bg-rose-50' },
    { id: 'HANDOFF', label: 'Pase Guardia', icon: Megaphone, color: 'text-amber-600', bg: 'bg-amber-50' },
] as const;

type ModuleId = typeof CLINICAL_MODULES[number]['id'];

export const ClinicalFollowUp: React.FC = () => {
    const [patients, setPatients] = useState<Patient[]>([]);
    const [selectedPatientId, setSelectedPatientId] = useState<string | null>(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [detailTab, setDetailTab] = useState<ModuleId>('NOTES');
    const [isFlorenceOpen, setIsFlorenceOpen] = useState(false);

    // UI State
    const [showCamera, setShowCamera] = useState(false);
    const [cameraMode, setCameraMode] = useState<'SCAN'|'PHOTO'>('SCAN');
    const [showAdmissionModal, setShowAdmissionModal] = useState(false);

    // AI Analysis State
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [analysisResult, setAnalysisResult] = useState<ClinicalAnalysis | null>(null);

    // Note State with Draft Persistence
    const [noteText, setNoteText] = useState(() => {
        return localStorage.getItem('paesys_note_draft_text') || '';
    });
    const [vitalsInput, setVitalsInput] = useState(() => {
        const saved = localStorage.getItem('paesys_note_draft_vitals');
        return saved ? JSON.parse(saved) : { ta: '', fc: '', sat: '', temp: '', gcs: '' };
    });
    const [attachments, setAttachments] = useState<{url:string, label:string, type:'IMAGE'|'AUDIO'}[]>([]);

    // FLORENCE AI STATE
    const [florenceMessages, setFlorenceMessages] = useState<ChatMessage[]>([]);
    const [florenceInput, setFlorenceInput] = useState('');
    const [isFlorenceTyping, setIsFlorenceTyping] = useState(false);
    const chatEndRef = useRef<HTMLDivElement>(null);

    // PERSISTENCE EFFECTS
    useEffect(() => {
        localStorage.setItem('paesys_note_draft_text', noteText);
    }, [noteText]);

    useEffect(() => {
        localStorage.setItem('paesys_note_draft_vitals', JSON.stringify(vitalsInput));
    }, [vitalsInput]);

    // Load Data
    useEffect(() => {
        const load = async () => {
            const data = await PatientService.getAll();
            setPatients(data);
        };
        load();
    }, []);

    const selectedPatient = useMemo(() => patients.find(p => p.id === selectedPatientId), [patients, selectedPatientId]);

    // Group History by Date
    const groupedHistory = useMemo(() => {
        if (!selectedPatient?.history) return {};
        const groups: Record<string, Evolution[]> = {};
        selectedPatient.history.forEach(h => {
            let label = new Date(h.timestamp).toLocaleDateString([], {day: 'numeric', month: 'long'});
            const now = new Date();
            const d = new Date(h.timestamp);
            if (d.getDate() === now.getDate() && d.getMonth() === now.getMonth()) label = 'Hoy';
            if (!groups[label]) groups[label] = [];
            groups[label].push(h);
        });
        return groups;
    }, [selectedPatient?.history]);

    // Handlers
    const handleAddPatient = async (patient: Patient) => {
        await PatientService.admitPatient(patient);
        const data = await PatientService.getAll();
        setPatients(data);
        setShowAdmissionModal(false);
    };

    const handleSaveNote = async () => {
        if (!selectedPatientId || !noteText.trim()) return;
        const newNote: Evolution = {
            id: `ev-${Date.now()}`,
            timestamp: new Date().toISOString(),
            note: noteText,
            vitals: { ...vitalsInput },
            type: 'EVOLUTION',
            riskLevel: 'STABLE', 
            analysis: analysisResult || undefined,
            attachments: attachments
        };
        await PatientService.addEvolution(selectedPatientId, newNote);

        // Optimistic update
        setPatients(prev => prev.map(p => p.id === selectedPatientId ? { ...p, history: [newNote, ...p.history] } : p));

        // Clear Drafts
        setNoteText('');
        setVitalsInput({ ta: '', fc: '', sat: '', temp: '', gcs: '' });
        setAttachments([]);
        setAnalysisResult(null);
        localStorage.removeItem('paesys_note_draft_text');
        localStorage.removeItem('paesys_note_draft_vitals');
    };

    const handleAnalyzeNote = async () => {
        if (!noteText.trim()) return;
        setIsAnalyzing(true);
        try {
            const result = await analyzeClinicalNote(noteText);
            setAnalysisResult(result);
        } catch(e) { console.error(e); }
        finally { setIsAnalyzing(false); }
    };

    const handleVoiceTranscript = (text: string) => {
        setNoteText(prev => prev + " " + text);
    };

    const handleCameraCapture = (data: string) => {
        if(cameraMode === 'PHOTO') {
            setAttachments([...attachments, { url: data, label: 'Imagen', type: 'IMAGE' }]);
        }
        // If SCAN logic needed, add here
    };

    // Sub-component Update Handlers
    const updatePatientData = async (updates: Partial<Patient>) => {
        if(!selectedPatientId) return;
        await PatientService.updatePatient(selectedPatientId, updates);
        setPatients(prev => prev.map(p => p.id === selectedPatientId ? { ...p, ...updates } : p));
    };

    // FLORENCE Logic
    const handleFlorenceSend = async (textOverride?: string) => {
        const text = textOverride || florenceInput;
        if(!text.trim() || !selectedPatient) return;

        const userMsg: ChatMessage = {
            id: Date.now().toString(),
            userId: 'me',
            userName: 'Yo',
            role: 'NURSE',
            text: text,
            timestamp: new Date().toISOString()
        };
        setFlorenceMessages(prev => [...prev, userMsg]);
        setFlorenceInput('');
        setIsFlorenceTyping(true);

        try {
            const response = await generateChatReply(text, 'MENTOR', selectedPatient);
            const aiMsg: ChatMessage = {
                id: 'ai-' + Date.now(),
                userId: 'florence',
                userName: 'Florence AI',
                role: 'ADMIN',
                text: response.answer,
                sources: response.sources,
                timestamp: new Date().toISOString(),
                isSystem: true
            };
            setFlorenceMessages(prev => [...prev, aiMsg]);
        } catch(e) {
            console.error(e);
        } finally {
            setIsFlorenceTyping(false);
        }
    };

    useEffect(() => {
        if(isFlorenceOpen && chatEndRef.current) chatEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }, [florenceMessages, isFlorenceOpen]);

    const openFlorence = () => {
        setIsFlorenceOpen(true);
        if(florenceMessages.length === 0) {
            setFlorenceMessages([{
                id: 'init',
                userId: 'ai',
                userName: 'Florence AI',
                role: 'ADMIN',
                text: `Hola. Estoy revisando el historial de **${selectedPatient?.name}**. ¿En qué puedo ayudarte?`,
                timestamp: new Date().toISOString(),
                isSystem: true
            }]);
        }
    };

    return (
        <div className="flex h-full flex-col bg-slate-100 overflow-hidden relative">
            {/* Header Mobile/Desktop */}
            <header className="bg-white border-b border-slate-200 px-4 py-3 flex justify-between items-center shrink-0 z-20 shadow-sm">
                <div>
                    <h1 className="text-lg font-black text-slate-800 tracking-tight flex items-center">
                        <ClipboardList className="w-5 h-5 mr-2 text-indigo-600"/> Seguimiento
                    </h1>
                    <p className="text-[10px] text-slate-500 font-bold uppercase tracking-wide">Unidad de Hospitalización</p>
                </div>
                <button onClick={() => setShowAdmissionModal(true)} className="bg-indigo-600 text-white px-3 py-2 rounded-xl text-xs font-bold shadow-md hover:bg-indigo-700 transition-all flex items-center active:scale-95">
                    <UserPlus className="w-4 h-4 mr-2"/> <span className="hidden md:inline">Ingreso</span><span className="md:hidden">Nuevo</span>
                </button>
            </header>

            <div className="flex flex-1 overflow-hidden">
                {/* Patient List (Sidebar on Desktop, Full on Mobile if no selection) */}
                <div className={`${selectedPatientId ? 'hidden lg:flex w-80' : 'flex w-full'} flex-col bg-white border-r border-slate-200 z-10 transition-all`}>

                    {/* Search Bar */}
                    <div className="p-3 border-b border-slate-100 sticky top-0 bg-white z-10">
                        <div className="relative">
                            <Search className="absolute left-3 top-2.5 w-4 h-4 text-slate-400"/>
                            <input 
                                value={searchTerm} 
                                onChange={e => setSearchTerm(e.target.value)} 
                                placeholder="Buscar paciente..."
                                className="w-full pl-9 p-2 rounded-xl bg-slate-50 border border-slate-200 text-sm font-bold focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                            />
                        </div>
                    </div>

                    {/* List */}
                    <div className="flex-1 overflow-y-auto custom-scrollbar p-2 space-y-2 bg-slate-50/50">
                        {patients.filter(p => p.name.toLowerCase().includes(searchTerm.toLowerCase())).map(patient => (
                            <button 
                                key={patient.id}
                                onClick={() => setSelectedPatientId(patient.id)}
                                className={`w-full text-left p-0 rounded-xl border transition-all flex overflow-hidden group relative active:scale-[0.98] ${selectedPatientId === patient.id ? 'bg-white border-indigo-500 ring-1 ring-indigo-500 shadow-md z-10' : 'bg-white border-slate-200 hover:border-indigo-300 shadow-sm'}`}
                            >
                                {/* Risk Strip */}
                                <div className={`w-1.5 shrink-0 ${patient.risk === 'HIGH' ? 'bg-rose-500' : patient.risk === 'MEDIUM' ? 'bg-amber-400' : 'bg-emerald-500'}`}></div>

                                <div className="p-3 flex-1 min-w-0">
                                    <div className="flex justify-between items-start mb-1">
                                        <span className="font-black text-sm text-slate-800 truncate pr-2">{patient.name}</span>
                                        <span className="text-[10px] font-bold bg-slate-100 text-slate-600 px-1.5 py-0.5 rounded border border-slate-200">{patient.bed}</span>
                                    </div>
                                    <div className="flex items-center gap-2 text-[10px] text-slate-500 font-medium">
                                        <div className="flex items-center bg-slate-50 px-1.5 py-0.5 rounded border border-slate-100">
                                            {patient.sex === 'M' ? 'H' : 'M'} • {patient.age}a
                                        </div>
                                        <span className="truncate flex-1">{patient.diagnosis}</span>
                                    </div>
                                    <div className="mt-2 flex items-center gap-2">
                                        <span className={`text-[9px] font-black px-1.5 py-0.5 rounded uppercase ${patient.risk === 'HIGH' ? 'text-rose-600 bg-rose-50' : 'text-emerald-600 bg-emerald-50'}`}>
                                            NEWS {patient.news2}
                                        </span>
                                        {patient.isolation && patient.isolation !== 'NONE' && (
                                            <span className="text-[9px] font-black text-amber-600 bg-amber-50 px-1.5 py-0.5 rounded flex items-center">
                                                <ShieldAlert className="w-2.5 h-2.5 mr-1"/> AISL
                                            </span>
                                        )}
                                    </div>
                                </div>
                                <div className="p-2 flex items-center justify-center bg-slate-50 border-l border-slate-100 text-slate-300 group-hover:text-indigo-400 transition-colors">
                                    <ChevronRight className="w-4 h-4"/>
                                </div>
                            </button>
                        ))}
                        {patients.length === 0 && (
                            <div className="text-center py-10 text-slate-400">
                                <p className="text-xs">No hay pacientes registrados.</p>
                            </div>
                        )}
                    </div>
                </div>

                {/* Detail View */}
                {selectedPatient ? (
                    <div className="flex-1 flex flex-col bg-slate-50 relative overflow-hidden h-full">

                        {/* Sticky Header */}
                        <div className="bg-white border-b border-slate-200 shadow-sm shrink-0 z-10">
                            <div className="px-4 py-3 flex justify-between items-start">
                                <div className="flex items-center gap-3 overflow-hidden">
                                    <button onClick={() => setSelectedPatientId(null)} className="lg:hidden p-2 -ml-2 rounded-full hover:bg-slate-100 text-slate-500">
                                        <ArrowLeft className="w-5 h-5"/>
                                    </button>
                                    <div className="min-w-0">
                                        <div className="flex items-baseline gap-2">
                                            <h2 className="text-lg font-black text-slate-900 truncate">{selectedPatient.name}</h2>
                                            <span className="bg-slate-900 text-white text-[10px] font-bold px-2 py-0.5 rounded">{selectedPatient.bed}</span>
                                        </div>
                                        <div className="flex items-center gap-2 text-xs text-slate-500 overflow-x-auto no-scrollbar">
                                            <span className="whitespace-nowrap">{selectedPatient.age} años</span>
                                            <span className="text-slate-300">|</span>
                                            <span className="whitespace-nowrap font-medium text-rose-600 truncate max-w-[150px]">{selectedPatient.allergies}</span>
                                            <span className="text-slate-300">|</span>
                                            <span className="whitespace-nowrap">{selectedPatient.weight} kg</span>
                                        </div>
                                    </div>
                                </div>
                                <button onClick={openFlorence} className="bg-gradient-to-r from-violet-600 to-indigo-600 text-white p-2 rounded-xl shadow-md hover:shadow-lg transition-all active:scale-95 shrink-0">
                                    <Bot className="w-5 h-5"/>
                                </button>
                            </div>

                            {/* Scrollable Tabs */}
                            <div className="flex px-4 gap-4 overflow-x-auto no-scrollbar border-t border-slate-50">
                                {CLINICAL_MODULES.map(m => (
                                    <button
                                        key={m.id}
                                        onClick={() => setDetailTab(m.id)}
                                        className={`py-3 text-xs font-bold uppercase border-b-2 transition-all flex items-center whitespace-nowrap ${detailTab === m.id ? `border-${m.color.split('-')[1]}-600 ${m.color.split(' ')[0]}` : 'border-transparent text-slate-400 hover:text-slate-600'}`}
                                    >
                                        <m.icon className="w-3.5 h-3.5 mr-2"/> {m.label}
                                    </button>
                                ))}
                            </div>
                        </div>

                        {/* Module Content Area */}
                        <div className="flex-1 overflow-y-auto p-4 md:p-6 custom-scrollbar pb-24 md:pb-6 relative bg-slate-50/50">

                            {detailTab === 'NOTES' && (
                                <div className="space-y-6 max-w-4xl mx-auto">
                                    {/* Note Input Card */}
                                    <div className="bg-white p-4 rounded-2xl border border-slate-200 shadow-sm transition-shadow hover:shadow-md">
                                        <div className="flex justify-between items-center mb-3">
                                            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center">
                                                <PenTool className="w-3 h-3 mr-2"/> Nueva Evolución
                                            </h3>
                                            <div className="flex gap-2">
                                                <button onClick={() => {setShowCamera(true); setCameraMode('PHOTO');}} className="p-2 bg-slate-50 rounded-lg text-slate-500 hover:text-indigo-600 transition-colors" title="Añadir Foto">
                                                    <Camera className="w-4 h-4"/>
                                                </button>
                                                <VoiceInput onTranscript={handleVoiceTranscript} isCompact />
                                            </div>
                                        </div>
                                        <textarea 
                                            value={noteText} 
                                            onChange={e => setNoteText(e.target.value)} 
                                            placeholder="Escribe la evolución del turno..." 
                                            className="w-full min-h-[100px] bg-slate-50 border-0 rounded-xl p-3 text-sm focus:ring-2 focus:ring-indigo-500/20 outline-none resize-none placeholder-slate-400 transition-all mb-3"
                                        />

                                        {/* Attachments Preview */}
                                        {attachments.length > 0 && (
                                            <div className="flex gap-2 mb-3 overflow-x-auto pb-2">
                                                {attachments.map((att, i) => (
                                                    <div key={i} className="relative w-16 h-16 rounded-lg overflow-hidden border border-slate-200 shrink-0 group">
                                                        <img src={att.url} className="w-full h-full object-cover"/>
                                                        <button onClick={() => setAttachments(prev => prev.filter((_, idx) => idx !== i))} className="absolute top-0 right-0 bg-black/50 text-white p-0.5 rounded-bl opacity-0 group-hover:opacity-100 transition-opacity">
                                                            <X className="w-3 h-3"/>
                                                        </button>
                                                    </div>
                                                ))}
                                            </div>
                                        )}

                                        {/* AI Analysis Result */}
                                        {analysisResult && (
                                            <div className="bg-indigo-50/50 rounded-xl p-3 mb-3 border border-indigo-100 text-xs animate-fade-in">
                                                <div className="flex gap-2 mb-2 flex-wrap">
                                                    {analysisResult.detectedRisks.map((r, i) => (
                                                        <span key={i} className="bg-rose-100 text-rose-700 px-2 py-0.5 rounded font-bold border border-rose-200">{r}</span>
                                                    ))}
                                                </div>
                                                <p className="text-slate-600 italic">"{analysisResult.sbarSummary}"</p>
                                            </div>
                                        )}

                                        <div className="flex justify-between items-center pt-2 border-t border-slate-100">
                                            <button onClick={handleAnalyzeNote} disabled={!noteText.trim() || isAnalyzing} className="text-xs font-bold text-indigo-600 flex items-center hover:bg-indigo-50 px-3 py-1.5 rounded-lg transition-colors disabled:opacity-50">
                                                {isAnalyzing ? <Loader2 className="w-3 h-3 animate-spin mr-1.5"/> : <Sparkles className="w-3 h-3 mr-1.5"/>}
                                                Analizar IA
                                            </button>
                                            <button onClick={handleSaveNote} disabled={!noteText.trim()} className="bg-indigo-600 text-white px-6 py-2 rounded-xl text-xs font-bold shadow-md hover:bg-indigo-700 transition-all active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed">
                                                GUARDAR
                                            </button>
                                        </div>
                                    </div>

                                    {/* History Timeline */}
                                    <div className="space-y-6 pl-2">
                                        {Object.entries(groupedHistory).map(([date, entries]) => (
                                            <div key={date} className="relative border-l-2 border-slate-200 ml-2 space-y-4 pb-2">
                                                <div className="absolute -left-[21px] top-0 bg-slate-100 border-2 border-slate-200 rounded-full px-2 py-0.5 text-[10px] font-black text-slate-500 uppercase">
                                                    {date}
                                                </div>
                                                <div className="pt-6 space-y-3">
                                                    {entries.map(h => (
                                                        <div key={h.id} className="relative ml-4 bg-white p-4 rounded-xl border border-slate-200 shadow-sm hover:border-indigo-200 transition-colors group">
                                                            <div className="absolute -left-[23px] top-5 w-3 h-3 bg-slate-300 rounded-full border-2 border-white group-hover:bg-indigo-400 transition-colors"></div>
                                                            <div className="flex justify-between items-start mb-2">
                                                                <span className="text-[10px] font-black text-slate-400 uppercase bg-slate-50 px-1.5 py-0.5 rounded">
                                                                    {new Date(h.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}
                                                                </span>
                                                                {h.riskLevel && h.riskLevel !== 'STABLE' && (
                                                                    <AlertTriangle className="w-4 h-4 text-amber-500"/>
                                                                )}
                                                            </div>
                                                            <p className="text-sm text-slate-700 leading-relaxed whitespace-pre-wrap">{h.note}</p>
                                                            {h.attachments && h.attachments.length > 0 && (
                                                                <div className="mt-3 flex gap-2 overflow-x-auto">
                                                                    {h.attachments.map((att, idx) => (
                                                                        <img key={idx} src={att.url} className="h-16 rounded border border-slate-100"/>
                                                                    ))}
                                                                </div>
                                                            )}
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}

                            {detailTab === 'MONITOR' && <VitalSigns history={selectedPatient.history} />}
                            {detailTab === 'MEDS' && <MedicationSheet prescriptions={selectedPatient.prescriptions || []} onUpdate={p => updatePatientData({prescriptions: p})} />}
                            {detailTab === 'PAE' && <CarePlanManager carePlans={selectedPatient.activePae || []} onUpdate={p => updatePatientData({activePae: p})} />}
                            {detailTab === 'LABS' && <LabResults reports={selectedPatient.labReports || []} />}
                            {detailTab === 'ACCESS' && <AccessManager devices={selectedPatient.activeDevices || []} onUpdate={d => updatePatientData({activeDevices: d})} />}
                            {detailTab === 'WOUNDS' && <WoundAnalysis wounds={selectedPatient.wounds || []} onAddWound={w => updatePatientData({wounds: [w, ...(selectedPatient.wounds||[])]})} />}
                            {detailTab === 'HANDOFF' && <ShiftHandoff patient={selectedPatient} onSendToChat={handleFlorenceSend} />}
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 hidden md:flex flex-col items-center justify-center bg-slate-50/50 text-slate-300">
                        <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center shadow-sm mb-4">
                            <User className="w-10 h-10 opacity-20"/>
                        </div>
                        <p className="text-sm font-black uppercase tracking-widest">Selecciona un paciente</p>
                    </div>
                )}
            </div>

            {/* Florence AI Drawer (Overlay) */}
            {isFlorenceOpen && selectedPatient && (
                <div className="fixed inset-0 z-50 flex justify-end">
                    <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm transition-opacity" onClick={() => setIsFlorenceOpen(false)}></div>
                    <div className="w-full md:w-[450px] bg-white h-full shadow-2xl relative flex flex-col animate-slide-in-right">
                        <div className="p-4 bg-slate-900 text-white flex justify-between items-center shadow-md shrink-0">
                            <div className="flex items-center gap-3">
                                <div className="relative">
                                    <div className="w-10 h-10 bg-white rounded-full p-0.5">
                                        <img src="https://ui-avatars.com/api/?name=Florence+AI&background=7c3aed&color=fff" className="w-full h-full rounded-full"/>
                                    </div>
                                    <div className="absolute bottom-0 right-0 w-3 h-3 bg-emerald-500 border-2 border-slate-900 rounded-full"></div>
                                </div>
                                <div>
                                    <h3 className="font-bold text-sm">Florence AI</h3>
                                    <p className="text-[10px] text-slate-400 font-medium">Asistente Contextual</p>
                                </div>
                            </div>
                            <button onClick={() => setIsFlorenceOpen(false)} className="p-2 hover:bg-slate-800 rounded-full transition-colors"><X className="w-5 h-5"/></button>
                        </div>

                        <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-100">
                            {florenceMessages.map((msg, i) => (
                                <div key={i} className={`flex ${msg.role === 'NURSE' ? 'justify-end' : 'justify-start'} animate-fade-in-up`}>
                                    <div className={`max-w-[85%] p-3.5 rounded-2xl text-sm shadow-sm relative ${msg.role === 'NURSE' ? 'bg-indigo-600 text-white rounded-br-none' : 'bg-white border border-slate-200 text-slate-700 rounded-bl-none'}`}>
                                        <p className="whitespace-pre-wrap leading-relaxed">{msg.text}</p>

                                        {/* Sources Rendering */}
                                        {msg.sources && msg.sources.length > 0 && (
                                            <div className="mt-3 pt-2 border-t border-slate-100/50">
                                                <div className="flex flex-wrap gap-1.5">
                                                    {/* Fix: Explicitly cast sources to avoid "unknown" map error */}
                                                    {(msg.sources as Array<{title: string, uri: string}>).map((src, idx) => (
                                                        <a key={idx} href={src.uri} target="_blank" rel="noreferrer" className="flex items-center gap-1 bg-black/5 hover:bg-black/10 px-2 py-1 rounded text-[10px] font-bold text-slate-600 truncate max-w-[150px] transition-colors">
                                                            <Globe className="w-3 h-3"/> {src.title}
                                                        </a>
                                                    ))}
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                </div>
                            ))}
                            {isFlorenceTyping && (
                                <div className="flex justify-start pl-2">
                                    <div className="bg-white p-3 rounded-2xl rounded-tl-none shadow-sm flex gap-1 items-center">
                                        <span className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce"></span>
                                        <span className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
                                        <span className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
                                    </div>
                                </div>
                            )}
                            <div ref={chatEndRef}></div>
                        </div>

                        <div className="p-3 bg-white border-t border-slate-200">
                            <form onSubmit={(e) => { e.preventDefault(); handleFlorenceSend(); }} className="relative flex items-end gap-2">
                                <input 
                                    className="flex-1 bg-slate-100 border-transparent focus:bg-white border focus:border-indigo-300 rounded-xl px-4 py-3 text-sm focus:ring-4 focus:ring-indigo-50 transition-all outline-none" 
