                                    <Send className="w-5 h-5"/>
                                </button>
                            </form>
                        </div>
                    </div>
                </div>
            )}

            {/* Modals */}
            {showAdmissionModal && <AdmissionModal onClose={() => setShowAdmissionModal(false)} onSave={handleAddPatient} />}
            {showCamera && <CameraCapture mode={cameraMode} onCapture={handleCameraCapture} onClose={() => setShowCamera(false)} />}
        </div>
    );
};

import { GoogleGenAI, Type } from "@google/genai";
import { TriageResult, Pathology, Drug, ClinicalAnalysis, DynamicTask, WoundAnalysisResult, Patient } from "../types";
import { logger } from "./logger";

// Initialization with Gemini 3 capabilities
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// --- SYSTEM INSTRUCTIONS ---

const TRIAGE_SYSTEM_INSTRUCTION = `
Eres un sistema experto de triaje clínico de alto rendimiento (Manchester/ESI). 
Analiza la sintomatología para clasificar el riesgo. Responde SIEMPRE en JSON.
Model: gemini-3-flash-preview.
Niveles: RED (Emergencia), YELLOW (Urgencia), GREEN (No Urgente).
`;

const FLORENCE_V3_INSTRUCTION = `
Eres FLORENCE v3.0, una IA Clínica Avanzada y Mentora de Enfermería.
Tu objetivo es guiar el juicio clínico basándote en la seguridad del paciente (Protocolo S.T.O.P).
Usa Google Search para validar protocolos actuales de 2024-2025.
Responde en JSON estructurado que incluya: reasoning, answer, confidence y criticalAlert.
`;

// --- API FUNCTIONS ---

export const getClinicalTriage = async (caseDescription: string, imageBase64?: string): Promise<TriageResult> => {
  try {
    const parts: any[] = [];
    if (imageBase64) {
        parts.push({ inlineData: { mimeType: "image/jpeg", data: imageBase64.split(',')[1] } });
        parts.push({ text: `Caso: "${caseDescription}". Clasifica riesgo.` });
    } else {
        parts.push({ text: `Analiza: "${caseDescription}"` });
    }

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview", 
      contents: { role: 'user', parts: parts },
      config: {
        systemInstruction: TRIAGE_SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
      },
    });
    return JSON.parse(response.text || "{}") as TriageResult;
  } catch (error) {
    logger.error('AI:Triage', 'Failed', error);
    throw error;
  }
};

export const generatePathology = async (query: string): Promise<Pathology> => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `Genera ficha clínica completa para: "${query}". Usa Google Search para evidencia.`,
            config: {
                responseMimeType: "application/json",
                tools: [{ googleSearch: {} }]
            }
        });
        const sources: { title: string, uri: string }[] = [];
        if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
            response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
                if (chunk.web) sources.push({ title: chunk.web.title, uri: chunk.web.uri });
            });
        }
        const parsed = JSON.parse(response.text || "{}") as Pathology;
        parsed.sources = sources;
        return parsed;
    } catch (error) {
        throw error;
    }
};

export const generateDrugDetails = async (drugName: string): Promise<Drug> => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `Genera Ficha Técnica Parenteral para: "${drugName}".`,
            config: { responseMimeType: "application/json" }
        });
        return JSON.parse(response.text || "{}") as Drug;
    } catch (error) {
        throw error;
    }
};

export interface FlorenceResponse {
    reasoning: string;
    answer: string;
    confidence: 'HIGH' | 'MEDIUM' | 'LOW';
    criticalAlert?: string;
    suggestedActions?: { label: string, view: string, params?: any }[];
    sources?: { title: string, uri: string }[];
}

export const generateChatReply = async (userMessage: string, personaKey: string, patientContext?: Patient): Promise<FlorenceResponse> => {
    try {
        let contextBlock = patientContext ? `DATOS PACIENTE: ${patientContext.name}, Dx: ${patientContext.diagnosis}, NEWS2: ${patientContext.news2}, Meds: ${patientContext.prescriptions?.map(p => p.drugName).join(', ')}` : "";

        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `${contextBlock}\n\nCONSULTA: "${userMessage}". Responde con rigor científico.`,
            config: {
                systemInstruction: FLORENCE_V3_INSTRUCTION,
                responseMimeType: "application/json",
                tools: [{ googleSearch: {} }]
            }
        });

        const sources: { title: string, uri: string }[] = [];
        if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
            response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
                if (chunk.web) sources.push({ title: chunk.web.title, uri: chunk.web.uri });
            });
        }

        const parsed = JSON.parse(response.text || "{}") as FlorenceResponse;
        if (sources.length > 0) parsed.sources = sources;
        return parsed;

    } catch (error) {
        return { reasoning: "Error", answer: "Error de conexión con el núcleo clínico.", confidence: "LOW" };
    }
};

export const searchMedicalKnowledge = async (query: string): Promise<{ text: string, sources: { title: string, uri: string }[] }> => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `Define brevemente con rigor: "${query}".`,
            config: { tools: [{ googleSearch: {} }] }
        });
        const sources: { title: string, uri: string }[] = [];
        if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
            response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
                if (chunk.web) sources.push({ title: chunk.web.title, uri: chunk.web.uri });
            });
        }
        return { text: response.text || "", sources };
    } catch (error) { return { text: "Error de búsqueda.", sources: [] }; }
};

