                                  <button onClick={() => onNavigate(ViewState.FOLLOWUP, {patientId: patient.id})} className="flex-1 bg-indigo-600 text-white py-2.5 rounded-xl text-[10px] font-black shadow-lg shadow-indigo-600/20 hover:bg-indigo-700 transition-all flex items-center justify-center gap-2 uppercase tracking-wide">
                                      <PenTool className="w-3.5 h-3.5"/> Evolución
                                  </button>
                              </div>
                          </div>
                      ))}
