                                    </div>
                                    <div className="absolute -bottom-1 -right-1 w-4 h-4 bg-emerald-500 border-4 border-slate-900 rounded-full"></div>
                                </div>
                                <div>
                                    <h3 className="font-black text-lg tracking-tight uppercase">Florence v3 <span className="text-indigo-400 text-xs ml-1">PRO</span></h3>
                                    <div className="flex items-center gap-2">
