                        {/* AI Feed */}
                        <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar bg-slate-100/50">
                            {florenceMessages.map((msg, i) => {
                                const isMe = msg.role === 'NURSE';
                                const structuredData = !isMe ? (msg.text?.startsWith('{') ? JSON.parse(msg.text) : null) : null;
                                const text = structuredData ? structuredData.answer : msg.text;

                                return (
                                    <div key={i} className={`flex ${isMe ? 'justify-end' : 'justify-start'} animate-fade-in-up`}>
                                        <div className={`max-w-[90%] p-5 rounded-3xl text-sm shadow-xl relative border ${
