                                    <div className="bg-white p-4 rounded-3xl rounded-tl-none shadow-lg flex flex-col gap-2">
                                        <div className="flex gap-1.5">
                                            <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
                                            <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
                                            <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></span>
                                        </div>
                                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Validando fuentes...</span>
                                    </div>
                                </div>
                            )}
                            <div ref={chatEndRef}></div>
                        </div>

                        {/* AI Input Area */}
                        <div className="p-6 bg-white border-t border-slate-200 shadow-inner">
                            <form onSubmit={(e) => { e.preventDefault(); handleFlorenceSend(); }} className="relative flex items-center gap-3">
