                                    <button type="button" className="p-3 text-slate-400 hover:text-indigo-600 transition-colors"><Mic className="w-5 h-5"/></button>
                                    <input 
                                        className="flex-1 bg-transparent border-none focus:ring-0 outline-none text-sm font-bold text-slate-700 px-2" 
                                        placeholder="Consultar guías, dosis o riesgos..." 
                                        value={florenceInput} 
                                        onChange={e => setFlorenceInput(e.target.value)}
                                    />
                                </div>
                                <button type="submit" disabled={!florenceInput.trim() || isFlorenceTyping} className="p-4 bg-slate-900 text-white rounded-full shadow-2xl hover:bg-black transition-all active:scale-95 disabled:opacity-50">
                                    <Send className="w-5 h-5"/>
                                </button>
                            </form>
                        </div>
                    </div>
                </div>
            )}

            {/* Modals */}
            {showAdmissionModal && <AdmissionModal onClose={() => setShowAdmissionModal(false)} onSave={handleAddPatient} />}
            {showCamera && <CameraCapture mode="PHOTO" onCapture={url => setAttachments([...attachments, {url, label:'Imagen', type:'IMAGE'}])} onClose={() => setShowCamera(false)} />}
        </div>
    );
};

