export interface FlorenceResponse {
    reasoning: string;
    answer: string;
    confidence: 'HIGH' | 'MEDIUM' | 'LOW';
    criticalAlert?: string;
    suggestedActions?: { label: string, view: string, params?: any }[];
    sources?: { title: string, uri: string }[];
}

export const generateChatReply = async (userMessage: string, personaKey: string, patientContext?: Patient): Promise<FlorenceResponse> => {
    try {
        let contextBlock = patientContext ? `CONTEXTO PACIENTE: ${patientContext.name}, Dx: ${patientContext.diagnosis}, NEWS2: ${patientContext.news2}, Meds: ${patientContext.prescriptions?.map(p => p.drugName).join(', ')}` : "";

        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `${contextBlock}\n\nCONSULTA: "${userMessage}". Responde con rigor científico y JSON.`,
            config: {
                systemInstruction: FLORENCE_V3_INSTRUCTION,
                responseMimeType: "application/json",
                tools: [{ googleSearch: {} }]
            }
        });

        const sources: { title: string, uri: string }[] = [];
        if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
            response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
                if (chunk.web) sources.push({ title: chunk.web.title, uri: chunk.web.uri });
            });
        }

        const parsed = JSON.parse(response.text || "{}") as FlorenceResponse;
        if (sources.length > 0) parsed.sources = sources;
        return parsed;

    } catch (error) {
        return { reasoning: "Error", answer: "Error de comunicación con el núcleo cognitivo.", confidence: "LOW" };
    }
};

