                                                                    {h.riskLevel === 'CRITICAL' && <AlertTriangle className="w-6 h-6 text-rose-500 animate-pulse"/>}
                                                                </div>

                                                                <p className="text-base font-medium text-slate-700 leading-relaxed whitespace-pre-wrap">{h.note}</p>

                                                                {h.analysis?.suggestedNanda && (
                                                                    <div className="mt-6 pt-6 border-t border-slate-50 flex flex-wrap gap-3">
                                                                        {(h.analysis.suggestedNanda as string[]).slice(0, 3).map((n, idx) => (
                                                                            <span key={idx} className="bg-emerald-50 text-emerald-800 px-4 py-1.5 rounded-full text-[10px] font-black uppercase border border-emerald-100 flex items-center shadow-sm">
                                                                                <ShieldCheck className="w-3.5 h-3.5 mr-2 text-emerald-500"/> {n}
                                                                            </span>
                                                                        ))}
                                                                    </div>
