                                                            </div>
                                                        ))}
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                )}

                                {detailTab === 'MONITOR' && <VitalSigns history={selectedPatient.history} />}
                                {detailTab === 'MEDS' && <MedicationSheet prescriptions={selectedPatient.prescriptions || []} onUpdate={p => updatePatientData({prescriptions: p})} />}
                                {detailTab === 'PAE' && <CarePlanManager carePlans={selectedPatient.activePae || []} onUpdate={p => updatePatientData({activePae: p})} />}
                                {detailTab === 'LABS' && <LabResults reports={selectedPatient.labReports || []} />}
                                {detailTab === 'ACCESS' && <AccessManager devices={selectedPatient.activeDevices || []} onUpdate={d => updatePatientData({activeDevices: d})} />}
                                {detailTab === 'WOUNDS' && <WoundAnalysis wounds={selectedPatient.wounds || []} onAddWound={w => updatePatientData({wounds: [w, ...(selectedPatient.wounds||[])]})} />}
                                {detailTab === 'HANDOFF' && <ShiftHandoff patient={selectedPatient} onSendToChat={handleFlorenceSend} />}
                            </div>
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 hidden md:flex flex-col items-center justify-center bg-slate-50/50 text-slate-300">
                        <div className="w-40 h-40 bg-white rounded-full flex items-center justify-center shadow-2xl border border-slate-100 mb-8">
                            <User className="w-16 h-16 opacity-10"/>
                        </div>
                        <p className="text-base font-black uppercase tracking-[0.4em]">Seleccione un Paciente del Censo</p>
                    </div>
                )}
            </div>

            {/* Florence AI v3 Floating Side-Over */}
            {isFlorenceOpen && selectedPatient && (
                <div className="fixed inset-0 z-50 flex justify-end">
                    <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm transition-opacity" onClick={() => setIsFlorenceOpen(false)}></div>
                    <div className="w-full md:w-[580px] bg-slate-50 h-full shadow-[0_0_120px_rgba(0,0,0,0.6)] relative flex flex-col animate-slide-in-right overflow-hidden border-l border-white/10">

                        {/* Advanced AI Header */}
                        <div className="p-7 bg-slate-900 text-white flex justify-between items-center shadow-2xl shrink-0 relative overflow-hidden">
                            <div className="absolute top-0 right-0 w-80 h-80 bg-indigo-500/20 rounded-full -mr-40 -mt-40 blur-3xl"></div>
                            <div className="flex items-center gap-5 relative z-10">
                                <div className="relative">
                                    <div className="w-16 h-16 bg-white rounded-2xl p-0.5 shadow-2xl rotate-2">
                                        <img src="https://ui-avatars.com/api/?name=Florence+AI&background=7c3aed&color=fff" className="w-full h-full rounded-[0.8rem] shadow-inner"/>
                                    </div>
                                    <div className="absolute -bottom-1 -right-1 w-5 h-5 bg-emerald-500 border-4 border-slate-900 rounded-full shadow-lg"></div>
                                </div>
                                <div>
                                    <h3 className="font-black text-xl tracking-tight uppercase">Florence AI <span className="text-indigo-400 text-xs ml-2 border border-indigo-500/50 px-2 py-0.5 rounded-full">v3.0 PRO</span></h3>
                                    <div className="flex items-center gap-3 mt-1">
                                        <div className="flex items-center text-[10px] font-black text-indigo-300 bg-indigo-500/20 px-2.5 py-1 rounded-full border border-indigo-500/30 shadow-inner">
                                            <Globe className="w-3.5 h-3.5 mr-2"/> EVIDENCE GROUNDING ACTIVO
                                        </div>
                                    </div>
                                </div>
                            </div>
                            <button onClick={() => setIsFlorenceOpen(false)} className="p-3 hover:bg-white/10 rounded-full transition-colors relative z-10 border border-white/10"><X className="w-6 h-6"/></button>
                        </div>

                        {/* AI Conversation Feed */}
                        <div className="flex-1 overflow-y-auto p-6 space-y-8 custom-scrollbar bg-slate-100/30">
                            {florenceMessages.map((msg, i) => {
                                const isMe = msg.role === 'NURSE';
                                let structuredData = null;
                                if (!isMe) {
                                    try {
                                        structuredData = msg.text?.startsWith('{') ? JSON.parse(msg.text) : null;
                                    } catch(e) { structuredData = null; }
                                }
                                const text = structuredData ? structuredData.answer : msg.text;

                                return (
                                    <div key={i} className={`flex ${isMe ? 'justify-end' : 'justify-start'} animate-fade-in-up`}>
                                        <div className={`max-w-[92%] p-6 rounded-[2rem] text-base shadow-2xl relative border ${
                                            isMe 
                                                ? 'bg-indigo-600 text-white rounded-br-none border-indigo-500 shadow-indigo-500/20' 
                                                : 'bg-white border-slate-200 text-slate-800 rounded-bl-none shadow-slate-200/50'
                                        }`}>
                                            {!isMe && structuredData && (
                                                <div className="flex items-center justify-between mb-4 pb-3 border-b border-slate-100">
                                                    <span className="text-[11px] font-black text-violet-600 flex items-center gap-2 uppercase tracking-[0.15em]"><ShieldCheck className="w-4 h-4"/> JUICIO CLÍNICO IA</span>
                                                    <span className={`text-[9px] font-black px-2.5 py-1 rounded-lg border ${structuredData.confidence === 'HIGH' ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 'bg-amber-50 text-amber-700 border-amber-200'}`}>FIABILIDAD: {structuredData.confidence}</span>
                                                </div>
                                            )}

                                            <div className="whitespace-pre-wrap leading-relaxed font-medium">
                                                {text.split(/(\*\*.*?\*\*)/g).map((part, idx) => 
                                                    part.startsWith('**') ? <strong key={idx} className={isMe ? "text-white" : "text-slate-900 font-black"}>{part.slice(2, -2)}</strong> : part
                                                )}
                                            </div>

                                            {/* Evidence Card rendering */}
                                            {!isMe && structuredData?.sources && (
                                                <div className="mt-6 pt-5 border-t border-slate-100">
                                                    <p className="text-[10px] font-black text-slate-400 uppercase mb-4 tracking-[0.2em]">Evidencia y Fuentes de Consulta:</p>
                                                    <div className="space-y-3">
                                                        {(structuredData.sources as any[]).map((src, idx) => (
                                                            <a key={idx} href={src.uri} target="_blank" rel="noreferrer" className="flex items-center gap-4 bg-slate-50 hover:bg-indigo-50 border border-slate-200 p-4 rounded-2xl transition-all group/link shadow-sm">
                                                                <div className="bg-white p-2 rounded-xl border border-slate-100 group-hover/link:text-indigo-600 shadow-inner"><Globe className="w-4 h-4"/></div>
                                                                <div className="flex-1 min-w-0">
                                                                    <div className="text-xs font-black text-slate-700 truncate">{src.title}</div>
                                                                    <div className="text-[10px] text-slate-400 font-mono flex items-center mt-1">
                                                                        {new URL(src.uri).hostname} <ExternalLink className="w-3 h-3 ml-2 opacity-50"/>
                                                                    </div>
                                                                </div>
                                                            </a>
                                                        ))}
                                                    </div>
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                );
                            })}
                            {isFlorenceTyping && (
                                <div className="flex justify-start pl-2">
                                    <div className="bg-white p-5 rounded-[2rem] rounded-tl-none shadow-xl flex flex-col gap-3 border border-slate-100">
                                        <div className="flex gap-2">
                                            <span className="w-2.5 h-2.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
                                            <span className="w-2.5 h-2.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
                                            <span className="w-2.5 h-2.5 bg-indigo-400 rounded-full animate-bounce"></span>
                                        </div>
                                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest animate-pulse">Analizando Evidencia...</span>
                                    </div>
                                </div>
                            )}
                            <div ref={chatEndRef}></div>
                        </div>

                        {/* Professional Input Console */}
                        <div className="p-7 bg-white border-t border-slate-200 shadow-2xl">
                            <form onSubmit={(e) => { e.preventDefault(); handleFlorenceSend(); }} className="relative flex items-center gap-4">
                                <div className="flex-1 bg-slate-100 rounded-[2.5rem] p-2 flex items-center border-2 border-transparent focus-within:border-indigo-500/20 focus-within:bg-white transition-all shadow-inner group">
                                    <button type="button" className="p-3 text-slate-400 hover:text-indigo-600 transition-colors"><Mic className="w-6 h-6"/></button>
                                    <input 
                                        className="flex-1 bg-transparent border-none focus:ring-0 outline-none text-base font-bold text-slate-700 px-3" 
                                        placeholder="Consultar guías, dosis o compatibilidad..." 
                                        value={florenceInput} 
                                        onChange={e => setFlorenceInput(e.target.value)}
                                    />
                                </div>
                                <button type="submit" disabled={!florenceInput.trim() || isFlorenceTyping} className="p-5 bg-slate-900 text-white rounded-full shadow-[0_15px_30px_rgba(15,23,42,0.3)] hover:bg-black transition-all active:scale-95 disabled:opacity-50 group">
                                    <Send className="w-6 h-6 group-hover:translate-x-0.5 group-hover:-translate-y-0.5 transition-transform"/>
                                </button>
                            </form>
                        </div>
                    </div>
                </div>
            )}

            {/* Application Modals */}
            {showAdmissionModal && <AdmissionModal onClose={() => setShowAdmissionModal(false)} onSave={handleAddPatient} />}
            {showCamera && <CameraCapture mode="PHOTO" onCapture={url => setAttachments([...attachments, {url, label:'Evidencia Visual', type:'IMAGE'}])} onClose={() => setShowCamera(false)} />}
        </div>
    );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Patient, Evolution, ClinicalAnalysis, ChatMessage } from '../types';
import { analyzeClinicalNote, generateChatReply } from '../services/geminiService';
import { PatientService } from '../services/firebaseMock';
// Added missing CheckCircle2 import
import { ClipboardList, Search, User, AlertCircle, Monitor, Pill, BookOpen, FlaskConical, Cable, Megaphone, Ruler, PenTool, Activity, ShieldAlert, ArrowLeft, Bot, Send, X, Globe, Sparkles, Loader2, ChevronRight, Camera, Mic, Volume2, ShieldCheck, ExternalLink, Calendar, Clock, AlertTriangle, UserPlus, CheckCircle2 } from 'lucide-react';
import { VoiceInput } from './VoiceInput';
import { CameraCapture } from './CameraCapture';
import { WoundAnalysis } from './WoundAnalysis';
import { MedicationSheet } from './MedicationSheet';
import { VitalSigns } from './VitalSigns';
import { AccessManager } from './AccessManager';
import { LabResults } from './LabResults';
import { CarePlanManager } from './CarePlanManager';
import { ShiftHandoff } from './ShiftHandoff';
import { AdmissionModal } from './AdmissionModal';

// MODULE CONFIGURATION
const CLINICAL_MODULES = [
    { id: 'NOTES', label: 'Evolución', icon: PenTool, color: 'text-indigo-600', bg: 'bg-indigo-50' },
    { id: 'MONITOR', label: 'Monitor', icon: Monitor, color: 'text-emerald-600', bg: 'bg-emerald-50' },
    { id: 'MEDS', label: 'Fármacos', icon: Pill, color: 'text-blue-600', bg: 'bg-blue-50' },
    { id: 'PAE', label: 'PAE', icon: BookOpen, color: 'text-violet-600', bg: 'bg-violet-50' },
    { id: 'LABS', label: 'Lab.', icon: FlaskConical, color: 'text-purple-600', bg: 'bg-purple-50' },
    { id: 'ACCESS', label: 'Disp.', icon: Cable, color: 'text-orange-600', bg: 'bg-orange-50' },
    { id: 'WOUNDS', label: 'Heridas', icon: Ruler, color: 'text-rose-600', bg: 'bg-rose-50' },
    { id: 'HANDOFF', label: 'Pase', icon: Megaphone, color: 'text-amber-600', bg: 'bg-amber-50' },
] as const;

type ModuleId = typeof CLINICAL_MODULES[number]['id'];

export const ClinicalFollowUp: React.FC = () => {
    const [patients, setPatients] = useState<Patient[]>([]);
    const [selectedPatientId, setSelectedPatientId] = useState<string | null>(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [detailTab, setDetailTab] = useState<ModuleId>('NOTES');
    const [isFlorenceOpen, setIsFlorenceOpen] = useState(false);

    // UI State
    const [showCamera, setShowCamera] = useState(false);
    const [showAdmissionModal, setShowAdmissionModal] = useState(false);

    // AI Analysis State
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [analysisResult, setAnalysisResult] = useState<ClinicalAnalysis | null>(null);

    // Note State
    const [noteText, setNoteText] = useState('');
    const [vitalsInput, setVitalsInput] = useState({ ta: '', fc: '', sat: '', temp: '', gcs: '' });
    const [attachments, setAttachments] = useState<{url:string, label:string, type:'IMAGE'|'AUDIO'}[]>([]);

    // FLORENCE AI STATE
    const [florenceMessages, setFlorenceMessages] = useState<ChatMessage[]>([]);
    const [florenceInput, setFlorenceInput] = useState('');
    const [isFlorenceTyping, setIsFlorenceTyping] = useState(false);
    const chatEndRef = useRef<HTMLDivElement>(null);

    // Load Data
    useEffect(() => {
        const load = async () => {
            const data = await PatientService.getAll();
            setPatients(data);
        };
        load();
    }, []);

    const selectedPatient = useMemo(() => patients.find(p => p.id === selectedPatientId), [patients, selectedPatientId]);

    // Group History by Date
    const groupedHistory = useMemo(() => {
        if (!selectedPatient?.history) return {};
        const groups: Record<string, Evolution[]> = {};
        selectedPatient.history.forEach(h => {
            let label = new Date(h.timestamp).toLocaleDateString([], {day: 'numeric', month: 'long'});
            const now = new Date();
            const d = new Date(h.timestamp);
            if (d.getDate() === now.getDate() && d.getMonth() === now.getMonth()) label = 'Hoy';
            if (!groups[label]) groups[label] = [];
            groups[label].push(h);
        });
        return groups;
    }, [selectedPatient?.history]);

    // Handlers
    const handleAddPatient = async (patient: Patient) => {
        await PatientService.admitPatient(patient);
        const data = await PatientService.getAll();
        setPatients(data);
        setShowAdmissionModal(false);
    };

    const handleSaveNote = async () => {
        if (!selectedPatientId || !noteText.trim()) return;
        const newNote: Evolution = {
            id: `ev-${Date.now()}`,
            timestamp: new Date().toISOString(),
            note: noteText,
            vitals: { ...vitalsInput },
            type: 'EVOLUTION',
            riskLevel: 'STABLE', 
            analysis: analysisResult || undefined,
            attachments: attachments
        };
        await PatientService.addEvolution(selectedPatientId, newNote);
        setPatients(prev => prev.map(p => p.id === selectedPatientId ? { ...p, history: [newNote, ...p.history] } : p));
        setNoteText('');
        setVitalsInput({ ta: '', fc: '', sat: '', temp: '', gcs: '' });
        setAttachments([]);
        setAnalysisResult(null);
    };

    const handleAnalyzeNote = async () => {
        if (!noteText.trim()) return;
        setIsAnalyzing(true);
        try {
            const result = await analyzeClinicalNote(noteText);
            setAnalysisResult(result);
        } catch(e) { console.error(e); }
        finally { setIsAnalyzing(false); }
    };

    const updatePatientData = async (updates: Partial<Patient>) => {
        if(!selectedPatientId) return;
        await PatientService.updatePatient(selectedPatientId, updates);
        setPatients(prev => prev.map(p => p.id === selectedPatientId ? { ...p, ...updates } : p));
    };

    // FLORENCE v3 Logic
    const handleFlorenceSend = async (textOverride?: string) => {
        const text = textOverride || florenceInput;
        if(!text.trim() || !selectedPatient) return;

        const userMsg: ChatMessage = {
            id: Date.now().toString(),
            userId: 'me',
            userName: 'Yo',
            role: 'NURSE',
            text: text,
            timestamp: new Date().toISOString()
        };
        setFlorenceMessages(prev => [...prev, userMsg]);
        setFlorenceInput('');
        setIsFlorenceTyping(true);

        try {
            const response = await generateChatReply(text, 'MENTOR', selectedPatient);
            const aiMsg: ChatMessage = {
                id: 'ai-' + Date.now(),
                userId: 'florence',
                userName: 'Florence AI',
                role: 'ADMIN',
                text: response.answer,
                sources: response.sources,
                timestamp: new Date().toISOString(),
                isSystem: true
            };
            setFlorenceMessages(prev => [...prev, aiMsg]);
        } catch(e) {
            console.error(e);
        } finally {
            setIsFlorenceTyping(false);
        }
    };

    const openFlorence = () => {
        setIsFlorenceOpen(true);
        if(florenceMessages.length === 0) {
            setFlorenceMessages([{
                id: 'init',
                userId: 'ai',
                userName: 'Florence AI',
                role: 'ADMIN',
                text: `He revisado el perfil de **${selectedPatient?.name}**. Estoy lista para asistirte con juicio clínico basado en evidencia.`,
                timestamp: new Date().toISOString(),
                isSystem: true
            }]);
        }
    };

    return (
        <div className="flex h-full flex-col bg-slate-100 overflow-hidden relative font-sans">
            {/* Header Desktop / Mobile Unified */}
            <header className="bg-slate-900 text-white border-b border-slate-800 px-6 py-4 flex justify-between items-center shrink-0 z-20 shadow-xl">
                <div className="flex items-center gap-3">
                    <div className="bg-indigo-600 p-2 rounded-xl shadow-lg">
                        <ClipboardList className="w-5 h-5"/>
                    </div>
                    <div>
                        <h1 className="text-lg font-black tracking-tight uppercase">Hospital OS <span className="text-indigo-400">Clinical Suite</span></h1>
                        <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Unidad de Vigilancia Activa</p>
                    </div>
                </div>
                <button onClick={() => setShowAdmissionModal(true)} className="bg-emerald-600 hover:bg-emerald-700 text-white px-5 py-2.5 rounded-xl text-xs font-black shadow-lg shadow-emerald-900/20 transition-all flex items-center active:scale-95 border border-emerald-500">
                    <UserPlus className="w-4 h-4 mr-2"/> ADMITIR PACIENTE
                </button>
            </header>

            <div className="flex flex-1 overflow-hidden">
                {/* Patient List Drawer (Hidden on mobile when selecting) */}
                <div className={`${selectedPatientId ? 'hidden lg:flex w-96' : 'flex w-full'} flex-col bg-white border-r border-slate-200 z-10 transition-all shadow-xl`}>

                    <div className="p-5 border-b border-slate-100 sticky top-0 bg-white z-10">
