export const getClinicalTriage = async (caseDescription: string, imageBase64?: string): Promise<TriageResult> => {
  try {
    const parts: any[] = [];
    if (imageBase64) {
        parts.push({ inlineData: { mimeType: "image/jpeg", data: imageBase64.split(',')[1] } });
        parts.push({ text: `Caso: "${caseDescription}". Clasifica riesgo.` });
    } else {
        parts.push({ text: `Analiza: "${caseDescription}"` });
    }

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview", 
      contents: { role: 'user', parts: parts },
      config: {
        systemInstruction: TRIAGE_SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
      },
    });
    return JSON.parse(response.text || "{}") as TriageResult;
  } catch (error) {
    logger.error('AI:Triage', 'Failed', error);
    throw error;
  }
};

export const generatePathology = async (query: string): Promise<Pathology> => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `Genera ficha clínica completa para: "${query}". Usa Google Search para evidencia reciente.`,
            config: {
                responseMimeType: "application/json",
                tools: [{ googleSearch: {} }]
            }
        });
        const sources: { title: string, uri: string }[] = [];
        if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
            response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
                if (chunk.web) sources.push({ title: chunk.web.title, uri: chunk.web.uri });
            });
        }
        const parsed = JSON.parse(response.text || "{}") as Pathology;
        parsed.sources = sources;
        return parsed;
    } catch (error) {
        throw error;
    }
};

