export const analyzeWoundImage = async (imageBase64: string): Promise<WoundAnalysisResult> => {
    const imagePart = { inlineData: { mimeType: 'image/jpeg', data: imageBase64.split(',')[1] } };
    const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: { role: 'user', parts: [imagePart, { text: "Analiza dimensiones, tejido y signos de infección de esta herida." }] },
        config: { responseMimeType: "application/json" }
    });
    return JSON.parse(response.text || "{}") as WoundAnalysisResult;
};

