const ShiftTimeline = ({ patients, onNavigate }: { patients: Patient[], onNavigate: any }) => {
    const timelineItems = useMemo(() => {
        const items: any[] = [];
        patients.forEach(p => {
            p.prescriptions?.forEach(rx => {
                if (rx.status === 'ACTIVE' && rx.nextAdmin) {
                    items.push({
                        time: new Date(rx.nextAdmin),
                        label: rx.drugName,
                        patient: p.name,
                        bed: p.bed,
                        patientId: p.id,
                        type: 'MED',
                        dose: rx.dose
                    });
                }
            });
        });
        return items.sort((a, b) => a.time.getTime() - b.time.getTime()).slice(0, 6);
    }, [patients]);

    return (
        <div className="bg-white dark:bg-slate-800 rounded-3xl border border-slate-200 dark:border-slate-700 shadow-sm overflow-hidden flex flex-col h-full">
            <div className="px-5 py-4 border-b border-slate-100 dark:border-slate-700 flex justify-between items-center bg-slate-50/50 dark:bg-slate-900/50">
                <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center">
                    <Timer className="w-3 h-3 mr-2 text-indigo-500"/> Smart Shift Timeline
                </h3>
                <div className="flex gap-1">
                    <div className="w-1.5 h-1.5 rounded-full bg-rose-500"></div>
                    <div className="w-1.5 h-1.5 rounded-full bg-amber-500"></div>
                    <div className="w-1.5 h-1.5 rounded-full bg-emerald-500"></div>
                </div>
            </div>
            <div className="flex-1 overflow-y-auto p-5 space-y-5 custom-scrollbar">
                {timelineItems.length > 0 ? timelineItems.map((item, i) => {
                    const now = new Date();
                    const isLate = item.time < now;
                    const isUrgent = (item.time.getTime() - now.getTime()) < 30 * 60000;

                    return (
                        <div key={i} className="flex gap-4 relative group cursor-pointer" onClick={() => onNavigate(ViewState.FOLLOWUP, {patientId: item.patientId})}>
                            {i !== timelineItems.length - 1 && <div className="absolute left-[11px] top-6 bottom-[-20px] w-0.5 bg-slate-100 dark:bg-slate-700"></div>}
                            <div className={`w-6 h-6 rounded-full border-4 border-white dark:border-slate-800 shrink-0 z-10 transition-transform group-hover:scale-110 ${isLate ? 'bg-rose-500 shadow-[0_0_8px_rgba(244,63,94,0.4)]' : isUrgent ? 'bg-amber-400 animate-pulse' : 'bg-indigo-400'}`}></div>
                            <div className="flex-1 min-w-0 pb-1">
                                <div className="flex justify-between items-start">
                                    <span className={`text-[10px] font-black ${isLate ? 'text-rose-600' : isUrgent ? 'text-amber-600' : 'text-indigo-600'}`}>
                                        {item.time.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                    </span>
                                    <span className="text-[9px] font-bold text-slate-400 bg-slate-100 dark:bg-slate-700 px-2 py-0.5 rounded-full">{item.bed}</span>
                                </div>
                                <h4 className="text-xs font-black text-slate-800 dark:text-white truncate mt-0.5">{item.label} <span className="font-medium text-slate-400 ml-1">({item.dose})</span></h4>
                                <p className="text-[10px] text-slate-500 dark:text-slate-400 truncate mt-0.5 flex items-center">
                                    <Users className="w-2.5 h-2.5 mr-1"/> {item.patient}
                                </p>
                            </div>
                        </div>
                    );
                }) : (
                    <div className="h-full flex flex-col items-center justify-center text-slate-300 py-10">
                        <CheckCircle2 className="w-10 h-10 opacity-10 mb-2"/>
                        <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">Sin tareas críticas próximas</p>
                    </div>
                )}
            </div>
        </div>
    );
};

