                  <ShiftTimeline patients={myPatients} onNavigate={onNavigate} />
              </div>

              {/* QUICK OPERATIONS */}
              <div className="bg-white dark:bg-slate-900 p-6 rounded-[2rem] border border-slate-200 dark:border-slate-800 shadow-sm">
                  <h3 className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-[0.2em] mb-5 flex items-center">
                      <Zap className="w-3.5 h-3.5 mr-2 text-amber-500"/> Centro de Operaciones
                  </h3>
                  <div className="grid grid-cols-2 gap-4">
                      <button onClick={() => onNavigate(ViewState.PATHOLOGIES)} className="p-4 rounded-2xl bg-indigo-50 dark:bg-indigo-900/20 border border-indigo-100 dark:border-indigo-800 flex flex-col items-center gap-3 hover:bg-indigo-100 transition-all group">
                          <div className="bg-white dark:bg-indigo-900 p-2.5 rounded-xl shadow-sm group-hover:scale-110 transition-transform">
                            <BookOpen className="w-6 h-6 text-indigo-600"/>
                          </div>
                          <span className="text-[10px] font-black uppercase text-indigo-700 dark:text-indigo-300">Biblioteca</span>
                      </button>
                      <button onClick={() => onNavigate(ViewState.CALCULATORS)} className="p-4 rounded-2xl bg-emerald-50 dark:bg-emerald-900/20 border border-emerald-100 dark:border-emerald-800 flex flex-col items-center gap-3 hover:bg-emerald-100 transition-all group">
                          <div className="bg-white dark:bg-emerald-900 p-2.5 rounded-xl shadow-sm group-hover:scale-110 transition-transform">
                            <Calculator className="w-6 h-6 text-emerald-600"/>
                          </div>
                          <span className="text-[10px] font-black uppercase text-emerald-700 dark:text-emerald-300">Escalas</span>
                      </button>
                  </div>

                  <div className="mt-5 p-4 bg-slate-50 dark:bg-slate-800 rounded-2xl border border-slate-100 dark:border-slate-700">
                    <div className="flex items-center justify-between mb-2">
                        <span className="text-[10px] font-black text-slate-400 uppercase">Carga de Turno (Unit)</span>
                        <span className={`text-xs font-black ${workloadIndex > 70 ? 'text-rose-600' : 'text-indigo-600'}`}>{workloadIndex}%</span>
                    </div>
                    <div className="h-1.5 bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden">
                        <div className={`h-full transition-all duration-1000 rounded-full ${workloadIndex > 70 ? 'bg-rose-500' : 'bg-indigo-500'}`} style={{width: `${workloadIndex}%`}}></div>
                    </div>
                  </div>
              </div>
          </div>

      </div>

      {isAdmitting && (
          <AdmissionModal onClose={() => setIsAdmitting(false)} onSave={async (p) => { await PatientService.admitPatient(p); loadData(); setIsAdmitting(false); }} />
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Patient, Evolution, ClinicalAnalysis, ChatMessage } from '../types';
