    { id: 'PAE', label: 'PAE', icon: BookOpen, color: 'text-violet-600', bg: 'bg-violet-50' },
    { id: 'LABS', label: 'Lab.', icon: FlaskConical, color: 'text-purple-600', bg: 'bg-purple-50' },
    { id: 'ACCESS', label: 'Disp.', icon: Cable, color: 'text-orange-600', bg: 'bg-orange-50' },
    { id: 'WOUNDS', label: 'Heridas', icon: Ruler, color: 'text-rose-600', bg: 'bg-rose-50' },
    { id: 'HANDOFF', label: 'Pase', icon: Megaphone, color: 'text-amber-600', bg: 'bg-amber-50' },
] as const;

type ModuleId = typeof CLINICAL_MODULES[number]['id'];

export const ClinicalFollowUp: React.FC = () => {
    const [patients, setPatients] = useState<Patient[]>([]);
    const [selectedPatientId, setSelectedPatientId] = useState<string | null>(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [detailTab, setDetailTab] = useState<ModuleId>('NOTES');
    const [isFlorenceOpen, setIsFlorenceOpen] = useState(false);

    // UI State
    const [showCamera, setShowCamera] = useState(false);
    const [showAdmissionModal, setShowAdmissionModal] = useState(false);

    // AI Analysis State
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [analysisResult, setAnalysisResult] = useState<ClinicalAnalysis | null>(null);

    // Note State
    const [noteText, setNoteText] = useState('');
    const [vitalsInput, setVitalsInput] = useState({ ta: '', fc: '', sat: '', temp: '', gcs: '' });
    const [attachments, setAttachments] = useState<{url:string, label:string, type:'IMAGE'|'AUDIO'}[]>([]);

    // FLORENCE AI STATE
    const [florenceMessages, setFlorenceMessages] = useState<ChatMessage[]>([]);
    const [florenceInput, setFlorenceInput] = useState('');
    const [isFlorenceTyping, setIsFlorenceTyping] = useState(false);
    const chatEndRef = useRef<HTMLDivElement>(null);

    // Load Data
    useEffect(() => {
        const load = async () => {
            const data = await PatientService.getAll();
            setPatients(data);
        };
        load();
    }, []);

    const selectedPatient = useMemo(() => patients.find(p => p.id === selectedPatientId), [patients, selectedPatientId]);

    // Group History by Date
    const groupedHistory = useMemo(() => {
        if (!selectedPatient?.history) return {};
        const groups: Record<string, Evolution[]> = {};
        selectedPatient.history.forEach(h => {
            let label = new Date(h.timestamp).toLocaleDateString([], {day: 'numeric', month: 'long'});
            const now = new Date();
            const d = new Date(h.timestamp);
            if (d.getDate() === now.getDate() && d.getMonth() === now.getMonth()) label = 'Hoy';
            if (!groups[label]) groups[label] = [];
            groups[label].push(h);
        });
        return groups;
    }, [selectedPatient?.history]);

    // Handlers
    const handleAddPatient = async (patient: Patient) => {
        await PatientService.admitPatient(patient);
        const data = await PatientService.getAll();
        setPatients(data);
        setShowAdmissionModal(false);
    };

    const handleSaveNote = async () => {
        if (!selectedPatientId || !noteText.trim()) return;
        const newNote: Evolution = {
            id: `ev-${Date.now()}`,
            timestamp: new Date().toISOString(),
            note: noteText,
            vitals: { ...vitalsInput },
            type: 'EVOLUTION',
            riskLevel: 'STABLE', 
            analysis: analysisResult || undefined,
            attachments: attachments
        };
        await PatientService.addEvolution(selectedPatientId, newNote);
        setPatients(prev => prev.map(p => p.id === selectedPatientId ? { ...p, history: [newNote, ...p.history] } : p));
        setNoteText('');
        setVitalsInput({ ta: '', fc: '', sat: '', temp: '', gcs: '' });
        setAttachments([]);
        setAnalysisResult(null);
    };

    const handleAnalyzeNote = async () => {
        if (!noteText.trim()) return;
        setIsAnalyzing(true);
        try {
            const result = await analyzeClinicalNote(noteText);
            setAnalysisResult(result);
        } catch(e) { console.error(e); }
        finally { setIsAnalyzing(false); }
    };

    const updatePatientData = async (updates: Partial<Patient>) => {
        if(!selectedPatientId) return;
        await PatientService.updatePatient(selectedPatientId, updates);
        setPatients(prev => prev.map(p => p.id === selectedPatientId ? { ...p, ...updates } : p));
    };

    // FLORENCE v3 Logic
    const handleFlorenceSend = async (textOverride?: string) => {
        const text = textOverride || florenceInput;
        if(!text.trim() || !selectedPatient) return;

        const userMsg: ChatMessage = {
            id: Date.now().toString(),
            userId: 'me',
            userName: 'Yo',
            role: 'NURSE',
            text: text,
            timestamp: new Date().toISOString()
        };
        setFlorenceMessages(prev => [...prev, userMsg]);
        setFlorenceInput('');
        setIsFlorenceTyping(true);

        try {
            const response = await generateChatReply(text, 'MENTOR', selectedPatient);
            const aiMsg: ChatMessage = {
                id: 'ai-' + Date.now(),
                userId: 'florence',
                userName: 'Florence AI',
                role: 'ADMIN',
                text: response.answer,
                sources: response.sources,
                timestamp: new Date().toISOString(),
                isSystem: true
            };
            setFlorenceMessages(prev => [...prev, aiMsg]);
        } catch(e) {
            console.error(e);
        } finally {
            setIsFlorenceTyping(false);
        }
    };

    const openFlorence = () => {
        setIsFlorenceOpen(true);
        if(florenceMessages.length === 0) {
            setFlorenceMessages([{
                id: 'init',
                userId: 'ai',
                userName: 'Florence AI',
                role: 'ADMIN',
                text: `He revisado el perfil de **${selectedPatient?.name}**. Estoy lista para asistirte con juicio clínico basado en evidencia y búsqueda en tiempo real.`,
                timestamp: new Date().toISOString(),
                isSystem: true
            }]);
        }
    };

    return (
        <div className="flex h-full flex-col bg-slate-100 overflow-hidden relative font-sans">
            {/* Header Desktop / Mobile Unified */}
            <header className="bg-slate-900 text-white border-b border-slate-800 px-6 py-4 flex justify-between items-center shrink-0 z-20 shadow-xl">
                <div className="flex items-center gap-3">
                    <div className="bg-indigo-600 p-2 rounded-xl shadow-lg">
                        <ClipboardList className="w-5 h-5"/>
                    </div>
                    <div>
                        <h1 className="text-lg font-black tracking-tight uppercase">Hospital OS <span className="text-indigo-400">Clinical Suite</span></h1>
                        <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Unidad de Vigilancia Activa</p>
                    </div>
                </div>
                <button onClick={() => setShowAdmissionModal(true)} className="bg-emerald-600 hover:bg-emerald-700 text-white px-5 py-2.5 rounded-xl text-xs font-black shadow-lg shadow-emerald-900/20 transition-all flex items-center active:scale-95 border border-emerald-500">
                    <UserPlus className="w-4 h-4 mr-2"/> ADMITIR PACIENTE
                </button>
            </header>

            <div className="flex-1 overflow-hidden">
                {/* Patient List Drawer (Hidden on mobile when selecting) */}
                <div className={`${selectedPatientId ? 'hidden lg:flex w-96' : 'flex w-full'} flex-col bg-white border-r border-slate-200 z-10 transition-all shadow-xl h-full`}>

                    <div className="p-5 border-b border-slate-100 sticky top-0 bg-white z-10">
                        <div className="relative group">
                            <Search className="absolute left-4 top-3.5 w-4 h-4 text-slate-400 group-focus-within:text-indigo-600 transition-colors"/>
                            <input 
                                value={searchTerm} 
                                onChange={e => setSearchTerm(e.target.value)} 
                                placeholder="Buscar cama o nombre..."
                                className="w-full pl-11 pr-4 py-3 rounded-2xl bg-slate-50 border border-slate-200 text-sm font-bold focus:ring-4 focus:ring-indigo-50/10 focus:bg-white outline-none transition-all placeholder:text-slate-400 shadow-inner"
                            />
                        </div>
                    </div>

                    <div className="flex-1 overflow-y-auto custom-scrollbar p-3 space-y-3 bg-slate-50/50">
                        {patients.filter(p => p.name.toLowerCase().includes(searchTerm.toLowerCase())).map(patient => (
                            <button 
                                key={patient.id}
                                onClick={() => setSelectedPatientId(patient.id)}
                                className={`w-full text-left p-0 rounded-2xl border transition-all flex overflow-hidden group relative active:scale-[0.98] ${selectedPatientId === patient.id ? 'bg-white border-indigo-500 ring-2 ring-indigo-100 shadow-xl z-10' : 'bg-white border-slate-200 hover:border-indigo-300 shadow-sm'}`}
                            >
                                <div className={`w-1.5 shrink-0 ${patient.risk === 'HIGH' ? 'bg-rose-500 animate-pulse' : patient.risk === 'MEDIUM' ? 'bg-amber-400' : 'bg-emerald-500'}`}></div>

                                <div className="p-4 flex-1 min-w-0">
                                    <div className="flex justify-between items-start mb-2">
                                        <span className="font-black text-sm text-slate-800 truncate pr-2 uppercase tracking-tight">{patient.name}</span>
                                        <span className="text-[10px] font-black bg-slate-900 text-white px-2 py-0.5 rounded shadow-sm">{patient.bed}</span>
                                    </div>
                                    <div className="flex items-center gap-2 text-[10px] text-slate-500 font-bold uppercase tracking-tighter">
                                        <div className="flex items-center bg-slate-100 px-1.5 py-0.5 rounded border border-slate-200">
                                            {patient.sex === 'M' ? 'H' : 'M'} • {patient.age}a
                                        </div>
                                        <span className="truncate flex-1 text-indigo-600">{patient.diagnosis}</span>
                                    </div>
                                    <div className="mt-3 flex items-center gap-2">
                                        <span className={`text-[10px] font-black px-2 py-0.5 rounded border ${patient.risk === 'HIGH' ? 'text-rose-600 bg-rose-50 border-rose-100' : 'text-emerald-600 bg-emerald-50 border-emerald-100'}`}>
                                            NEWS2 {patient.news2}
                                        </span>
                                        {patient.isolation && patient.isolation !== 'NONE' && (
                                            <span className="text-[10px] font-black text-amber-600 bg-amber-50 px-2 py-0.5 rounded border border-amber-100 flex items-center">
                                                <ShieldAlert className="w-3 h-3 mr-1"/> AISL.
                                            </span>
                                        )}
                                    </div>
                                </div>
                                <div className="p-3 flex items-center justify-center bg-slate-50 border-l border-slate-100 text-slate-300 group-hover:text-indigo-500 transition-colors">
                                    <ChevronRight className="w-5 h-5"/>
                                </div>
                            </button>
                        ))}
                    </div>
                </div>

                {/* Detail View Container */}
                {selectedPatient ? (
                    <div className="flex-1 flex flex-col bg-slate-50 relative overflow-hidden h-full">

                        {/* Header Detail Clinical Dashboard */}
                        <div className="bg-white border-b border-slate-200 shadow-sm shrink-0 z-10 p-4 md:p-6">
                            <div className="flex justify-between items-start gap-4">
                                <div className="flex items-center gap-5 overflow-hidden">
                                    <button onClick={() => setSelectedPatientId(null)} className="lg:hidden p-2.5 bg-slate-100 rounded-full text-slate-500 active:scale-90 transition-transform">
                                        <ArrowLeft className="w-5 h-5"/>
                                    </button>
                                    <div className="min-w-0">
                                        <div className="flex items-center gap-3 mb-1">
                                            <h2 className="text-xl md:text-3xl font-black text-slate-900 truncate uppercase tracking-tighter">{selectedPatient.name}</h2>
                                            <div className="flex items-center gap-2">
                                                <span className="bg-indigo-600 text-white text-[10px] font-black px-3 py-1 rounded-full shadow-lg shadow-indigo-600/30">{selectedPatient.bed}</span>
                                                {selectedPatient.risk === 'HIGH' && <div className="bg-rose-500 w-3 h-3 rounded-full animate-ping shadow-[0_0_10px_rgba(244,63,94,0.6)]"></div>}
                                            </div>
                                        </div>
                                        <div className="flex items-center gap-3 text-xs font-black uppercase text-slate-400 overflow-x-auto no-scrollbar whitespace-nowrap">
                                            <span>{selectedPatient.age} Años</span>
                                            <span className="text-slate-200">|</span>
                                            <span className="text-rose-600 bg-rose-50 px-2 py-0.5 rounded border border-rose-100 flex items-center shadow-sm"><ShieldAlert className="w-3 h-3 mr-1"/> Alergias: {selectedPatient.allergies}</span>
                                            <span className="text-slate-200">|</span>
                                            <span>Peso: {selectedPatient.weight} kg</span>
                                        </div>
                                    </div>
                                </div>
                                <button onClick={openFlorence} className="bg-gradient-to-tr from-violet-600 to-indigo-700 text-white p-3.5 rounded-2xl shadow-xl shadow-indigo-600/30 hover:scale-105 active:scale-95 transition-all shrink-0 relative group">
                                    <div className="absolute -inset-1 bg-gradient-to-tr from-violet-400 to-indigo-400 rounded-2xl blur opacity-0 group-hover:opacity-40 transition-opacity"></div>
                                    <Bot className="w-6 h-6 relative z-10"/>
                                </button>
                            </div>

                            {/* HIGH-DENSITY NAVIGATION TABS */}
                            <div className="flex gap-2 mt-6 overflow-x-auto no-scrollbar scroll-smooth">
                                {CLINICAL_MODULES.map(m => (
                                    <button
                                        key={m.id}
                                        onClick={() => setDetailTab(m.id)}
                                        className={`px-4 py-2.5 rounded-xl text-xs font-black uppercase tracking-wider transition-all flex items-center whitespace-nowrap border-2 ${detailTab === m.id ? `bg-slate-900 text-white border-slate-900 shadow-xl` : 'bg-white text-slate-500 border-slate-100 hover:border-slate-200 hover:bg-slate-50'}`}
                                    >
                                        <m.icon className={`w-4 h-4 mr-2 ${detailTab === m.id ? 'text-indigo-400' : m.color}`}/> 
                                        {m.label}
                                    </button>
                                ))}
                            </div>
                        </div>

                        {/* Content Area with High Contrast Scrollable Panel */}
                        <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar bg-slate-50/50 pb-32">
                            <div className="max-w-6xl mx-auto">

                                {detailTab === 'NOTES' && (
                                    <div className="space-y-8 animate-fade-in">
                                        {/* AI PROACTIVE INSIGHT PANEL */}
                                        {analysisResult && (
                                            <div className="bg-indigo-900 text-white p-6 rounded-[2.5rem] shadow-2xl border border-indigo-700 border-l-[16px] border-l-emerald-500 relative overflow-hidden group">
                                                <div className="absolute right-0 top-0 w-48 h-48 bg-white/5 rounded-full -mr-20 -mt-20 blur-3xl group-hover:bg-white/10 transition-colors"></div>
                                                <div className="flex items-start gap-5 relative z-10">
                                                    <div className="bg-emerald-500 p-2.5 rounded-2xl shadow-lg"><Sparkles className="w-7 h-7 text-white animate-pulse"/></div>
                                                    <div className="flex-1">
                                                        <h4 className="text-[10px] font-black uppercase tracking-[0.25em] text-emerald-400 mb-2 flex items-center">
                                                            SBAR Clinical Intelligence <CheckCircle2 className="w-3 h-3 ml-2"/>
                                                        </h4>
                                                        <p className="text-base font-bold leading-relaxed mb-5">"{analysisResult.sbarSummary}"</p>
                                                        <div className="flex flex-wrap gap-2.5">
                                                            {analysisResult.detectedRisks.map((r, i) => (
                                                                <span key={i} className="bg-rose-500/20 text-rose-200 border border-rose-500/30 px-3.5 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-tight">{r}</span>
                                                            ))}
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                        )}

                                        {/* Evolution Entry Card */}
                                        <div className="bg-white p-6 rounded-[2.5rem] border border-slate-200 shadow-xl shadow-slate-200/50 relative overflow-hidden">
                                            <div className="flex justify-between items-center mb-6">
                                                <h3 className="text-xs font-black text-slate-800 uppercase tracking-widest flex items-center">
                                                    <PenTool className="w-4 h-4 mr-2 text-indigo-600"/> Nueva Nota de Evolución
                                                </h3>
                                                <div className="flex gap-2">
                                                    <button onClick={() => setShowCamera(true)} className="p-3 bg-slate-50 rounded-2xl text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 transition-all border border-slate-100 shadow-sm"><Camera className="w-5 h-5"/></button>
                                                    <VoiceInput onTranscript={t => setNoteText(prev => prev + " " + t)} isCompact />
                                                </div>
                                            </div>

                                            <textarea 
                                                value={noteText} 
                                                onChange={e => setNoteText(e.target.value)} 
                                                placeholder="Describe el estado clínico, cambios en la monitorización, respuesta a fármacos o intervenciones realizadas..." 
                                                className="w-full min-h-[180px] bg-slate-50/50 border-2 border-transparent rounded-3xl p-6 text-base font-bold text-slate-700 focus:bg-white focus:border-indigo-500/30 focus:ring-8 focus:ring-indigo-500/5 outline-none resize-none placeholder:text-slate-400 transition-all mb-6 shadow-inner"
                                            />

                                            <div className="flex justify-between items-center pt-6 border-t border-slate-100">
                                                <button 
                                                    onClick={handleAnalyzeNote} 
                                                    disabled={!noteText.trim() || isAnalyzing} 
                                                    className="text-xs font-black text-indigo-600 flex items-center hover:bg-indigo-50 px-6 py-3 rounded-2xl transition-all border-2 border-transparent hover:border-indigo-100 disabled:opacity-50"
                                                >
                                                    {isAnalyzing ? <Loader2 className="w-5 h-5 animate-spin mr-2"/> : <Sparkles className="w-5 h-5 mr-2"/>}
                                                    ANÁLISIS PREDICTIVO
                                                </button>
                                                <button 
                                                    onClick={handleSaveNote} 
                                                    disabled={!noteText.trim()} 
                                                    className="bg-slate-900 text-white px-12 py-4 rounded-2xl text-xs font-black uppercase tracking-widest shadow-2xl shadow-slate-900/40 hover:bg-black transition-all active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed"
                                                >
                                                    REGISTRAR EVOLUCIÓN
                                                </button>
                                            </div>
                                        </div>

                                        {/* Timeline of Evolutions v3 */}
                                        <div className="space-y-10">
                                            {Object.entries(groupedHistory).map(([date, entries]) => (
                                                <div key={date} className="relative">
                                                    <div className="sticky top-0 z-10 py-4 mb-8 bg-slate-50/90 backdrop-blur-xl flex items-center gap-5">
                                                        <div className="bg-slate-200 px-4 py-1.5 rounded-xl text-[10px] font-black text-slate-600 uppercase tracking-[0.25em] border border-slate-300 shadow-sm">{date}</div>
                                                        <div className="h-px bg-slate-300 flex-1 opacity-50"></div>
                                                    </div>

                                                    <div className="space-y-8 relative ml-4 border-l-4 border-slate-200 pl-10 pb-4">
                                                        {entries.map(h => (
                                                            <div key={h.id} className="relative bg-white p-7 rounded-[2.5rem] border border-slate-200 shadow-md hover:shadow-xl transition-all group overflow-hidden">
                                                                <div className="absolute -left-[46px] top-8 w-6 h-6 bg-white border-4 border-indigo-600 rounded-full z-10 shadow-lg group-hover:scale-125 transition-transform"></div>

                                                                <div className="flex justify-between items-start mb-4">
                                                                    <div className="flex items-center gap-4">
                                                                        <span className="text-[11px] font-black text-indigo-600 uppercase bg-indigo-50 px-3 py-1.5 rounded-xl flex items-center border border-indigo-100 shadow-inner">
                                                                            <Clock className="w-4 h-4 mr-2"/>
                                                                            {new Date(h.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}
                                                                        </span>
                                                                        {h.vitals && (
                                                                            <div className="flex gap-2.5">
                                                                                <span className="text-[10px] font-bold text-slate-400 bg-slate-50 px-2.5 py-1.5 rounded-xl border border-slate-100">TA {h.vitals.ta}</span>
                                                                                <span className="text-[10px] font-bold text-slate-400 bg-slate-50 px-2.5 py-1.5 rounded-xl border border-slate-100">Sat {h.vitals.sat}%</span>
                                                                            </div>
                                                                        )}
                                                                    </div>
                                                                    {h.riskLevel === 'CRITICAL' && <AlertTriangle className="w-6 h-6 text-rose-500 animate-pulse"/>}
