import React, { useState } from 'react';
import { Prescription } from '../types';
import { Pill, Clock, Check, AlertTriangle, FileText, Plus, Syringe, MoreHorizontal, X, AlertOctagon, RefreshCcw, Sparkles, Loader2 } from 'lucide-react';
import { checkDrugInteractions } from '../services/geminiService';

interface MedicationSheetProps {
    prescriptions: Prescription[];
    onUpdate: (updatedList: Prescription[]) => void;
}

export const MedicationSheet: React.FC<MedicationSheetProps> = ({ prescriptions, onUpdate }) => {
    const [showAddModal, setShowAddModal] = useState(false);
    const [interactionAlerts, setInteractionAlerts] = useState<string[]>([]);
    const [isChecking, setIsChecking] = useState(false);

    // New Prescription State
    const [newMeds, setNewMeds] = useState<Partial<Prescription>>({
        drugName: '', dose: '', route: 'IV', frequency: '24h', type: 'SCHEDULED'
    });

    const handleAdminister = (id: string) => {
        const now = new Date();
        const updated = prescriptions.map(p => {
            if (p.id === id) {
                // Calculate next dose roughly based on frequency
                let next = new Date(now);
                if (p.frequency.includes('8h')) next.setHours(next.getHours() + 8);
                else if (p.frequency.includes('12h')) next.setHours(next.getHours() + 12);
                else if (p.frequency.includes('24h')) next.setHours(next.getHours() + 24);
                else if (p.frequency.includes('6h')) next.setHours(next.getHours() + 6);

                return { 
                    ...p, 
                    lastAdmin: now.toISOString(),
                    nextAdmin: p.type === 'SCHEDULED' ? next.toISOString() : undefined
                };
            }
            return p;
        });
        onUpdate(updated);
    };

    const handleAdd = () => {
        if (!newMeds.drugName || !newMeds.dose) return;
        const p: Prescription = {
            id: `rx-${Date.now()}`,
            drugName: newMeds.drugName,
            dose: newMeds.dose,
            route: newMeds.route as any,
            frequency: newMeds.frequency || '24h',
            type: newMeds.type as any,
            status: 'ACTIVE',
            nextAdmin: new Date().toISOString() // Due now
        } as Prescription;

        onUpdate([...prescriptions, p]);
        setNewMeds({ drugName: '', dose: '', route: 'IV', frequency: '24h', type: 'SCHEDULED' });
        setShowAddModal(false);
    };

    const checkInteractions = async () => {
        const drugNames = prescriptions.map(p => p.drugName);
        if (drugNames.length < 2) return;
        setIsChecking(true);
        try {
            const alerts = await checkDrugInteractions(drugNames);
            setInteractionAlerts(alerts);
        } catch(e) {
            console.error(e);
        } finally {
            setIsChecking(false);
        }
    };

    const getStatusInfo = (p: Prescription) => {
        if (p.status === 'STOPPED') return { color: 'bg-slate-100 border-slate-200 opacity-60', statusText: 'SUSPENDIDO', icon: X };
        if (!p.nextAdmin) return { color: 'bg-white border-slate-200', statusText: 'SI PRECISA', icon: RefreshCcw }; // PRN

        const next = new Date(p.nextAdmin);
        const now = new Date();
        const diffMins = (now.getTime() - next.getTime()) / 60000;

        if (diffMins > 60) return { color: 'bg-rose-50 border-rose-200 ring-1 ring-rose-100', statusText: 'RETRASADO', icon: AlertTriangle }; // Late > 1h
        if (diffMins > 0) return { color: 'bg-amber-50 border-amber-200 ring-1 ring-amber-100', statusText: 'PENDIENTE', icon: Clock }; // Due
        return { color: 'bg-white border-slate-200', statusText: 'PROGRAMADO', icon: Clock }; // Future
    };

    return (
        <div className="h-full flex flex-col gap-6">

            {/* Header Actions */}
            <div className="flex gap-3">
                <button onClick={() => setShowAddModal(true)} className="flex-1 bg-indigo-600 text-white py-3 rounded-xl text-xs font-bold shadow-md hover:bg-indigo-700 transition-all flex items-center justify-center active:scale-95">
                    <Plus className="w-4 h-4 mr-2"/> AÑADIR ORDEN
                </button>
                <button onClick={checkInteractions} disabled={isChecking} className="flex-1 bg-white text-violet-600 border border-violet-200 py-3 rounded-xl text-xs font-bold shadow-sm hover:bg-violet-50 transition-all flex items-center justify-center active:scale-95">
                    {/* Loader2 added to lucide-react imports above */}
                    {isChecking ? <Loader2 className="w-4 h-4 animate-spin mr-2"/> : <><Sparkles className="w-4 h-4 mr-2"/> ANALIZAR TERAPIA</>}
                </button>
            </div>

            {/* Interaction Alerts */}
            {interactionAlerts.length > 0 && (
                <div className="bg-rose-50 p-4 rounded-xl border border-rose-200 animate-fade-in border-l-4 border-l-rose-500 shadow-sm relative overflow-hidden">
                    <div className="absolute right-0 top-0 w-24 h-24 bg-rose-500/5 rounded-full -mr-12 -mt-12"></div>
                    <h4 className="text-xs font-black text-rose-800 uppercase mb-2 flex items-center relative z-10"><AlertOctagon className="w-4 h-4 mr-2"/> Alertas de Seguridad IA</h4>
                    <ul className="text-xs text-rose-700 list-disc list-inside font-medium space-y-1 ml-1 relative z-10">
                        {interactionAlerts.map((a, i) => <li key={i}>{a}</li>)}
                    </ul>
                </div>
            )}

            {/* Medication List */}
            <div className="flex-1 overflow-y-auto custom-scrollbar space-y-3 pb-20 p-1">
                {prescriptions.length === 0 && (
                    <div className="text-center py-10 text-slate-400 border-2 border-dashed border-slate-200 rounded-2xl bg-slate-50/50">
                        <Pill className="w-12 h-12 mx-auto mb-2 opacity-20"/>
                        <p className="text-xs font-bold uppercase">Sin medicación pautada</p>
                    </div>
                )}

                {prescriptions.map(p => {
                    const statusInfo = getStatusInfo(p);
                    const StatusIcon = statusInfo.icon;
                    return (
                        <div key={p.id} className={`p-4 rounded-2xl border shadow-sm transition-all flex flex-col gap-3 relative group overflow-hidden ${statusInfo.color}`}>

                            <div className="flex justify-between items-start z-10 relative">
                                <div className="flex-1">
                                    <div className="flex items-center gap-2 mb-1.5">
                                        <span className={`text-[9px] font-black px-2 py-0.5 rounded uppercase flex items-center gap-1 ${p.type === 'PRN' ? 'bg-amber-100 text-amber-700' : 'bg-slate-800 text-white'}`}>
                                            <StatusIcon className="w-2.5 h-2.5"/> {statusInfo.statusText}
                                        </span>
                                        <span className="text-[9px] font-bold text-slate-500 bg-white/80 px-2 py-0.5 rounded border border-slate-200/50">{p.route}</span>
                                    </div>
                                    <h4 className="font-black text-slate-800 text-base uppercase leading-tight">{p.drugName}</h4>
                                    <p className="text-sm font-bold text-indigo-600 mt-0.5">{p.dose} <span className="text-[10px] text-slate-400 font-medium ml-1">/ {p.frequency}</span></p>
                                </div>

                                {p.lastAdmin && (
                                    <div className="text-right pl-4">
                                        <div className="text-[8px] text-slate-400 font-bold uppercase tracking-wide">Última</div>
                                        <div className="text-xs font-bold text-slate-600 font-mono bg-white/50 px-2 py-1 rounded">{new Date(p.lastAdmin).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</div>
                                    </div>
                                )}
                            </div>

                            {/* Action Bar */}
                            <div className="flex items-center justify-between border-t border-slate-200/50 pt-3 mt-1 z-10 relative">
                                <div className="flex items-center gap-2 text-xs text-slate-500 font-medium">
                                    <Clock className="w-3.5 h-3.5"/>
                                    {p.nextAdmin && p.type === 'SCHEDULED' 
                                        ? <span>Próxima: <span className="font-bold text-slate-800">{new Date(p.nextAdmin).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span></span> 
                                        : <span>Si precisa</span>
                                    }
                                </div>
                                <button onClick={() => handleAdminister(p.id)} className="bg-emerald-600 hover:bg-emerald-700 text-white px-5 py-2 rounded-xl text-[10px] font-black uppercase shadow-sm hover:shadow-md transition-all flex items-center active:scale-95 group/btn">
                                    <Check className="w-4 h-4 mr-1.5 group-hover/btn:scale-110 transition-transform"/> CONFIRMAR
                                </button>
                            </div>
                        </div>
                    );
                })}
            </div>

            {/* Add Modal Overlay */}
            {showAddModal && (
                <div className="absolute inset-0 bg-white/95 z-20 p-6 flex flex-col animate-fade-in rounded-2xl backdrop-blur-md">
                    <div className="flex justify-between items-center mb-6">
                        <h3 className="font-black text-slate-800 uppercase flex items-center"><Plus className="w-5 h-5 mr-2 text-indigo-600"/> Nueva Orden Médica</h3>
                        <button onClick={() => setShowAddModal(false)}><X className="w-6 h-6 text-slate-400 hover:text-rose-500 transition-colors"/></button>
                    </div>
                    <div className="space-y-5 flex-1">
                        <div>
                            <label className="text-xs font-bold text-slate-500 uppercase block mb-1.5">Fármaco (Principio Activo)</label>
                            <input value={newMeds.drugName} onChange={e => setNewMeds({...newMeds, drugName: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3.5 text-sm font-bold outline-none focus:ring-2 focus:ring-indigo-500 transition-all placeholder:text-slate-300" placeholder="Ej: Paracetamol"/>
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="text-xs font-bold text-slate-500 uppercase block mb-1.5">Dosis</label>
                                <input value={newMeds.dose} onChange={e => setNewMeds({...newMeds, dose: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3.5 text-sm font-bold outline-none focus:ring-2 focus:ring-indigo-500 transition-all placeholder:text-slate-300" placeholder="Ej: 1g"/>
                            </div>
                            <div>
                                <label className="text-xs font-bold text-slate-500 uppercase block mb-1.5">Vía</label>
                                <select value={newMeds.route} onChange={e => setNewMeds({...newMeds, route: e.target.value as any})} className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3.5 text-sm font-bold outline-none focus:ring-2 focus:ring-indigo-500 transition-all">
                                    <option value="IV">Intravenosa</option>
                                    <option value="VO">Oral</option>
                                    <option value="SC">Subcutánea</option>
                                    <option value="NEB">Nebulizada</option>
                                </select>
                            </div>
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="text-xs font-bold text-slate-500 uppercase block mb-1.5">Frecuencia</label>
                                <select value={newMeds.frequency} onChange={e => setNewMeds({...newMeds, frequency: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3.5 text-sm font-bold outline-none focus:ring-2 focus:ring-indigo-500 transition-all">
                                    <option value="24h">Cada 24h</option>
                                    <option value="12h">Cada 12h</option>
                                    <option value="8h">Cada 8h</option>
                                    <option value="6h">Cada 6h</option>
                                    <option value="PRN">Si precisa</option>
                                </select>
                            </div>
                            <div>
                                <label className="text-xs font-bold text-slate-500 uppercase block mb-1.5">Tipo</label>
                                <select value={newMeds.type} onChange={e => setNewMeds({...newMeds, type: e.target.value as any})} className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3.5 text-sm font-bold outline-none focus:ring-2 focus:ring-indigo-500 transition-all">
                                    <option value="SCHEDULED">Pautada</option>
                                    <option value="PRN">Condicional</option>
                                    <option value="STAT">Dosis Única</option>
                                </select>
                            </div>
                        </div>
                    </div>
                    <button onClick={handleAdd} className="w-full bg-indigo-600 text-white py-4 rounded-xl font-bold uppercase shadow-lg hover:bg-indigo-700 transition-all active:scale-95 flex items-center justify-center">
                        <Check className="w-5 h-5 mr-2"/> Confirmar Orden
