import { GoogleGenAI, Type } from "@google/genai";
import { TriageResult, Pathology, Drug, ClinicalAnalysis, DynamicTask, WoundAnalysisResult, Patient } from "../types";
import { logger } from "./logger";

// Initialization with Gemini 3 capabilities
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// --- SYSTEM INSTRUCTIONS ---

const FLORENCE_V3_INSTRUCTION = `
Eres FLORENCE v3.0 PRO, el sistema de soporte a la decisión clínica de PAESYS. 
Tu objetivo es garantizar la seguridad del paciente y el rigor científico.
Usa Google Search para validar protocolos actuales (2024-2025).
Responde SIEMPRE en JSON estructurado con:
- reasoning: razonamiento interno basado en el protocolo S.T.O.P.
- answer: mensaje claro y profesional para el personal de enfermería.
- confidence: HIGH/MEDIUM/LOW.
- criticalAlert: string si hay riesgo vital.
- sources: links reales de grounding.
`;

const TRIAGE_INSTRUCTION = `
Sistema experto de triaje Manchester/ESI. Clasifica riesgo vital. Responde en JSON.
Model: gemini-3-flash-preview.
Niveles: RED (Emergencia), YELLOW (Urgencia), GREEN (No Urgente).
`;

// --- API FUNCTIONS ---

export const getClinicalTriage = async (caseDescription: string, imageBase64?: string): Promise<TriageResult> => {
  try {
    const parts: any[] = [];
    if (imageBase64) {
        parts.push({ inlineData: { mimeType: "image/jpeg", data: imageBase64.split(',')[1] } });
    }
    parts.push({ text: `Analiza este caso clínico y clasifica el riesgo: "${caseDescription}"` });

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview", 
      contents: { role: 'user', parts: parts },
      config: {
        systemInstruction: TRIAGE_INSTRUCTION,
        responseMimeType: "application/json",
      },
    });
    return JSON.parse(response.text || "{}") as TriageResult;
  } catch (error) {
    logger.error('AI:Triage', 'Error en el motor de triaje', error);
    throw error;
  }
};

export const generatePathology = async (query: string): Promise<Pathology> => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `Genera ficha clínica avanzada para: "${query}". Usa Google Search para evidencia 2024.`,
            config: {
                responseMimeType: "application/json",
                tools: [{ googleSearch: {} }]
            }
        });
        const sources: { title: string, uri: string }[] = [];
        if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
            response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
                if (chunk.web) sources.push({ title: chunk.web.title, uri: chunk.web.uri });
            });
        }
        const parsed = JSON.parse(response.text || "{}") as Pathology;
        parsed.sources = sources;
        return parsed;
    } catch (error) {
        throw error;
    }
};

export interface FlorenceResponse {
    reasoning: string;
    answer: string;
    confidence: 'HIGH' | 'MEDIUM' | 'LOW';
    criticalAlert?: string;
    suggestedActions?: { label: string, view: string, params?: any }[];
    sources?: { title: string, uri: string }[];
}

export const generateChatReply = async (userMessage: string, personaKey: string, patientContext?: Patient): Promise<FlorenceResponse> => {
    try {
        let contextBlock = patientContext ? `CONTEXTO PACIENTE: ${patientContext.name}, Dx: ${patientContext.diagnosis}, NEWS2: ${patientContext.news2}, Meds: ${patientContext.prescriptions?.map(p => p.drugName).join(', ')}` : "";

        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `${contextBlock}\n\nCONSULTA: "${userMessage}". Responde con rigor científico y formato JSON.`,
            config: {
                systemInstruction: FLORENCE_V3_INSTRUCTION,
                responseMimeType: "application/json",
                tools: [{ googleSearch: {} }]
            }
        });

        const sources: { title: string, uri: string }[] = [];
        if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
            response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
                if (chunk.web) sources.push({ title: chunk.web.title, uri: chunk.web.uri });
            });
        }

        const parsed = JSON.parse(response.text || "{}") as FlorenceResponse;
        if (sources.length > 0) parsed.sources = sources;
        return parsed;

    } catch (error) {
        return { reasoning: "Error de enlace", answer: "No se pudo conectar con el motor Florence v3.", confidence: "LOW" };
    }
};

export const checkDrugInteractions = async (drugs: string[]): Promise<string[]> => {
    const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Analiza interacciones clínicas graves entre estos fármacos: ${drugs.join(', ')}. Responde JSON {alerts: string[]}`,
        config: { responseMimeType: "application/json" }
    });
    const data = JSON.parse(response.text || "{}");
    return data.alerts || [];
};

export const analyzeClinicalNote = async (note: string): Promise<ClinicalAnalysis> => {
