    const [isFlorenceOpen, setIsFlorenceOpen] = useState(false);

    const [showCamera, setShowCamera] = useState(false);
    const [showAdmissionModal, setShowAdmissionModal] = useState(false);

    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [analysisResult, setAnalysisResult] = useState<ClinicalAnalysis | null>(null);

    const [noteText, setNoteText] = useState('');
    const [vitalsInput, setVitalsInput] = useState({ ta: '', fc: '', sat: '', temp: '', gcs: '' });
    const [attachments, setAttachments] = useState<{url:string, label:string, type:'IMAGE'|'AUDIO'}[]>([]);

    const [florenceMessages, setFlorenceMessages] = useState<ChatMessage[]>([]);
    const [florenceInput, setFlorenceInput] = useState('');
    const [isFlorenceTyping, setIsFlorenceTyping] = useState(false);
    const chatEndRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const load = async () => {
            const data = await PatientService.getAll();
            setPatients(data);
        };
        load();
    }, []);

    const selectedPatient = useMemo(() => patients.find(p => p.id === selectedPatientId), [patients, selectedPatientId]);

    const groupedHistory = useMemo(() => {
        if (!selectedPatient?.history) return {};
        const groups: Record<string, Evolution[]> = {};
        selectedPatient.history.forEach(h => {
            let label = new Date(h.timestamp).toLocaleDateString([], {day: 'numeric', month: 'long'});
            const d = new Date(h.timestamp);
            const now = new Date();
            if (d.getDate() === now.getDate() && d.getMonth() === now.getMonth()) label = 'Hoy';
            if (!groups[label]) groups[label] = [];
            groups[label].push(h);
        });
        return groups;
    }, [selectedPatient?.history]);

    const handleSaveNote = async () => {
        if (!selectedPatientId || !noteText.trim()) return;
        const newNote: Evolution = {
            id: `ev-${Date.now()}`,
            timestamp: new Date().toISOString(),
            note: noteText,
            vitals: { ...vitalsInput },
            type: 'EVOLUTION',
            riskLevel: 'STABLE', 
            analysis: analysisResult || undefined,
            attachments: attachments
        };
        await PatientService.addEvolution(selectedPatientId, newNote);
        const updated = await PatientService.getAll();
        setPatients(updated);
        setNoteText('');
        setVitalsInput({ ta: '', fc: '', sat: '', temp: '', gcs: '' });
        setAttachments([]);
        setAnalysisResult(null);
    };

    const handleAnalyzeNote = async () => {
        if (!noteText.trim()) return;
        setIsAnalyzing(true);
        try {
            const result = await analyzeClinicalNote(noteText);
            setAnalysisResult(result);
        } catch(e) { console.error(e); }
        finally { setIsAnalyzing(false); }
    };

    const handleFlorenceSend = async (textOverride?: string) => {
        const text = textOverride || florenceInput;
        if(!text.trim() || !selectedPatient) return;

        const userMsg: ChatMessage = {
            id: Date.now().toString(),
            userId: 'me',
            userName: 'Yo',
            role: 'NURSE',
            text: text,
            timestamp: new Date().toISOString()
        };
        setFlorenceMessages(prev => [...prev, userMsg]);
        setFlorenceInput('');
        setIsFlorenceTyping(true);

        try {
            const response = await generateChatReply(text, 'MENTOR', selectedPatient);
            const aiMsg: ChatMessage = {
                id: 'ai-' + Date.now(),
                userId: 'florence',
                userName: 'Florence AI',
                role: 'ADMIN',
                text: response.answer,
                sources: response.sources,
                timestamp: new Date().toISOString(),
                isSystem: true
            };
            setFlorenceMessages(prev => [...prev, aiMsg]);
        } catch(e) {
            console.error(e);
        } finally {
            setIsFlorenceTyping(false);
        }
    };

    return (
        <div className="flex h-full flex-col bg-slate-100 overflow-hidden relative font-sans">
            <header className="bg-slate-900 text-white border-b border-slate-800 px-6 py-4 flex justify-between items-center shrink-0 z-20 shadow-xl">
                <div className="flex items-center gap-3">
                    <div className="bg-indigo-600 p-2 rounded-xl shadow-lg">
                        <ClipboardList className="w-5 h-5"/>
                    </div>
                    <div>
                        <h1 className="text-lg font-black tracking-tight uppercase">Hospital OS <span className="text-indigo-400">Clinical v22</span></h1>
                        <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Unidad de Vigilancia Activa</p>
                    </div>
                </div>
                <button onClick={() => setShowAdmissionModal(true)} className="bg-emerald-600 hover:bg-emerald-700 text-white px-5 py-2.5 rounded-xl text-xs font-black shadow-lg transition-all flex items-center active:scale-95 border border-emerald-500">
                    <UserPlus className="w-4 h-4 mr-2"/> ADMITIR PACIENTE
                </button>
            </header>

            <div className="flex-1 overflow-hidden flex">
                <div className={`${selectedPatientId ? 'hidden lg:flex w-96' : 'flex w-full'} flex-col bg-white border-r border-slate-200 z-10 transition-all shadow-xl h-full`}>
                    <div className="p-5 border-b border-slate-100 sticky top-0 bg-white z-10">
                        <div className="relative group">
                            <Search className="absolute left-4 top-3.5 w-4 h-4 text-slate-400 group-focus-within:text-indigo-600 transition-colors"/>
                            <input 
                                value={searchTerm} 
                                onChange={e => setSearchTerm(e.target.value)} 
                                placeholder="Buscar paciente o cama..."
                                className="w-full pl-11 pr-4 py-3 rounded-2xl bg-slate-50 border border-slate-200 text-sm font-bold focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all placeholder:text-slate-400"
                            />
                        </div>
                    </div>

                    <div className="flex-1 overflow-y-auto custom-scrollbar p-3 space-y-3 bg-slate-50/50">
                        {patients.filter(p => p.name.toLowerCase().includes(searchTerm.toLowerCase())).map(patient => (
                            <button 
                                key={patient.id}
                                onClick={() => setSelectedPatientId(patient.id)}
                                className={`w-full text-left p-0 rounded-2xl border transition-all flex overflow-hidden group relative active:scale-[0.98] ${selectedPatientId === patient.id ? 'bg-white border-indigo-500 ring-2 ring-indigo-100 shadow-xl z-10' : 'bg-white border-slate-200 hover:border-indigo-300 shadow-sm'}`}
                            >
                                <div className={`w-1.5 shrink-0 ${patient.risk === 'HIGH' ? 'bg-rose-500 animate-pulse' : patient.risk === 'MEDIUM' ? 'bg-amber-400' : 'bg-emerald-500'}`}></div>
                                <div className="p-4 flex-1 min-w-0">
                                    <div className="flex justify-between items-start mb-2">
                                        <span className="font-black text-sm text-slate-800 truncate pr-2 uppercase tracking-tight">{patient.name}</span>
                                        <span className="text-[10px] font-black bg-slate-900 text-white px-2 py-0.5 rounded shadow-sm">{patient.bed}</span>
                                    </div>
                                    <div className="flex items-center gap-2 text-[10px] text-slate-500 font-bold uppercase tracking-tighter">
                                        <div className="flex items-center bg-slate-100 px-1.5 py-0.5 rounded border border-slate-200">
                                            {patient.sex} • {patient.age}a
                                        </div>
                                        <span className="truncate flex-1 text-indigo-600">{patient.diagnosis}</span>
                                    </div>
                                    <div className="mt-3 flex items-center gap-2">
                                        <span className={`text-[10px] font-black px-2 py-0.5 rounded border ${patient.risk === 'HIGH' ? 'text-rose-600 bg-rose-50 border-rose-100' : 'text-emerald-600 bg-emerald-50 border-emerald-100'}`}>
                                            NEWS2 {patient.news2}
                                        </span>
                                    </div>
                                </div>
                                <div className="p-3 flex items-center justify-center bg-slate-50 border-l border-slate-100 text-slate-300 group-hover:text-indigo-500 transition-colors">
                                    <ChevronRight className="w-5 h-5"/>
                                </div>
                            </button>
                        ))}
                    </div>
                </div>

                {selectedPatient ? (
                    <div className="flex-1 flex flex-col bg-slate-50 relative overflow-hidden h-full">
                        <div className="bg-white border-b border-slate-200 shadow-sm shrink-0 z-10 p-4 md:p-6">
                            <div className="flex justify-between items-start gap-4">
                                <div className="flex items-center gap-5 overflow-hidden">
                                    <button onClick={() => setSelectedPatientId(null)} className="lg:hidden p-2.5 bg-slate-100 rounded-full text-slate-500 active:scale-90 transition-transform">
                                        <ArrowLeft className="w-5 h-5"/>
                                    </button>
                                    <div className="min-w-0">
                                        <div className="flex items-center gap-3 mb-1">
                                            <h2 className="text-xl md:text-3xl font-black text-slate-900 truncate uppercase tracking-tighter">{selectedPatient.name}</h2>
                                            <span className="bg-indigo-600 text-white text-[10px] font-black px-3 py-1 rounded-full shadow-lg shadow-indigo-600/30">{selectedPatient.bed}</span>
                                        </div>
                                        <div className="flex items-center gap-3 text-xs font-black uppercase text-slate-400 overflow-x-auto no-scrollbar whitespace-nowrap">
                                            <span>{selectedPatient.age} Años</span>
                                            <span className="text-slate-200">|</span>
                                            <span className="text-rose-600 bg-rose-50 px-2 py-0.5 rounded border border-rose-100 flex items-center shadow-sm"><ShieldAlert className="w-3 h-3 mr-1"/> Alergias: {selectedPatient.allergies}</span>
                                            <span className="text-slate-200">|</span>
                                            <span>Peso: {selectedPatient.weight} kg</span>
                                        </div>
                                    </div>
                                </div>
                                <button onClick={() => setIsFlorenceOpen(true)} className="bg-gradient-to-tr from-violet-600 to-indigo-700 text-white p-3.5 rounded-2xl shadow-xl hover:scale-105 active:scale-95 transition-all shrink-0">
                                    <Bot className="w-6 h-6"/>
                                </button>
                            </div>

                            <div className="flex gap-2 mt-6 overflow-x-auto no-scrollbar scroll-smooth">
                                {CLINICAL_MODULES.map(m => (
                                    <button
                                        key={m.id}
                                        onClick={() => setDetailTab(m.id)}
                                        className={`px-4 py-2.5 rounded-xl text-xs font-black uppercase tracking-wider transition-all flex items-center whitespace-nowrap border-2 ${detailTab === m.id ? `bg-slate-900 text-white border-slate-900 shadow-xl` : 'bg-white text-slate-500 border-slate-100 hover:border-slate-200 hover:bg-slate-50'}`}
                                    >
                                        <m.icon className={`w-4 h-4 mr-2 ${detailTab === m.id ? 'text-indigo-400' : m.color}`}/> 
                                        {m.label}
                                    </button>
                                ))}
                            </div>
                        </div>

                        <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar bg-slate-50/50 pb-32">
                            <div className="max-w-6xl mx-auto">
                                {detailTab === 'NOTES' && (
                                    <div className="space-y-8 animate-fade-in">
                                        {analysisResult && (
                                            <div className="bg-indigo-900 text-white p-6 rounded-[2.5rem] shadow-2xl border-l-[16px] border-l-emerald-500 relative overflow-hidden group">
                                                <div className="flex items-start gap-5 relative z-10">
                                                    <div className="bg-emerald-500 p-2.5 rounded-2xl"><Sparkles className="w-7 h-7 text-white animate-pulse"/></div>
                                                    <div className="flex-1">
                                                        <h4 className="text-[10px] font-black uppercase tracking-[0.25em] text-emerald-400 mb-2">SBAR Clinical Intelligence</h4>
                                                        <p className="text-base font-bold leading-relaxed mb-5">"{analysisResult.sbarSummary}"</p>
                                                        <div className="flex flex-wrap gap-2.5">
                                                            {analysisResult.detectedRisks.map((r, i) => (
                                                                <span key={i} className="bg-rose-500/20 text-rose-200 border border-rose-500/30 px-3.5 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-tight">{r}</span>
                                                            ))}
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                        )}

                                        <div className="bg-white p-6 rounded-[2.5rem] border border-slate-200 shadow-xl relative overflow-hidden">
                                            <div className="flex justify-between items-center mb-6">
                                                <h3 className="text-xs font-black text-slate-800 uppercase tracking-widest flex items-center">
                                                    <PenTool className="w-4 h-4 mr-2 text-indigo-600"/> Registro de Evolución
                                                </h3>
                                                <div className="flex gap-2">
                                                    <VoiceInput onTranscript={t => setNoteText(prev => prev + " " + t)} isCompact />
                                                </div>
                                            </div>

                                            <textarea 
                                                value={noteText} 
                                                onChange={e => setNoteText(e.target.value)} 
                                                placeholder="Describe el estado clínico, cambios en la monitorización o respuesta a fármacos..." 
                                                className="w-full min-h-[180px] bg-slate-50/50 border-2 border-transparent rounded-3xl p-6 text-base font-bold text-slate-700 focus:bg-white focus:border-indigo-500/30 focus:ring-8 focus:ring-indigo-500/5 outline-none resize-none placeholder:text-slate-400 transition-all mb-6"
                                            />

                                            <div className="flex justify-between items-center pt-6 border-t border-slate-100">
                                                <button 
                                                    onClick={handleAnalyzeNote} 
                                                    disabled={!noteText.trim() || isAnalyzing} 
                                                    className="text-xs font-black text-indigo-600 flex items-center hover:bg-indigo-50 px-6 py-3 rounded-2xl transition-all disabled:opacity-50"
                                                >
                                                    {isAnalyzing ? <Loader2 className="w-5 h-5 animate-spin mr-2"/> : <Sparkles className="w-5 h-5 mr-2"/>}
                                                    ANÁLISIS PREDICTIVO
                                                </button>
                                                <button 
                                                    onClick={handleSaveNote} 
                                                    disabled={!noteText.trim()} 
                                                    className="bg-slate-900 text-white px-12 py-4 rounded-2xl text-xs font-black uppercase tracking-widest shadow-2xl hover:bg-black transition-all active:scale-95 disabled:opacity-50"
                                                >
                                                    REGISTRAR EVOLUCIÓN
                                                </button>
                                            </div>
                                        </div>

                                        <div className="space-y-10">
                                            {Object.entries(groupedHistory).map(([date, entries]) => (
                                                <div key={date} className="relative">
                                                    <div className="sticky top-0 z-10 py-4 mb-8 bg-slate-50/90 backdrop-blur-xl flex items-center gap-5">
                                                        <div className="bg-slate-200 px-4 py-1.5 rounded-xl text-[10px] font-black text-slate-600 uppercase tracking-[0.25em] border border-slate-300 shadow-sm">{date}</div>
                                                        <div className="h-px bg-slate-300 flex-1 opacity-50"></div>
                                                    </div>
                                                    <div className="space-y-8 relative ml-4 border-l-4 border-slate-200 pl-10 pb-4">
                                                        {entries.map(h => (
                                                            <div key={h.id} className="relative bg-white p-7 rounded-[2.5rem] border border-slate-200 shadow-md hover:shadow-xl transition-all group overflow-hidden">
                                                                <div className="absolute -left-[46px] top-8 w-6 h-6 bg-white border-4 border-indigo-600 rounded-full z-10 shadow-lg group-hover:scale-125 transition-transform"></div>
                                                                <div className="flex justify-between items-start mb-4">
                                                                    <span className="text-[11px] font-black text-indigo-600 uppercase bg-indigo-50 px-3 py-1.5 rounded-xl flex items-center border border-indigo-100">
                                                                        <Clock className="w-4 h-4 mr-2"/>
                                                                        {new Date(h.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}
                                                                    </span>
                                                                    {h.riskLevel === 'CRITICAL' && <AlertTriangle className="w-6 h-6 text-rose-500 animate-pulse"/>}
                                                                </div>
                                                                <p className="text-base font-medium text-slate-700 leading-relaxed whitespace-pre-wrap">{h.note}</p>
                                                                {h.analysis?.suggestedNanda && Array.isArray(h.analysis.suggestedNanda) && (
                                                                    <div className="mt-6 pt-6 border-t border-slate-50 flex flex-wrap gap-3">
                                                                        {h.analysis.suggestedNanda.slice(0, 3).map((n, idx) => (
                                                                            <span key={idx} className="bg-emerald-50 text-emerald-800 px-4 py-1.5 rounded-full text-[10px] font-black uppercase border border-emerald-100 flex items-center shadow-sm">
                                                                                <ShieldCheck className="w-3.5 h-3.5 mr-2 text-emerald-500"/> {n}
                                                                            </span>
                                                                        ))}
                                                                    </div>
                                                                )}
                                                            </div>
                                                        ))}
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                )}

                                {detailTab === 'MONITOR' && <VitalSigns history={selectedPatient.history} />}
                                {detailTab === 'MEDS' && <MedicationSheet prescriptions={selectedPatient.prescriptions || []} onUpdate={p => PatientService.updatePatient(selectedPatient.id, {prescriptions: p}).then(loadData)} />}
                                {detailTab === 'PAE' && <CarePlanManager carePlans={selectedPatient.activePae || []} onUpdate={p => PatientService.updatePatient(selectedPatient.id, {activePae: p}).then(loadData)} />}
                                {detailTab === 'LABS' && <LabResults reports={selectedPatient.labReports || []} />}
                                {detailTab === 'ACCESS' && <AccessManager devices={selectedPatient.activeDevices || []} onUpdate={d => PatientService.updatePatient(selectedPatient.id, {activeDevices: d}).then(loadData)} />}
                                {detailTab === 'WOUNDS' && <WoundAnalysis wounds={selectedPatient.wounds || []} onAddWound={w => PatientService.updatePatient(selectedPatient.id, {wounds: [w, ...(selectedPatient.wounds||[])]}).then(loadData)} />}
                                {detailTab === 'HANDOFF' && <ShiftHandoff patient={selectedPatient} onSendToChat={handleFlorenceSend} />}
                            </div>
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 hidden md:flex flex-col items-center justify-center bg-slate-50/50 text-slate-300">
                        <div className="w-40 h-40 bg-white rounded-full flex items-center justify-center shadow-2xl border border-slate-100 mb-8">
                            <User className="w-16 h-16 opacity-10"/>
                        </div>
                        <p className="text-base font-black uppercase tracking-[0.4em]">Seleccione un Paciente del Censo</p>
                    </div>
                )}
            </div>

            {isFlorenceOpen && selectedPatient && (
                <div className="fixed inset-0 z-50 flex justify-end">
                    <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm transition-opacity" onClick={() => setIsFlorenceOpen(false)}></div>
                    <div className="w-full md:w-[580px] bg-slate-50 h-full shadow-[0_0_120px_rgba(0,0,0,0.6)] relative flex flex-col animate-slide-in-right overflow-hidden border-l border-white/10">
                        <div className="p-7 bg-slate-900 text-white flex justify-between items-center shadow-2xl shrink-0 relative overflow-hidden">
                            <div className="flex items-center gap-5 relative z-10">
                                <div className="relative">
                                    <div className="w-16 h-16 bg-white rounded-2xl p-0.5 shadow-2xl rotate-2">
                                        <img src="https://ui-avatars.com/api/?name=Florence+AI&background=7c3aed&color=fff" className="w-full h-full rounded-[0.8rem] shadow-inner" alt="Florence"/>
                                    </div>
                                    <div className="absolute -bottom-1 -right-1 w-5 h-5 bg-emerald-500 border-4 border-slate-900 rounded-full shadow-lg"></div>
                                </div>
                                <div>
                                    <h3 className="font-black text-xl tracking-tight uppercase">Florence AI <span className="text-indigo-400 text-xs ml-2 px-2 py-0.5 rounded-full border border-indigo-500/50">v3.0 PRO</span></h3>
                                    <div className="flex items-center gap-3 mt-1">
                                        <div className="flex items-center text-[10px] font-black text-indigo-300 bg-indigo-500/20 px-2.5 py-1 rounded-full border border-indigo-500/30">
                                            <Globe className="w-3.5 h-3.5 mr-2"/> GROUNDING ACTIVO
                                        </div>
                                    </div>
                                </div>
                            </div>
                            <button onClick={() => setIsFlorenceOpen(false)} className="p-3 hover:bg-white/10 rounded-full transition-colors relative z-10 border border-white/10"><X className="w-6 h-6"/></button>
                        </div>

                        <div className="flex-1 overflow-y-auto p-6 space-y-8 custom-scrollbar bg-slate-100/30">
                            {florenceMessages.map((msg, i) => {
                                const isMe = msg.role === 'NURSE';
                                let structuredData: any = null;
                                if (!isMe) {
                                    try { structuredData = msg.text?.startsWith('{') ? JSON.parse(msg.text) : null; } catch(e) { structuredData = null; }
                                }
                                const text: string = (structuredData ? structuredData.answer : msg.text) || "";

                                return (
                                    <div key={i} className={`flex ${isMe ? 'justify-end' : 'justify-start'} animate-fade-in-up`}>
                                        <div className={`max-w-[92%] p-6 rounded-[2rem] text-base shadow-2xl relative border ${
                                            isMe ? 'bg-indigo-600 text-white rounded-br-none border-indigo-500 shadow-indigo-500/20' 
                                                 : 'bg-white border-slate-200 text-slate-800 rounded-bl-none shadow-slate-200/50'
                                        }`}>
                                            {!isMe && structuredData && (
                                                <div className="flex items-center justify-between mb-4 pb-3 border-b border-slate-100">
                                                    <span className="text-[11px] font-black text-violet-600 flex items-center gap-2 uppercase tracking-[0.15em]"><ShieldCheck className="w-4 h-4"/> JUICIO CLÍNICO IA</span>
                                                    <span className={`text-[9px] font-black px-2.5 py-1 rounded-lg border ${structuredData.confidence === 'HIGH' ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 'bg-amber-50 text-amber-700 border-amber-200'}`}>FIABILIDAD: {structuredData.confidence}</span>
                                                </div>
                                            )}
                                            <div className="whitespace-pre-wrap leading-relaxed font-medium">
                                                {text.split(/(\*\*.*?\*\*)/g).map((part, i) => 
                                                    part.startsWith('**') && part.endsWith('**') ? <strong key={i} className={isMe ? "text-white" : "text-slate-900 font-black"}>{part.slice(2, -2)}</strong> : part
                                                )}
                                            </div>
                                            {!isMe && structuredData?.sources && (
                                                <div className="mt-6 pt-5 border-t border-slate-100">
                                                    <div className="space-y-3">
                                                        {(structuredData.sources as any[]).map((src, idx) => (
                                                            <a key={idx} href={src.uri} target="_blank" rel="noreferrer" className="flex items-center gap-4 bg-slate-50 hover:bg-indigo-50 border border-slate-200 p-4 rounded-2xl transition-all group/link">
                                                                <div className="bg-white p-2 rounded-xl border border-slate-100 group-hover/link:text-indigo-600 shadow-inner"><Globe className="w-4 h-4"/></div>
                                                                <div className="flex-1 min-w-0">
                                                                    <div className="text-xs font-black text-slate-700 truncate">{src.title}</div>
                                                                    <div className="text-[10px] text-slate-400 font-mono flex items-center mt-1">
                                                                        {new URL(src.uri).hostname} <ExternalLink className="w-3 h-3 ml-2 opacity-50"/>
                                                                    </div>
                                                                </div>
                                                            </a>
                                                        ))}
                                                    </div>
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                );
                            })}
                            {isFlorenceTyping && (
                                <div className="flex justify-start pl-2">
                                    <div className="bg-white p-5 rounded-[2rem] rounded-tl-none shadow-xl flex flex-col gap-3 border border-slate-100">
                                        <div className="flex gap-2">
                                            <span className="w-2.5 h-2.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
                                            <span className="w-2.5 h-2.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
                                            <span className="w-2.5 h-2.5 bg-indigo-400 rounded-full animate-bounce"></span>
                                        </div>
                                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest animate-pulse">Analizando Evidencia...</span>
                                    </div>
                                </div>
                            )}
                            <div ref={chatEndRef}></div>
                        </div>

                        <div className="p-7 bg-white border-t border-slate-200 shadow-2xl">
                            <form onSubmit={(e) => { e.preventDefault(); handleFlorenceSend(); }} className="relative flex items-center gap-4">
                                <div className="flex-1 bg-slate-100 rounded-[2.5rem] p-2 flex items-center border-2 border-transparent focus-within:border-indigo-500/20 focus-within:bg-white transition-all shadow-inner">
                                    <button type="button" className="p-3 text-slate-400 hover:text-indigo-600 transition-colors"><Mic className="w-6 h-6"/></button>
                                    <input 
                                        className="flex-1 bg-transparent border-none focus:ring-0 outline-none text-base font-bold text-slate-700 px-3" 
                                        placeholder="Consultar guías, dosis o compatibilidad..." 
                                        value={florenceInput} 
                                        onChange={e => setFlorenceInput(e.target.value)}
                                    />
                                </div>
                                <button type="submit" disabled={!florenceInput.trim() || isFlorenceTyping} className="p-5 bg-slate-900 text-white rounded-full shadow-2xl hover:bg-black transition-all active:scale-95 disabled:opacity-50">
                                    <Send className="w-6 h-6"/>
                                </button>
                            </form>
                        </div>
                    </div>
                </div>
            )}

            {showAdmissionModal && <AdmissionModal onClose={() => setShowAdmissionModal(false)} onSave={async (p) => { await PatientService.admitPatient(p); const data = await PatientService.getAll(); setPatients(data); setShowAdmissionModal(false); }} />}
            {showCamera && <CameraCapture mode="PHOTO" onCapture={url => setAttachments([...attachments, {url, label:'Imagen Clínica', type:'IMAGE'}])} onClose={() => setShowCamera(false)} />}
        </div>
    );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Patient, Evolution, ClinicalAnalysis, ChatMessage } from '../types';
// Added FlorenceResponse to imports for type safety
import { analyzeClinicalNote, generateChatReply, FlorenceResponse } from '../services/geminiService';
import { PatientService } from '../services/firebaseMock';
import { ClipboardList, Search, User, AlertCircle, Monitor, Pill, BookOpen, FlaskConical, Cable, Megaphone, Ruler, PenTool, Activity, ShieldAlert, ArrowLeft, Bot, Send, X, Globe, Sparkles, Loader2, ChevronRight, Camera, Mic, Volume2, ShieldCheck, ExternalLink, Calendar, Clock, AlertTriangle, UserPlus, CheckCircle2 } from 'lucide-react';
import { VoiceInput } from './VoiceInput';
import { CameraCapture } from './CameraCapture';
import { WoundAnalysis } from './WoundAnalysis';
import { MedicationSheet } from './MedicationSheet';
import { VitalSigns } from './VitalSigns';
import { AccessManager } from './AccessManager';
import { LabResults } from './LabResults';
import { CarePlanManager } from './CarePlanManager';
import { ShiftHandoff } from './ShiftHandoff';
import { AdmissionModal } from './AdmissionModal';

const CLINICAL_MODULES = [
    { id: 'NOTES', label: 'Evolución', icon: PenTool, color: 'text-indigo-600', bg: 'bg-indigo-50' },
    { id: 'MONITOR', label: 'Monitor', icon: Monitor, color: 'text-emerald-600', bg: 'bg-emerald-50' },
    { id: 'MEDS', label: 'Fármacos', icon: Pill, color: 'text-blue-600', bg: 'bg-blue-50' },
    { id: 'PAE', label: 'PAE', icon: BookOpen, color: 'text-violet-600', bg: 'bg-violet-50' },
    { id: 'LABS', label: 'Laboratorio', icon: FlaskConical, color: 'text-purple-600', bg: 'bg-purple-50' },
    { id: 'ACCESS', label: 'Disp.', icon: Cable, color: 'text-orange-600', bg: 'bg-orange-50' },
    { id: 'WOUNDS', label: 'Heridas', icon: Ruler, color: 'text-rose-600', bg: 'bg-rose-50' },
    { id: 'HANDOFF', label: 'Pase', icon: Megaphone, color: 'text-amber-600', bg: 'bg-amber-50' },
] as const;

type ModuleId = typeof CLINICAL_MODULES[number]['id'];

export const ClinicalFollowUp: React.FC = () => {
    const [patients, setPatients] = useState<Patient[]>([]);
    const [selectedPatientId, setSelectedPatientId] = useState<string | null>(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [detailTab, setDetailTab] = useState<ModuleId>('NOTES');
    const [isFlorenceOpen, setIsFlorenceOpen] = useState(false);

    const [showCamera, setShowCamera] = useState(false);
    const [showAdmissionModal, setShowAdmissionModal] = useState(false);

    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [analysisResult, setAnalysisResult] = useState<ClinicalAnalysis | null>(null);

    const [noteText, setNoteText] = useState('');
    const [vitalsInput, setVitalsInput] = useState({ ta: '', fc: '', sat: '', temp: '', gcs: '' });
    const [attachments, setAttachments] = useState<{url:string, label:string, type:'IMAGE'|'AUDIO'}[]>([]);

    const [florenceMessages, setFlorenceMessages] = useState<ChatMessage[]>([]);
    const [florenceInput, setFlorenceInput] = useState('');
    const [isFlorenceTyping, setIsFlorenceTyping] = useState(false);
    const chatEndRef = useRef<HTMLDivElement>(null);

    // Fix: Define loadData to resolve "Cannot find name 'loadData'" errors when used in child component callbacks
    const loadData = async () => {
        const data = await PatientService.getAll();
        setPatients(data);
    };

    useEffect(() => {
        loadData();
    }, []);

    const selectedPatient = useMemo(() => patients.find(p => p.id === selectedPatientId), [patients, selectedPatientId]);

    const groupedHistory = useMemo(() => {
        if (!selectedPatient?.history) return {};
        const groups: Record<string, Evolution[]> = {};
        selectedPatient.history.forEach(h => {
            let label = new Date(h.timestamp).toLocaleDateString([], {day: 'numeric', month: 'long'});
            const d = new Date(h.timestamp);
            const now = new Date();
            if (d.getDate() === now.getDate() && d.getMonth() === now.getMonth()) label = 'Hoy';
            if (!groups[label]) groups[label] = [];
            groups[label].push(h);
        });
        return groups;
    }, [selectedPatient?.history]);

    const handleSaveNote = async () => {
        if (!selectedPatientId || !noteText.trim()) return;
        const newNote: Evolution = {
            id: `ev-${Date.now()}`,
            timestamp: new Date().toISOString(),
            note: noteText,
            vitals: { ...vitalsInput },
            type: 'EVOLUTION',
            riskLevel: 'STABLE', 
            analysis: analysisResult || undefined,
            attachments: attachments
        };
        await PatientService.addEvolution(selectedPatientId, newNote);
        const updated = await PatientService.getAll();
        setPatients(updated);
        setNoteText('');
        setVitalsInput({ ta: '', fc: '', sat: '', temp: '', gcs: '' });
        setAttachments([]);
        setAnalysisResult(null);
    };

    const handleAnalyzeNote = async () => {
        if (!noteText.trim()) return;
        setIsAnalyzing(true);
        try {
            const result = await analyzeClinicalNote(noteText);
            setAnalysisResult(result);
        } catch(e) { console.error(e); }
        finally { setIsAnalyzing(false); }
    };

    const handleFlorenceSend = async (textOverride?: string) => {
        const text = textOverride || florenceInput;
        if(!text.trim() || !selectedPatient) return;

        const userMsg: ChatMessage = {
            id: Date.now().toString(),
            userId: 'me',
            userName: 'Yo',
            role: 'NURSE',
            text: text,
            timestamp: new Date().toISOString()
        };
        setFlorenceMessages(prev => [...prev, userMsg]);
        setFlorenceInput('');
        setIsFlorenceTyping(true);

        try {
            const response = await generateChatReply(text, 'MENTOR', selectedPatient);
            const aiMsg: ChatMessage = {
                id: 'ai-' + Date.now(),
                userId: 'florence',
                userName: 'Florence AI',
                role: 'ADMIN',
                text: response.answer,
                sources: response.sources,
                timestamp: new Date().toISOString(),
                isSystem: true
            };
            setFlorenceMessages(prev => [...prev, aiMsg]);
        } catch(e) {
            console.error(e);
        } finally {
            setIsFlorenceTyping(false);
        }
    };

    return (
        <div className="flex h-full flex-col bg-slate-100 overflow-hidden relative font-sans">
            <header className="bg-slate-900 text-white border-b border-slate-800 px-6 py-4 flex justify-between items-center shrink-0 z-20 shadow-xl">
                <div className="flex items-center gap-3">
                    <div className="bg-indigo-600 p-2 rounded-xl shadow-lg">
                        <ClipboardList className="w-5 h-5"/>
                    </div>
                    <div>
                        <h1 className="text-lg font-black tracking-tight uppercase">Hospital OS <span className="text-indigo-400">Clinical v22</span></h1>
                        <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Unidad de Vigilancia Activa</p>
                    </div>
                </div>
                <button onClick={() => setShowAdmissionModal(true)} className="bg-emerald-600 hover:bg-emerald-700 text-white px-5 py-2.5 rounded-xl text-xs font-black shadow-lg transition-all flex items-center active:scale-95 border border-emerald-500">
                    <UserPlus className="w-4 h-4 mr-2"/> ADMITIR PACIENTE
                </button>
            </header>

            <div className="flex-1 overflow-hidden flex">
                <div className={`${selectedPatientId ? 'hidden lg:flex w-96' : 'flex w-full'} flex-col bg-white border-r border-slate-200 z-10 transition-all shadow-xl h-full`}>
                    <div className="p-5 border-b border-slate-100 sticky top-0 bg-white z-10">
                        <div className="relative group">
                            <Search className="absolute left-4 top-3.5 w-4 h-4 text-slate-400 group-focus-within:text-indigo-600 transition-colors"/>
                            <input 
                                value={searchTerm} 
                                onChange={e => setSearchTerm(e.target.value)} 
                                placeholder="Buscar paciente o cama..."
                                className="w-full pl-11 pr-4 py-3 rounded-2xl bg-slate-50 border border-slate-200 text-sm font-bold focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all placeholder:text-slate-400"
                            />
                        </div>
                    </div>

                    <div className="flex-1 overflow-y-auto custom-scrollbar p-3 space-y-3 bg-slate-50/50">
                        {patients.filter(p => p.name.toLowerCase().includes(searchTerm.toLowerCase())).map(patient => (
                            <button 
                                key={patient.id}
                                onClick={() => setSelectedPatientId(patient.id)}
                                className={`w-full text-left p-0 rounded-2xl border transition-all flex overflow-hidden group relative active:scale-[0.98] ${selectedPatientId === patient.id ? 'bg-white border-indigo-500 ring-2 ring-indigo-100 shadow-xl z-10' : 'bg-white border-slate-200 hover:border-indigo-300 shadow-sm'}`}
                            >
                                <div className={`w-1.5 shrink-0 ${patient.risk === 'HIGH' ? 'bg-rose-500 animate-pulse' : patient.risk === 'MEDIUM' ? 'bg-amber-400' : 'bg-emerald-500'}`}></div>
                                <div className="p-4 flex-1 min-w-0">
                                    <div className="flex justify-between items-start mb-2">
                                        <span className="font-black text-sm text-slate-800 truncate pr-2 uppercase tracking-tight">{patient.name}</span>
                                        <span className="text-[10px] font-black bg-slate-900 text-white px-2 py-0.5 rounded shadow-sm">{patient.bed}</span>
                                    </div>
                                    <div className="flex items-center gap-2 text-[10px] text-slate-500 font-bold uppercase tracking-tighter">
                                        <div className="flex items-center bg-slate-100 px-1.5 py-0.5 rounded border border-slate-200">
                                            {patient.sex} • {patient.age}a
                                        </div>
                                        <span className="truncate flex-1 text-indigo-600">{patient.diagnosis}</span>
                                    </div>
                                    <div className="mt-3 flex items-center gap-2">
                                        <span className={`text-[10px] font-black px-2 py-0.5 rounded border ${patient.risk === 'HIGH' ? 'text-rose-600 bg-rose-50 border-rose-100' : 'text-emerald-600 bg-emerald-50 border-emerald-100'}`}>
                                            NEWS2 {patient.news2}
                                        </span>
                                    </div>
                                </div>
                                <div className="p-3 flex items-center justify-center bg-slate-50 border-l border-slate-100 text-slate-300 group-hover:text-indigo-500 transition-colors">
                                    <ChevronRight className="w-5 h-5"/>
                                </div>
                            </button>
                        ))}
                    </div>
                </div>

                {selectedPatient ? (
                    <div className="flex-1 flex flex-col bg-slate-50 relative overflow-hidden h-full">
                        <div className="bg-white border-b border-slate-200 shadow-sm shrink-0 z-10 p-4 md:p-6">
                            <div className="flex justify-between items-start gap-4">
                                <div className="flex items-center gap-5 overflow-hidden">
                                    <button onClick={() => setSelectedPatientId(null)} className="lg:hidden p-2.5 bg-slate-100 rounded-full text-slate-500 active:scale-90 transition-transform">
                                        <ArrowLeft className="w-5 h-5"/>
                                    </button>
                                    <div className="min-w-0">
                                        <div className="flex items-center gap-3 mb-1">
                                            <h2 className="text-xl md:text-3xl font-black text-slate-900 truncate uppercase tracking-tighter">{selectedPatient.name}</h2>
                                            <span className="bg-indigo-600 text-white text-[10px] font-black px-3 py-1 rounded-full shadow-lg shadow-indigo-600/30">{selectedPatient.bed}</span>
                                        </div>
                                        <div className="flex items-center gap-3 text-xs font-black uppercase text-slate-400 overflow-x-auto no-scrollbar whitespace-nowrap">
                                            <span>{selectedPatient.age} Años</span>
                                            <span className="text-slate-200">|</span>
                                            <span className="text-rose-600 bg-rose-50 px-2 py-0.5 rounded border border-rose-100 flex items-center shadow-sm"><ShieldAlert className="w-3 h-3 mr-1"/> Alergias: {selectedPatient.allergies}</span>
                                            <span className="text-slate-200">|</span>
                                            <span>Peso: {selectedPatient.weight} kg</span>
                                        </div>
                                    </div>
                                </div>
                                <button onClick={() => setIsFlorenceOpen(true)} className="bg-gradient-to-tr from-violet-600 to-indigo-700 text-white p-3.5 rounded-2xl shadow-xl hover:scale-105 active:scale-95 transition-all shrink-0">
                                    <Bot className="w-6 h-6"/>
                                </button>
                            </div>

                            <div className="flex gap-2 mt-6 overflow-x-auto no-scrollbar scroll-smooth">
                                {CLINICAL_MODULES.map(m => (
                                    <button
                                        key={m.id}
                                        onClick={() => setDetailTab(m.id)}
                                        className={`px-4 py-2.5 rounded-xl text-xs font-black uppercase tracking-wider transition-all flex items-center whitespace-nowrap border-2 ${detailTab === m.id ? `bg-slate-900 text-white border-slate-900 shadow-xl` : 'bg-white text-slate-500 border-slate-100 hover:border-slate-200 hover:bg-slate-50'}`}
                                    >
                                        <m.icon className={`w-4 h-4 mr-2 ${detailTab === m.id ? 'text-indigo-400' : m.color}`}/> 
                                        {m.label}
                                    </button>
                                ))}
                            </div>
                        </div>

                        <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar bg-slate-50/50 pb-32">
                            <div className="max-w-6xl mx-auto">
                                {detailTab === 'NOTES' && (
                                    <div className="space-y-8 animate-fade-in">
                                        {analysisResult && (
                                            <div className="bg-indigo-900 text-white p-6 rounded-[2.5rem] shadow-2xl border-l-[16px] border-l-emerald-500 relative overflow-hidden group">
                                                <div className="flex items-start gap-5 relative z-10">
                                                    <div className="bg-emerald-500 p-2.5 rounded-2xl"><Sparkles className="w-7 h-7 text-white animate-pulse"/></div>
                                                    <div className="flex-1">
                                                        <h4 className="text-[10px] font-black uppercase tracking-[0.25em] text-emerald-400 mb-2">SBAR Clinical Intelligence</h4>
                                                        <p className="text-base font-bold leading-relaxed mb-5">"{analysisResult.sbarSummary}"</p>
                                                        <div className="flex flex-wrap gap-2.5">
                                                            {analysisResult.detectedRisks.map((r, i) => (
                                                                <span key={i} className="bg-rose-500/20 text-rose-200 border border-rose-500/30 px-3.5 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-tight">{r}</span>
                                                            ))}
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                        )}

                                        <div className="bg-white p-6 rounded-[2.5rem] border border-slate-200 shadow-xl relative overflow-hidden">
                                            <div className="flex justify-between items-center mb-6">
                                                <h3 className="text-xs font-black text-slate-800 uppercase tracking-widest flex items-center">
                                                    <PenTool className="w-4 h-4 mr-2 text-indigo-600"/> Registro de Evolución
                                                </h3>
                                                <div className="flex gap-2">
                                                    <VoiceInput onTranscript={t => setNoteText(prev => prev + " " + t)} isCompact />
                                                </div>
                                            </div>

                                            <textarea 
                                                value={noteText} 
                                                onChange={e => setNoteText(e.target.value)} 
                                                placeholder="Describe el estado clínico, cambios en la monitorización o respuesta a fármacos..." 
                                                className="w-full min-h-[180px] bg-slate-50/50 border-2 border-transparent rounded-3xl p-6 text-base font-bold text-slate-700 focus:bg-white focus:border-indigo-500/30 focus:ring-8 focus:ring-indigo-500/5 outline-none resize-none placeholder:text-slate-400 transition-all mb-6"
                                            />

                                            <div className="flex justify-between items-center pt-6 border-t border-slate-100">
                                                <button 
                                                    onClick={handleAnalyzeNote} 
                                                    disabled={!noteText.trim() || isAnalyzing} 
                                                    className="text-xs font-black text-indigo-600 flex items-center hover:bg-indigo-50 px-6 py-3 rounded-2xl transition-all disabled:opacity-50"
                                                >
                                                    {isAnalyzing ? <Loader2 className="w-5 h-5 animate-spin mr-2"/> : <Sparkles className="w-5 h-5 mr-2"/>}
                                                    ANÁLISIS PREDICTIVO
                                                </button>
                                                <button 
                                                    onClick={handleSaveNote} 
                                                    disabled={!noteText.trim()} 
                                                    className="bg-slate-900 text-white px-12 py-4 rounded-2xl text-xs font-black uppercase tracking-widest shadow-2xl hover:bg-black transition-all active:scale-95 disabled:opacity-50"
                                                >
                                                    REGISTRAR EVOLUCIÓN
                                                </button>
                                            </div>
                                        </div>

                                        <div className="space-y-10">
                                            {Object.entries(groupedHistory).map(([date, entries]) => (
                                                <div key={date} className="relative">
                                                    <div className="sticky top-0 z-10 py-4 mb-8 bg-slate-50/90 backdrop-blur-xl flex items-center gap-5">
                                                        <div className="bg-slate-200 px-4 py-1.5 rounded-xl text-[10px] font-black text-slate-600 uppercase tracking-[0.25em] border border-slate-300 shadow-sm">{date}</div>
                                                        <div className="h-px bg-slate-300 flex-1 opacity-50"></div>
                                                    </div>
                                                    <div className="space-y-8 relative ml-4 border-l-4 border-slate-200 pl-10 pb-4">
                                                        {entries.map(h => (
                                                            <div key={h.id} className="relative bg-white p-7 rounded-[2.5rem] border border-slate-200 shadow-md hover:shadow-xl transition-all group overflow-hidden">
                                                                <div className="absolute -left-[46px] top-8 w-6 h-6 bg-white border-4 border-indigo-600 rounded-full z-10 shadow-lg group-hover:scale-125 transition-transform"></div>
                                                                <div className="flex justify-between items-start mb-4">
                                                                    <span className="text-[11px] font-black text-indigo-600 uppercase bg-indigo-50 px-3 py-1.5 rounded-xl flex items-center border border-indigo-100">
                                                                        <Clock className="w-4 h-4 mr-2"/>
                                                                        {new Date(h.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}
                                                                    </span>
                                                                    {h.riskLevel === 'CRITICAL' && <AlertTriangle className="w-6 h-6 text-rose-500 animate-pulse"/>}
                                                                </div>
                                                                <p className="text-base font-medium text-slate-700 leading-relaxed whitespace-pre-wrap">{h.note}</p>
                                                                {/* Fix: Added optional chaining to ensure h.analysis exists when mapping suggested NANDA */}
                                                                {h.analysis?.suggestedNanda && Array.isArray(h.analysis.suggestedNanda) && (
                                                                    <div className="mt-6 pt-6 border-t border-slate-50 flex flex-wrap gap-3">
                                                                        {h.analysis.suggestedNanda.slice(0, 3).map((n, idx) => (
                                                                            <span key={idx} className="bg-emerald-50 text-emerald-800 px-4 py-1.5 rounded-full text-[10px] font-black uppercase border border-emerald-100 flex items-center shadow-sm">
                                                                                <ShieldCheck className="w-3.5 h-3.5 mr-2 text-emerald-500"/> {n}
                                                                            </span>
                                                                        ))}
                                                                    </div>
                                                                )}
                                                            </div>
                                                        ))}
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                )}

                                {detailTab === 'MONITOR' && <VitalSigns history={selectedPatient.history} />}
                                {detailTab === 'MEDS' && <MedicationSheet prescriptions={selectedPatient.prescriptions || []} onUpdate={p => PatientService.updatePatient(selectedPatient.id, {prescriptions: p}).then(loadData)} />}
                                {detailTab === 'PAE' && <CarePlanManager carePlans={selectedPatient.activePae || []} onUpdate={p => PatientService.updatePatient(selectedPatient.id, {activePae: p}).then(loadData)} />}
                                {detailTab === 'LABS' && <LabResults reports={selectedPatient.labReports || []} />}
                                {detailTab === 'ACCESS' && <AccessManager devices={selectedPatient.activeDevices || []} onUpdate={d => PatientService.updatePatient(selectedPatient.id, {activeDevices: d}).then(loadData)} />}
                                {detailTab === 'WOUNDS' && <WoundAnalysis wounds={selectedPatient.wounds || []} onAddWound={w => PatientService.updatePatient(selectedPatient.id, {wounds: [w, ...(selectedPatient.wounds||[])]}).then(loadData)} />}
                                {detailTab === 'HANDOFF' && <ShiftHandoff patient={selectedPatient} onSendToChat={handleFlorenceSend} />}
                            </div>
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 hidden md:flex flex-col items-center justify-center bg-slate-50/50 text-slate-300">
                        <div className="w-40 h-40 bg-white rounded-full flex items-center justify-center shadow-2xl border border-slate-100 mb-8">
                            <User className="w-16 h-16 opacity-10"/>
                        </div>
                        <p className="text-base font-black uppercase tracking-[0.4em]">Seleccione un Paciente del Censo</p>
                    </div>
                )}
            </div>

            {isFlorenceOpen && selectedPatient && (
                <div className="fixed inset-0 z-50 flex justify-end">
                    <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm transition-opacity" onClick={() => setIsFlorenceOpen(false)}></div>
                    <div className="w-full md:w-[580px] bg-slate-50 h-full shadow-[0_0_120px_rgba(0,0,0,0.6)] relative flex flex-col animate-slide-in-right overflow-hidden border-l border-white/10">
                        <div className="p-7 bg-slate-900 text-white flex justify-between items-center shadow-2xl shrink-0 relative overflow-hidden">
                            <div className="flex items-center gap-5 relative z-10">
                                <div className="relative">
                                    <div className="w-16 h-16 bg-white rounded-2xl p-0.5 shadow-2xl rotate-2">
                                        <img src="https://ui-avatars.com/api/?name=Florence+AI&background=7c3aed&color=fff" className="w-full h-full rounded-[0.8rem] shadow-inner" alt="Florence"/>
                                    </div>
                                    <div className="absolute -bottom-1 -right-1 w-5 h-5 bg-emerald-500 border-4 border-slate-900 rounded-full shadow-lg"></div>
                                </div>
                                <div>
                                    <h3 className="font-black text-xl tracking-tight uppercase">Florence AI <span className="text-indigo-400 text-xs ml-2 px-2 py-0.5 rounded-full border border-indigo-500/50">v3.0 PRO</span></h3>
                                    <div className="flex items-center gap-3 mt-1">
                                        <div className="flex items-center text-[10px] font-black text-indigo-300 bg-indigo-500/20 px-2.5 py-1 rounded-full border border-indigo-500/30">
                                            <Globe className="w-3.5 h-3.5 mr-2"/> GROUNDING ACTIVO
                                        </div>
                                    </div>
                                </div>
                            </div>
                            <button onClick={() => setIsFlorenceOpen(false)} className="p-3 hover:bg-white/10 rounded-full transition-colors relative z-10 border border-white/10"><X className="w-6 h-6"/></button>
                        </div>

                        <div className="flex-1 overflow-y-auto p-6 space-y-8 custom-scrollbar bg-slate-100/30">
