export const ClinicalFollowUp: React.FC = () => {
    const [patients, setPatients] = useState<Patient[]>([]);
    const [selectedPatientId, setSelectedPatientId] = useState<string | null>(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [detailTab, setDetailTab] = useState<string>('NOTES');
    const [isFlorenceOpen, setIsFlorenceOpen] = useState(false);

    // UI State
    const [showCamera, setShowCamera] = useState(false);
    const [showAdmissionModal, setShowAdmissionModal] = useState(false);
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [analysisResult, setAnalysisResult] = useState<ClinicalAnalysis | null>(null);
    const [noteText, setNoteText] = useState('');

    // AI Chat
    const [florenceMessages, setFlorenceMessages] = useState<ChatMessage[]>([]);
    const [florenceInput, setFlorenceInput] = useState('');
    const [isFlorenceTyping, setIsFlorenceTyping] = useState(false);

    const loadData = async () => {
        const data = await PatientService.getAll();
        setPatients(data);
    };

    useEffect(() => { loadData(); }, []);

    const selectedPatient = useMemo(() => patients.find(p => p.id === selectedPatientId), [patients, selectedPatientId]);

    const groupedHistory = useMemo(() => {
        if (!selectedPatient?.history) return {};
        const groups: Record<string, Evolution[]> = {};
        selectedPatient.history.forEach(h => {
            let label = new Date(h.timestamp).toLocaleDateString([], {day: 'numeric', month: 'long'});
            if (new Date(h.timestamp).toDateString() === new Date().toDateString()) label = 'Hoy';
            if (!groups[label]) groups[label] = [];
            groups[label].push(h);
        });
        return groups;
    }, [selectedPatient?.history]);

    const handleSaveNote = async () => {
        if (!selectedPatientId || !noteText.trim()) return;
        const newNote: Evolution = {
            id: `ev-${Date.now()}`,
            timestamp: new Date().toISOString(),
            note: noteText,
            type: 'EVOLUTION',
            analysis: analysisResult || undefined
        };
        await PatientService.addEvolution(selectedPatientId, newNote);
        await loadData();
        setNoteText('');
        setAnalysisResult(null);
    };

    const handleAnalyzeNote = async () => {
        if (!noteText.trim()) return;
        setIsAnalyzing(true);
        try {
            const result = await analyzeClinicalNote(noteText);
            setAnalysisResult(result);
        } catch(e) { console.error(e); }
        finally { setIsAnalyzing(false); }
    };

    const handleFlorenceSend = async (textOverride?: string) => {
        const text = textOverride || florenceInput;
        if(!text.trim() || !selectedPatient) return;

        const userMsg: ChatMessage = { id: Date.now().toString(), userId: 'me', userName: 'Yo', role: 'NURSE', text: text, timestamp: new Date().toISOString() };
        setFlorenceMessages(prev => [...prev, userMsg]);
        setFlorenceInput('');
        setIsFlorenceTyping(true);

        try {
            const response = await generateChatReply(text, selectedPatient);
            const aiMsg: ChatMessage = {
                id: 'ai-' + Date.now(), userId: 'florence', userName: 'Florence AI', role: 'ADMIN',
                text: JSON.stringify(response), timestamp: new Date().toISOString(), isSystem: true
            };
            setFlorenceMessages(prev => [...prev, aiMsg]);
        } catch(e) { console.error(e); }
        finally { setIsFlorenceTyping(false); }
    };

    return (
        <div className="flex h-full flex-col bg-slate-100 overflow-hidden relative font-sans">
            <header className="bg-slate-900 text-white border-b border-slate-800 px-6 py-4 flex justify-between items-center z-20 shadow-xl shrink-0">
                <div className="flex items-center gap-3">
                    <div className="bg-indigo-600 p-2 rounded-xl shadow-lg"><ClipboardList className="w-5 h-5"/></div>
                    <div>
                        <h1 className="text-lg font-black tracking-tight uppercase">Hospital OS <span className="text-indigo-400">Clinical PRO</span></h1>
                        <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Unidad de Gestión Avanzada</p>
                    </div>
                </div>
                <button onClick={() => setShowAdmissionModal(true)} className="bg-emerald-600 hover:bg-emerald-700 text-white px-5 py-2.5 rounded-xl text-xs font-black shadow-lg active:scale-95 transition-all">
                    <UserPlus className="w-4 h-4 mr-2"/> ADMITIR
                </button>
            </header>

            <div className="flex-1 flex overflow-hidden">
                <div className={`${selectedPatientId ? 'hidden lg:flex w-96' : 'flex w-full'} flex-col bg-white border-r border-slate-200 z-10 shadow-xl h-full shrink-0`}>
                    <div className="p-5 border-b border-slate-100 sticky top-0 bg-white z-10">
                        <div className="relative">
                            <Search className="absolute left-4 top-3.5 w-4 h-4 text-slate-400"/>
                            <input 
                                value={searchTerm} 
                                onChange={e => setSearchTerm(e.target.value)} 
                                placeholder="Buscar paciente o cama..."
                                className="w-full pl-11 pr-4 py-3 rounded-2xl bg-slate-50 border border-slate-200 text-sm font-bold focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all"
                            />
                        </div>
                    </div>
                    <div className="flex-1 overflow-y-auto p-3 space-y-3 bg-slate-50/50 custom-scrollbar">
                        {patients.filter(p => p.name.toLowerCase().includes(searchTerm.toLowerCase())).map(patient => (
                            <button 
                                key={patient.id}
                                onClick={() => setSelectedPatientId(patient.id)}
                                className={`w-full text-left p-4 rounded-2xl border transition-all flex items-center justify-between ${selectedPatientId === patient.id ? 'bg-white border-indigo-500 ring-2 ring-indigo-50 shadow-xl' : 'bg-white border-slate-200 hover:border-indigo-300 shadow-sm'}`}
                            >
                                <div className="flex-1 min-w-0">
                                    <div className="flex justify-between items-center mb-1">
                                        <span className="font-black text-sm text-slate-800 truncate pr-2 uppercase">{patient.name}</span>
                                        <span className="text-[10px] font-black bg-slate-900 text-white px-2 py-0.5 rounded">{patient.bed}</span>
                                    </div>
                                    <p className="text-[10px] text-slate-500 font-bold uppercase truncate">{patient.diagnosis}</p>
                                    <div className={`mt-2 inline-block px-2 py-0.5 rounded text-[9px] font-black uppercase ${patient.risk === 'HIGH' ? 'bg-rose-50 text-rose-600' : 'bg-emerald-50 text-emerald-600'}`}>NEWS2 {patient.news2}</div>
                                </div>
                                <ChevronRight className="w-5 h-5 text-slate-300 ml-3"/>
                            </button>
                        ))}
                    </div>
                </div>

                {selectedPatient ? (
                    <div className="flex-1 flex flex-col bg-slate-50 relative overflow-hidden h-full">
                        <div className="bg-white border-b border-slate-200 shadow-sm p-4 md:p-6 shrink-0 z-10">
                            <div className="flex justify-between items-start gap-4">
                                <div className="flex items-center gap-4 min-w-0">
                                    <button onClick={() => setSelectedPatientId(null)} className="lg:hidden p-2.5 bg-slate-100 rounded-full text-slate-500"><ArrowLeft className="w-5 h-5"/></button>
                                    <div>
                                        <div className="flex items-center gap-3">
                                            <h2 className="text-xl md:text-2xl font-black text-slate-900 uppercase tracking-tighter truncate">{selectedPatient.name}</h2>
                                            <span className="bg-indigo-600 text-white text-[10px] font-black px-2 py-1 rounded-lg">{selectedPatient.bed}</span>
                                        </div>
                                        <div className="flex gap-3 text-xs font-bold text-slate-400 uppercase mt-1">
                                            <span>{selectedPatient.age} Años</span>
                                            <span>{selectedPatient.weight} kg</span>
                                            <span className="text-rose-500 flex items-center gap-1"><ShieldAlert className="w-3.5 h-3.5"/> {selectedPatient.allergies}</span>
                                        </div>
                                    </div>
                                </div>
                                <button onClick={() => setIsFlorenceOpen(true)} className="bg-gradient-to-tr from-violet-600 to-indigo-700 text-white p-3 rounded-2xl shadow-xl shadow-indigo-600/20 active:scale-95 transition-all">
                                    <Bot className="w-7 h-7"/>
                                </button>
                            </div>
                            <div className="flex gap-2 mt-6 overflow-x-auto no-scrollbar scroll-smooth">
                                {CLINICAL_MODULES.map(m => (
                                    <button
                                        key={m.id}
                                        onClick={() => setDetailTab(m.id)}
                                        className={`px-4 py-2.5 rounded-xl text-xs font-black uppercase tracking-wider transition-all flex items-center whitespace-nowrap border-2 ${detailTab === m.id ? `bg-slate-900 text-white border-slate-900 shadow-xl` : 'bg-white text-slate-500 border-slate-100 hover:border-slate-200 hover:bg-slate-50'}`}
                                    >
                                        <m.icon className={`w-4 h-4 mr-2 ${detailTab === m.id ? 'text-indigo-400' : m.color}`}/> {m.label}
                                    </button>
                                ))}
                            </div>
                        </div>

                        <div className="flex-1 overflow-y-auto p-4 md:p-8 bg-slate-50/50 custom-scrollbar pb-32">
                            <div className="max-w-5xl mx-auto">
                                {detailTab === 'NOTES' && (
                                    <div className="space-y-8 animate-fade-in">
                                        {analysisResult && (
                                            <div className="bg-indigo-900 text-white p-6 rounded-[2rem] shadow-2xl border-l-[16px] border-l-emerald-500 relative overflow-hidden group">
                                                <div className="flex items-start gap-5 relative z-10">
                                                    <div className="bg-emerald-500 p-2 rounded-2xl"><Sparkles className="w-7 h-7 text-white animate-pulse"/></div>
                                                    <div className="flex-1">
                                                        <h4 className="text-[10px] font-black uppercase tracking-[0.25em] text-emerald-400 mb-2">Resumen SBAR (IA)</h4>
                                                        <p className="text-base font-bold leading-relaxed mb-4">"{analysisResult.sbarSummary}"</p>
                                                        <div className="flex flex-wrap gap-2">
                                                            {analysisResult.detectedRisks.map((r, i) => (
                                                                <span key={i} className="bg-rose-500/20 text-rose-200 border border-rose-500/30 px-3 py-1 rounded-xl text-[10px] font-black uppercase tracking-tight">{r}</span>
                                                            ))}
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                        )}

                                        <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-xl relative overflow-hidden">
                                            <div className="flex justify-between items-center mb-6">
                                                <h3 className="text-xs font-black text-slate-800 uppercase tracking-widest flex items-center">
                                                    <PenTool className="w-4 h-4 mr-2 text-indigo-600"/> Evolución Enfermera
                                                </h3>
                                                <div className="flex gap-2">
                                                    <VoiceInput onTranscript={t => setNoteText(prev => prev + " " + t)} isCompact />
                                                    <button onClick={() => setShowCamera(true)} className="p-2 bg-slate-100 rounded-full text-slate-500 hover:text-indigo-600 transition-colors"><Camera className="w-5 h-5"/></button>
                                                </div>
                                            </div>
                                            <textarea 
                                                value={noteText} 
                                                onChange={e => setNoteText(e.target.value)} 
                                                placeholder="Registre el estado del paciente, cambios en monitorización o respuesta a tratamientos..." 
                                                className="w-full min-h-[160px] bg-slate-50/50 border-2 border-transparent rounded-3xl p-6 text-base font-bold text-slate-700 focus:bg-white focus:border-indigo-500/30 focus:ring-8 focus:ring-indigo-500/5 outline-none resize-none placeholder:text-slate-400 transition-all mb-6"
                                            />
                                            <div className="flex justify-between items-center pt-6 border-t border-slate-100">
                                                <button onClick={handleAnalyzeNote} disabled={!noteText.trim() || isAnalyzing} className="text-xs font-black text-indigo-600 flex items-center hover:bg-indigo-50 px-6 py-3 rounded-2xl transition-all disabled:opacity-50">
                                                    {isAnalyzing ? <Loader2 className="w-5 h-5 animate-spin mr-2"/> : <Sparkles className="w-5 h-5 mr-2"/>} ANÁLISIS IA
                                                </button>
                                                <button onClick={handleSaveNote} disabled={!noteText.trim()} className="bg-slate-900 text-white px-10 py-4 rounded-2xl text-xs font-black uppercase tracking-widest shadow-2xl active:scale-95 transition-all">REGISTRAR EVOLUCIÓN</button>
                                            </div>
                                        </div>

                                        <div className="space-y-8">
                                            {Object.entries(groupedHistory).map(([date, entries]) => (
                                                <div key={date} className="relative">
                                                    <div className="sticky top-0 z-10 py-3 mb-6 bg-slate-50/90 backdrop-blur-xl flex items-center gap-4">
                                                        <div className="bg-slate-200 px-3 py-1 rounded-xl text-[10px] font-black text-slate-600 uppercase tracking-widest border border-slate-300">{date}</div>
                                                        <div className="h-px bg-slate-300 flex-1"></div>
                                                    </div>
                                                    <div className="space-y-6 relative ml-4 border-l-4 border-slate-200 pl-10">
                                                        {entries.map(h => (
                                                            <div key={h.id} className="relative bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm group">
                                                                <div className="absolute -left-[45px] top-6 w-5 h-5 bg-white border-4 border-indigo-600 rounded-full z-10 shadow-md"></div>
                                                                <div className="flex justify-between items-start mb-3">
                                                                    <span className="text-[11px] font-black text-indigo-600 uppercase bg-indigo-50 px-2 py-1 rounded-lg flex items-center gap-1.5"><Clock className="w-4 h-4"/> {new Date(h.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span>
                                                                    {h.riskLevel === 'CRITICAL' && <AlertTriangle className="w-5 h-5 text-rose-500 animate-pulse"/>}
                                                                </div>
                                                                <p className="text-sm font-medium text-slate-700 leading-relaxed whitespace-pre-wrap">{h.note}</p>
                                                                {h.analysis?.suggestedNanda && (
                                                                    <div className="mt-4 pt-4 border-t border-slate-50 flex flex-wrap gap-2">
                                                                        {h.analysis.suggestedNanda.map((n, idx) => (
                                                                            <span key={idx} className="bg-emerald-50 text-emerald-800 px-3 py-1 rounded-full text-[10px] font-black uppercase border border-emerald-100 flex items-center gap-1.5"><ShieldCheck className="w-3 h-3 text-emerald-500"/> {n}</span>
                                                                        ))}
                                                                    </div>
                                                                )}
                                                            </div>
                                                        ))}
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                )}

                                {detailTab === 'MONITOR' && <VitalSigns history={selectedPatient.history} />}
                                {detailTab === 'MEDS' && <MedicationSheet prescriptions={selectedPatient.prescriptions || []} onUpdate={p => PatientService.updatePatient(selectedPatient.id, {prescriptions: p}).then(loadData)} />}
                                {detailTab === 'PAE' && <CarePlanManager carePlans={selectedPatient.activePae || []} onUpdate={p => PatientService.updatePatient(selectedPatient.id, {activePae: p}).then(loadData)} />}
                                {detailTab === 'LABS' && <LabResults reports={selectedPatient.labReports || []} />}
                                {detailTab === 'ACCESS' && <AccessManager devices={selectedPatient.activeDevices || []} onUpdate={d => PatientService.updatePatient(selectedPatient.id, {activeDevices: d}).then(loadData)} />}
                                {detailTab === 'WOUNDS' && <WoundAnalysis wounds={selectedPatient.wounds || []} onAddWound={w => PatientService.updatePatient(selectedPatient.id, {wounds: [w, ...(selectedPatient.wounds||[])]}).then(loadData)} />}
                                {detailTab === 'HANDOFF' && <ShiftHandoff patient={selectedPatient} onSendToChat={handleFlorenceSend} />}
                            </div>
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 hidden md:flex flex-col items-center justify-center bg-slate-50/50 text-slate-300">
                        <div className="w-40 h-40 bg-white rounded-full flex items-center justify-center shadow-2xl mb-6"><User className="w-20 h-20 opacity-10"/></div>
                        <p className="text-sm font-black uppercase tracking-[0.4em]">Seleccione un Paciente</p>
                    </div>
                )}
            </div>

            {/* Florence Floating Side-Over */}
            {isFlorenceOpen && selectedPatient && (
                <div className="fixed inset-0 z-50 flex justify-end">
                    <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm transition-opacity" onClick={() => setIsFlorenceOpen(false)}></div>
                    <div className="w-full md:w-[600px] bg-slate-50 h-full shadow-[0_0_100px_rgba(0,0,0,0.5)] relative flex flex-col animate-slide-in-right border-l border-white/10">
                        <div className="p-6 bg-slate-900 text-white flex justify-between items-center shadow-2xl shrink-0">
                            <div className="flex items-center gap-4">
                                <div className="w-12 h-12 bg-white rounded-2xl p-0.5 shadow-2xl"><img src="https://ui-avatars.com/api/?name=Florence+AI&background=7c3aed&color=fff" className="w-full h-full rounded-2xl" alt="AI"/></div>
                                <div>
                                    <h3 className="font-black text-xl tracking-tight uppercase">Florence AI <span className="text-indigo-400 text-xs ml-2 border border-indigo-500/50 px-2 py-0.5 rounded-full">v3.0</span></h3>
                                    <div className="flex items-center text-[10px] font-black text-indigo-300 bg-indigo-500/20 px-2 py-1 rounded-full border border-indigo-500/30 w-fit mt-1"><Globe className="w-3.5 h-3.5 mr-2"/> EVIDENCE GROUNDING ACTIVO</div>
                                </div>
                            </div>
                            <button onClick={() => setIsFlorenceOpen(false)} className="p-2 hover:bg-white/10 rounded-full transition-colors"><X className="w-6 h-6"/></button>
                        </div>
                        <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar bg-slate-100/30">
                            {florenceMessages.map((msg, i) => {
                                const isMe = msg.role === 'NURSE';
                                let data: any = null;
                                if (!isMe) { try { data = msg.text?.startsWith('{') ? JSON.parse(msg.text) : null; } catch(e) { data = null; } }
                                const text = data ? data.answer : msg.text;
                                return (
                                    <div key={i} className={`flex ${isMe ? 'justify-end' : 'justify-start'} animate-fade-in-up`}>
                                        <div className={`max-w-[90%] p-5 rounded-[2rem] text-sm shadow-xl relative border ${isMe ? 'bg-indigo-600 text-white rounded-br-none border-indigo-500' : 'bg-white border-slate-200 text-slate-800 rounded-bl-none shadow-slate-200/50'}`}>
                                            {!isMe && data && (
                                                <div className="flex items-center justify-between mb-3 pb-2 border-b border-slate-100">
                                                    <span className="text-[10px] font-black text-violet-600 flex items-center gap-2 uppercase tracking-widest"><ShieldCheck className="w-4 h-4"/> JUICIO CLÍNICO</span>
                                                    <span className={`text-[8px] font-black px-2 py-0.5 rounded border ${data.confidence === 'HIGH' ? 'bg-emerald-50 text-emerald-700' : 'bg-amber-50 text-amber-700'}`}>FIABILIDAD: {data.confidence}</span>
                                                </div>
                                            )}
                                            <div className="whitespace-pre-wrap leading-relaxed font-medium">
                                                {text?.split(/(\*\*.*?\*\*)/g).map((part: string, i: number) => part.startsWith('**') && part.endsWith('**') ? <strong key={i} className={isMe ? "text-white" : "text-slate-900 font-black"}>{part.slice(2, -2)}</strong> : part)}
                                            </div>
                                            {!isMe && data?.sources && (
                                                <div className="mt-4 pt-3 border-t border-slate-100 space-y-2">
                                                    {data.sources.map((src: any, idx: number) => (
                                                        <a key={idx} href={src.uri} target="_blank" rel="noreferrer" className="flex items-center gap-3 bg-slate-50 hover:bg-indigo-50 border border-slate-200 p-2.5 rounded-xl transition-all group/link">
                                                            <div className="bg-white p-1.5 rounded border border-slate-100 group-hover/link:text-indigo-600 shadow-inner"><Globe className="w-3.5 h-3.5"/></div>
                                                            <div className="flex-1 min-w-0">
                                                                <div className="text-[10px] font-black text-slate-700 truncate">{src.title}</div>
                                                                <div className="text-[9px] text-slate-400 font-mono flex items-center">{new URL(src.uri).hostname} <ExternalLink className="w-2.5 h-2.5 ml-1 opacity-50"/></div>
                                                            </div>
                                                        </a>
                                                    ))}
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                );
                            })}
                            {isFlorenceTyping && (
                                <div className="flex justify-start"><div className="bg-white p-4 rounded-3xl rounded-tl-none shadow-xl border border-slate-100 flex gap-2"><span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></span><span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.15s]"></span><span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.3s]"></span></div></div>
                            )}
                        </div>
                        <div className="p-6 bg-white border-t border-slate-200 shadow-2xl"><form onSubmit={(e) => { e.preventDefault(); handleFlorenceSend(); }} className="flex items-center gap-3"><div className="flex-1 bg-slate-100 rounded-[2rem] p-1.5 flex items-center border-2 border-transparent focus-within:border-indigo-500/20 focus-within:bg-white transition-all shadow-inner"><button type="button" className="p-2.5 text-slate-400 hover:text-indigo-600 transition-colors"><Mic className="w-5 h-5"/></button><input className="flex-1 bg-transparent border-none focus:ring-0 outline-none text-sm font-bold text-slate-700 px-2" placeholder="Consulte guías, dosis o compatibilidad..." value={florenceInput} onChange={e => setFlorenceInput(e.target.value)}/></div><button type="submit" disabled={!florenceInput.trim() || isFlorenceTyping} className="p-4 bg-slate-900 text-white rounded-full shadow-2xl hover:bg-black transition-all active:scale-95 disabled:opacity-50"><Send className="w-6 h-6"/></button></form></div>
                    </div>
                </div>
            )}

            {showAdmissionModal && <AdmissionModal onClose={() => setShowAdmissionModal(false)} onSave={async (p) => { await PatientService.admitPatient(p); await loadData(); setShowAdmissionModal(false); }} />}
            {showCamera && <CameraCapture mode="PHOTO" onCapture={url => alert("Imagen capturada: " + url)} onClose={() => setShowCamera(false)} />}
        </div>
    );
};

import React, { useState } from 'react';
import { Prescription } from '../types';
import { Pill, Clock, Check, AlertTriangle, Plus, X, AlertOctagon, Sparkles, Loader2, RefreshCcw } from 'lucide-react';
import { checkDrugInteractions } from '../services/geminiService';

interface MedicationSheetProps {
    prescriptions: Prescription[];
    onUpdate: (updatedList: Prescription[]) => void;
}

export const MedicationSheet: React.FC<MedicationSheetProps> = ({ prescriptions, onUpdate }) => {
    const [interactionAlerts, setInteractionAlerts] = useState<string[]>([]);
    const [isChecking, setIsChecking] = useState(false);
    const [showAddModal, setShowAddModal] = useState(false);
    const [newMeds, setNewMeds] = useState<Partial<Prescription>>({ drugName: '', dose: '', route: 'IV', frequency: '24h', type: 'SCHEDULED' });

    const handleAdminister = (id: string) => {
        const now = new Date();
        const updated = prescriptions.map(p => {
            if (p.id === id) {
                let next = new Date(now);
                if (p.frequency.includes('8h')) next.setHours(next.getHours() + 8);
                else if (p.frequency.includes('12h')) next.setHours(next.getHours() + 12);
                else if (p.frequency.includes('24h')) next.setHours(next.getHours() + 24);
                return { ...p, lastAdmin: now.toISOString(), nextAdmin: p.type === 'SCHEDULED' ? next.toISOString() : undefined };
            }
            return p;
        });
        onUpdate(updated);
    };

    const handleCheckInteractions = async () => {
        const drugNames = prescriptions.map(p => p.drugName);
        if (drugNames.length < 2) return;
        setIsChecking(true);
        try {
            const alerts = await checkDrugInteractions(drugNames);
            setInteractionAlerts(alerts);
        } catch(e) { console.error(e); }
        finally { setIsChecking(false); }
    };

    return (
        <div className="h-full flex flex-col gap-6">
            <div className="flex gap-4">
                <button onClick={() => setShowAddModal(true)} className="flex-1 bg-indigo-600 text-white py-3 rounded-2xl text-xs font-black shadow-lg hover:bg-indigo-700 active:scale-95 transition-all flex items-center justify-center gap-2">
                    <Plus className="w-5 h-5"/> AÑADIR ORDEN
                </button>
