                                const isMe = msg.role === 'NURSE';
                                let data: any = null;
                                if (!isMe) { try { data = msg.text?.startsWith('{') ? JSON.parse(msg.text) : null; } catch(e) { data = null; } }
                                // Fix: Explicitly cast text to any/string to avoid unknown property access errors during compilation
                                const text: any = data ? data.answer : msg.text;
                                return (
                                    <div key={i} className={`flex ${isMe ? 'justify-end' : 'justify-start'} animate-fade-in-up`}>
                                        <div className={`max-w-[90%] p-5 rounded-[2rem] text-sm shadow-xl relative border ${isMe ? 'bg-indigo-600 text-white rounded-br-none border-indigo-500' : 'bg-white border-slate-200 text-slate-800 rounded-bl-none shadow-slate-200/50'}`}>
                                            {!isMe && data && (
                                                <div className="flex items-center justify-between mb-3 pb-2 border-b border-slate-100">
                                                    <span className="text-[10px] font-black text-violet-600 flex items-center gap-2 uppercase tracking-widest"><ShieldCheck className="w-4 h-4"/> JUICIO CLÍNICO</span>
                                                    <span className={`text-[8px] font-black px-2 py-0.5 rounded border ${data.confidence === 'HIGH' ? 'bg-emerald-50 text-emerald-700' : 'bg-amber-50 text-amber-700'}`}>FIABILIDAD: {data.confidence}</span>
                                                </div>
                                            )}
                                            <div className="whitespace-pre-wrap leading-relaxed font-medium">
                                                {/* Fix: Added explicit cast for split-map sequence to handle potential undefined text */}
                                                {((text as string | undefined)?.split(/(\*\*.*?\*\*)/g) || []).map((part: string, i: number) => part.startsWith('**') && part.endsWith('**') ? <strong key={i} className={isMe ? "text-white" : "text-slate-900 font-black"}>{part.slice(2, -2)}</strong> : part)}
                                            </div>
                                            {!isMe && data?.sources && (
                                                <div className="mt-4 pt-3 border-t border-slate-100 space-y-2">
                                                    {data.sources.map((src: any, idx: number) => (
                                                        <a key={idx} href={src.uri} target="_blank" rel="noreferrer" className="flex items-center gap-3 bg-slate-50 hover:bg-indigo-50 border border-slate-200 p-2.5 rounded-xl transition-all group/link">
                                                            <div className="bg-white p-1.5 rounded border border-slate-100 group-hover/link:text-indigo-600 shadow-inner"><Globe className="w-3.5 h-3.5"/></div>
                                                            <div className="flex-1 min-w-0">
                                                                <div className="text-[10px] font-black text-slate-700 truncate">{src.title}</div>
                                                                <div className="text-[9px] text-slate-400 font-mono flex items-center">{new URL(src.uri).hostname} <ExternalLink className="w-2.5 h-2.5 ml-1 opacity-50"/></div>
                                                            </div>
                                                        </a>
                                                    ))}
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                );
                            })}
                            {isFlorenceTyping && (
                                <div className="flex justify-start"><div className="bg-white p-4 rounded-3xl rounded-tl-none shadow-xl border border-slate-100 flex gap-2"><span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></span><span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.15s]"></span><span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.3s]"></span></div></div>
                            )}
                        </div>
                        <div className="p-6 bg-white border-t border-slate-200 shadow-2xl"><form onSubmit={(e) => { e.preventDefault(); handleFlorenceSend(); }} className="flex items-center gap-3"><div className="flex-1 bg-slate-100 rounded-[2rem] p-1.5 flex items-center border-2 border-transparent focus-within:border-indigo-500/20 focus-within:bg-white transition-all shadow-inner"><button type="button" className="p-2.5 text-slate-400 hover:text-indigo-600 transition-colors"><Mic className="w-5 h-5"/></button><input className="flex-1 bg-transparent border-none focus:ring-0 outline-none text-sm font-bold text-slate-700 px-2" placeholder="Consulte guías, dosis o compatibilidad..." value={florenceInput} onChange={e => setFlorenceInput(e.target.value)}/></div><button type="submit" disabled={!florenceInput.trim() || isFlorenceTyping} className="p-4 bg-slate-900 text-white rounded-full shadow-2xl hover:bg-black transition-all active:scale-95 disabled:opacity-50"><Send className="w-6 h-6"/></button></form></div>
                    </div>
                </div>
            )}

            {showAdmissionModal && <AdmissionModal onClose={() => setShowAdmissionModal(false)} onSave={async (p) => { await PatientService.admitPatient(p); await loadData(); setShowAdmissionModal(false); }} />}
            {showCamera && <CameraCapture mode="PHOTO" onCapture={url => alert("Imagen capturada: " + url)} onClose={() => setShowCamera(false)} />}
        </div>
    );
};

