export const Pathologies: React.FC<PathologiesProps> = ({ initialQuery, initialCategory, onNavigate }) => {
  const [query, setQuery] = useState(initialQuery || '');
  const [filterQuery, setFilterQuery] = useState(initialQuery || '');
  const [selectedCategory, setSelectedCategory] = useState<string>(initialCategory || 'ALL');
  const [selectedPathology, setSelectedPathology] = useState<Pathology | null>(null);
  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState<'CLINICAL' | 'PHARMA' | 'PAE'>('CLINICAL');
  const [viewMode, setViewMode] = useState<'AZ' | 'GROUP'>('GROUP');
  const [customLibrary, setCustomLibrary] = useState<Pathology[]>([]);

  useEffect(() => {
      const timer = setTimeout(() => setFilterQuery(query), 300);
      return () => clearTimeout(timer);
  }, [query]);

  const organizedList = useMemo(() => {
      const q = (filterQuery || '').toLowerCase().trim();
      let activeItems = [...FLATTENED_STATIC_CATALOG];

      let filtered = activeItems;
      if (q) {
          filtered = activeItems.reduce((acc: any[], item) => {
              let score = 0;
              const n = (item.name || '').toLowerCase();
              if (n === q) score = 100;
              else if (n.startsWith(q)) score = 80;
              else if (n.includes(q)) score = 50;
              if (score > 0) acc.push({ ...item, score });
              return acc;
          }, []).sort((a: any, b: any) => b.score - a.score);
      } else if (selectedCategory !== 'ALL') {
          filtered = activeItems.filter(i => i.category === selectedCategory);
      }

      const grouped: Record<string, any[]> = {};
      if (viewMode === 'AZ') {
          filtered.sort((a,b) => (a.name || '').localeCompare(b.name || '')).forEach(item => {
              const letter = (item.name || '#').charAt(0).toUpperCase();
              if(!grouped[letter]) grouped[letter] = [];
              grouped[letter].push(item);
          });
      } else {
          filtered.forEach(item => {
              if(!grouped[item.category]) grouped[item.category] = [];
              grouped[item.category].push(item);
          });
      }
      return grouped;
  }, [filterQuery, selectedCategory, viewMode]);

  const sortedKeys = Object.keys(organizedList).sort();

  const handleAIRequest = async (term: string) => {
      setLoading(true);
