    const [activeGroup, setActiveGroup] = useState('ALL');

    useEffect(() => {
        if (initialQuery) {
            setQuery(initialQuery);
            handleSelectDrug({ name: initialQuery });
        }
    }, [initialQuery]);

    const organizedList = useMemo(() => {
        const q = (query || '').toLowerCase().trim();
        let allItems: any[] = [];
        RAW_DRUG_CATALOG.forEach(cat => {
            cat.items.forEach(item => {
                allItems.push({ name: item, group: cat.category, isStatic: false });
            });
        });
        STATIC_DRUGS.forEach(d => {
            if (!allItems.some(i => i.name === d.name)) {
                allItems.push({ name: d.name, group: d.group, isStatic: true, drug: d });
            }
        });

        let filtered = allItems.filter(item => {
            const matchesSearch = !q || (item.name || '').toLowerCase().includes(q);
            const matchesGroup = activeGroup === 'ALL' || (item.group || '').toLowerCase().includes(activeGroup.toLowerCase());
            return matchesSearch && matchesGroup;
        }).sort((a,b) => (a.name || '').localeCompare(b.name || ''));

        const groups: Record<string, any[]> = {};
        filtered.forEach(item => {
            const letter = (item.name || '#').charAt(0).toUpperCase();
            if(!groups[letter]) groups[letter] = [];
            groups[letter].push(item);
        });
        return groups;
    }, [query, activeGroup]);

    const handleSelectDrug = async (item: any) => {
