                        />
                    </div>
                </div>
                <div className="flex-1 overflow-y-auto custom-scrollbar bg-slate-50">
                    {Object.keys(organizedList).sort().length > 0 ? Object.keys(organizedList).sort().map(key => (
                        <div key={key}>
