import React, { useState, useEffect, useMemo } from 'react';
import { Drug } from '../types';
import { generateDrugDetails } from '../services/geminiService';
import { 
    Search, Pill, Syringe, AlertTriangle, Clock, Droplets, Activity, 
    ShieldAlert, ArrowLeft, Calculator, X, Star, Eye, CheckCircle, 
    AlertOctagon, BookOpen, FlaskConical, ThermometerSnowflake, Zap, 
    Ban, Sun, Baby, FileText, Info, Filter, ChevronRight, Stethoscope, 
    Hash, Anchor, Beaker, Skull, Brain, HeartPulse, Tablet, Wind, 
    List, Layers, Timer, Biohazard, Plus, Wand2, Save, Loader2, 
    SlidersHorizontal, Check, UserPlus, Cloud, Package, Trash2, 
    Sparkles, CheckCircle2, ShieldCheck, Microscope, Monitor, FileCheck
} from 'lucide-react';

const RAW_DRUG_CATALOG = [
    { category: "Antiinfecciosos", items: ["Aciclovir", "Amikacina", "Amoxicilina", "Azitromicina", "Ceftriaxona", "Ciprofloxacino", "Linezolid", "Meropenem", "Vancomicina"] },
    { category: "Analgesia/Sedación", items: ["Dexketoprofeno", "Diazepam", "Fentanilo", "Metamizol", "Morfina", "Paracetamol", "Propofol", "Remifentanilo", "Tramadol"] },
    { category: "Cardiovascular", items: ["Adrenalina", "Amiodarona", "Digoxina", "Dobutamina", "Dopamina", "Furosemida", "Labetalol", "Noradrenalina", "Nitroglicerina"] },
    { category: "Respiratorio", items: ["Bromuro de Ipratropio", "Budesonida", "Metilprednisolona", "Salbutamol"] },
    { category: "Digestivo", items: ["Omeprazol", "Ondansetron", "Pantoprazol", "Metoclopramida"] }
];

export const STATIC_DRUGS: Drug[] = [
    {
        id: 'd1', name: 'Adrenalina', brandNames: 'Adrenalina Braun, Epinefrina', group: 'Cardiovascular / Vasopresor',
        presentation: 'Ampollas 1mg/1ml (1:1000)', indications: ['PCR', 'Anafilaxia'], dilution: 'Bolo IV o perfusión.', administrationRoute: 'IV, IM, SC',
        administrationTime: 'Bolo rápido.', compatibility: 'SF, SG5%.', sideEffects: ['Taquicardia'], monitoring: 'ECG continuo.',
        safetyAlert: 'ALTO RIESGO.', pregnancy: 'C', pharmacokinetics: { onset: 'Inmediato', peak: '1-2 min', duration: '2-10 min' }
    }
];

export const Pharmacology: React.FC<{initialQuery?: string}> = ({ initialQuery }) => {
    const [query, setQuery] = useState(initialQuery || '');
    const [selectedDrug, setSelectedDrug] = useState<Drug | null>(null);
    const [loadingAI, setLoadingAI] = useState(false);
    const [activeSection, setActiveSection] = useState<'ADMIN' | 'PREP' | 'SAFETY'>('ADMIN');
    const [activeGroup, setActiveGroup] = useState('ALL');

    useEffect(() => {
        if (initialQuery) {
            setQuery(initialQuery);
            handleSelectDrug({ name: initialQuery });
        }
    }, [initialQuery]);

    const organizedList = useMemo(() => {
        const q = (query || '').toLowerCase().trim();
        let allItems: any[] = [];
        RAW_DRUG_CATALOG.forEach(cat => {
            cat.items.forEach(item => {
                allItems.push({ name: item, group: cat.category, isStatic: false });
            });
        });
        STATIC_DRUGS.forEach(d => {
            if (!allItems.some(i => i.name === d.name)) {
                allItems.push({ name: d.name, group: d.group, isStatic: true, drug: d });
            }
        });

        let filtered = allItems.filter(item => {
            const matchesSearch = !q || (item.name || '').toLowerCase().includes(q);
            const matchesGroup = activeGroup === 'ALL' || (item.group || '').toLowerCase().includes(activeGroup.toLowerCase());
            return matchesSearch && matchesGroup;
        }).sort((a,b) => (a.name || '').localeCompare(b.name || ''));

        const groups: Record<string, any[]> = {};
        filtered.forEach(item => {
            const letter = (item.name || '#').charAt(0).toUpperCase();
            if(!groups[letter]) groups[letter] = [];
            groups[letter].push(item);
        });
        return groups;
    }, [query, activeGroup]);

    const handleSelectDrug = async (item: any) => {
        if (item.drug) { setSelectedDrug(item.drug); return; }
        setLoadingAI(true);
        setActiveSection('ADMIN'); // Reset to first tab
        try {
            const newDrug = await generateDrugDetails(item.name);
            setSelectedDrug(newDrug);
        } catch (e) { console.error(e); }
        finally { setLoadingAI(false); }
    };

    return (
        <div className="flex flex-col lg:flex-row h-full bg-slate-100 overflow-hidden font-sans">
            {/* --- LISTA LATERAL IZQUIERDA --- */}
            <div className={`lg:w-96 bg-white border-r border-slate-200 flex flex-col shrink-0 z-20 shadow-xl ${selectedDrug || loadingAI ? 'hidden lg:flex' : 'flex w-full'}`}>
                <div className="p-5 bg-slate-900 text-white sticky top-0 shadow-lg">
