import { Search, Pill, Syringe, AlertTriangle, Clock, Droplets, Activity, ShieldAlert, ArrowLeft, Calculator, X, Star, Eye, CheckCircle, AlertOctagon, BookOpen, FlaskConical, ThermometerSnowflake, Zap, Ban, Sun, Baby, FileText, Info, Filter, ChevronRight, Stethoscope, Hash, Anchor, Beaker, Skull, Brain, HeartPulse, Tablet, Wind, List, Layers, Timer, Biohazard, Plus, Wand2, Save, Loader2, SlidersHorizontal, Check, UserPlus, Cloud, Package, Trash2, Sparkles, CheckCircle2 } from 'lucide-react';

