    { category: "Antiinfecciosos", items: ["Aciclovir", "Amikacina", "Amoxicilina", "Amoxicilina-Clavulánico", "Azitromicina", "Aztreonam", "Caspofungina", "Cefazolina", "Cefepima", "Cefotaxima", "Ceftazidima", "Ceftriaxona", "Ciprofloxacino", "Claritromicina", "Clindamicina", "Cloxacilina", "Colistina", "Daptomicina", "Doxiciclina", "Eritromicina", "Ertapenem", "Fluconazol", "Fosfomicina", "Gentamicina", "Imipenem-Cilastatina", "Levofloxacino", "Linezolid", "Meropenem", "Metronidazol", "Moxifloxacino", "Piperacilina-Tazobactam", "Rifampicina", "Sulfametoxazol-Trimetoprima", "Teicoplanina", "Tigeciclina", "Tobramicina", "Vancomicina", "Voriconazol"] },
    { category: "Analgesia/Sedación", items: ["Alfentanilo", "Buprenorfina", "Dexketoprofeno", "Dexmedetomidina", "Diazepam", "Diclofenaco", "Etomidato", "Fentanilo", "Ketamina", "Ketorolaco", "Lormetazepam", "Metadona", "Metamizol", "Midazolam", "Morfina", "Naproxeno", "Oxicodona", "Paracetamol", "Petidina", "Propofol", "Remifentanilo", "Rocuronio", "Sevoflurano", "Succinilcolina", "Tramadol", "Vecuronio"] },
    { category: "Cardiovascular", items: ["Adrenalina", "Amiodarona", "Amlodipino", "Atenolol", "Atropina", "Bisoprolol", "Captopril", "Digoxina", "Diltiazem", "Dobutamina", "Dopamina", "Enalapril", "Esmolol", "Espironolactona", "Flecainida", "Furosemida", "Hidralazina", "Isoprenalina", "Labetalol", "Lidocaína", "Losartán", "Metildopa", "Milrinona", "Nicardipino", "Nifedipino", "Nitroglicerina", "Nitroprusiato", "Noradrenalina", "Ramipril", "Sotalol", "Torasemida", "Urapidilo", "Valsartán", "Verapamilo"] },
    { category: "Hematología", items: ["Abciximab", "Acenocumarol", "Ácido Tranexámico", "Apixabán", "Bemiparina", "Clopidogrel", "Dabigatrán", "Enoxaparina", "Epoetina", "Fondaparinux", "Heparina Sódica", "Idarucizumab", "Nadroparina", "Prasugrel", "Protamina", "Rivaroxabán", "Ticagrelor", "Tinzaparina", "Warfarina"] },
    { category: "Respiratorio", items: ["Aminofilina", "Bromuro de Ipratropio", "Budesonida", "Dexametasona", "Fluticasona", "Hidrocortisona", "Metilprednisolona", "Montelukast", "Salbutamol", "Salmeterol", "Teofilina", "Tiotropio"] },
