    { category: "Endocrino/Metabólico", items: ["Glucagón", "Insulina Aspart", "Insulina Degludec", "Insulina Glargina", "Insulina Lispro", "Insulina Rápida", "Levotiroxina", "Metformina", "Somatotropina"] },
    { category: "Neurología", items: ["Ácido Valproico", "Carbamazepina", "Fenitoína", "Fenobarbital", "Gabapentina", "Levetiracetam", "Pregabalina"] }
];

export const STATIC_DRUGS: Drug[] = [
    {
        id: 'd1', name: 'Adrenalina', brandNames: 'Adrenalina Braun, Epinefrina', group: 'Cardiovascular / Vasopresor',
        presentation: 'Ampollas 1mg/1ml (1:1000)', indications: ['PCR', 'Anafilaxia', 'Shock Séptico'], dilution: 'Bolo IV directo (en PCR) o perfusión (0.05-0.5 mcg/kg/min).', administrationRoute: 'IV, IM, SC, Intratecal',
        administrationTime: 'Bolo rápido o continua.', compatibility: 'SF, SG5%. No mezclar con bicarbonato.', sideEffects: ['Taquicardia', 'Arritmias', 'Hipertensión', 'Ansiedad'], monitoring: 'ECG continuo, PA invasiva, FC.',
        safetyAlert: 'FÁRMACO DE ALTO RIESGO. Doble chequeo obligatorio.', pregnancy: 'C', pharmacokinetics: { onset: 'Inmediato (IV)', peak: '1-2 min', duration: '2-10 min' }
