        safetyAlert: 'Controlar balance hídrico estrictamente.', pregnancy: 'C', pharmacokinetics: { onset: '5 min (IV)', peak: '20-60 min', duration: '2h' }
    }
];

export const Pharmacology: React.FC<{initialQuery?: string}> = ({ initialQuery }) => {
    const [query, setQuery] = useState(initialQuery || '');
    const [selectedDrug, setSelectedDrug] = useState<Drug | null>(null);
    const [loadingAI, setLoadingAI] = useState(false);
    const [activeSection, setActiveSection] = useState<'ADMIN' | 'PREP' | 'SAFETY'>('ADMIN');
    const [customDrugs, setCustomDrugs] = useState<Drug[]>([]);
    const [showNewDrugModal, setShowNewDrugModal] = useState(false);

    // Form for new drug
    const [newDrugForm, setNewDrugForm] = useState<Partial<Drug>>({
        name: '', group: 'General', brandNames: '', presentation: '', dilution: '', administrationRoute: 'IV', monitoring: '', safetyAlert: 'N/A'
    });

    const loadCustomDrugs = async () => {
        const drugs = await DrugService.getAll();
        setCustomDrugs(drugs);
    };

    useEffect(() => { loadCustomDrugs(); }, []);

    useEffect(() => {
        if (initialQuery) {
            setQuery(initialQuery);
            handleSelectDrug({ name: initialQuery });
        }
    }, [initialQuery]);

    const organizedList = useMemo(() => {
        const q = (query || '').toLowerCase().trim();
        let allItems: any[] = [];

        // 1. Static items from catalog (only names)
        RAW_DRUG_CATALOG.forEach(cat => {
            cat.items.forEach(item => {
                allItems.push({ name: item, group: cat.category, isStatic: false, type: 'CATALOG' });
            });
        });

        // 2. Full detail static drugs
        STATIC_DRUGS.forEach(d => {
            if (!allItems.some(i => i.name.toLowerCase() === d.name.toLowerCase())) {
                allItems.push({ name: d.name, group: d.group, isStatic: true, drug: d, type: 'STATIC' });
            } else {
                // Update catalog item to static if detail exists
                const idx = allItems.findIndex(i => i.name.toLowerCase() === d.name.toLowerCase());
                allItems[idx] = { ...allItems[idx], isStatic: true, drug: d, type: 'STATIC' };
            }
        });

        // 3. Custom user drugs
        customDrugs.forEach(d => {
            allItems.push({ name: d.name, group: d.group, isStatic: true, drug: d, type: 'CUSTOM' });
        });

        let filtered = allItems.filter(item => {
            const matchesSearch = !q || item.name.toLowerCase().includes(q) || (item.drug?.brandNames || '').toLowerCase().includes(q);
            return matchesSearch;
        }).sort((a,b) => a.name.localeCompare(b.name));

        const groups: Record<string, any[]> = {};
        filtered.forEach(item => {
            const letter = item.name.charAt(0).toUpperCase();
            if(!groups[letter]) groups[letter] = [];
            groups[letter].push(item);
        });
        return groups;
    }, [query, customDrugs]);

    const handleSelectDrug = async (item: any) => {
        if (item.drug) { setSelectedDrug(item.drug); return; }
        setLoadingAI(true);
        try {
            const newDrug = await generateDrugDetails(item.name);
            setSelectedDrug(newDrug);
        } catch (e) { console.error(e); }
        finally { setLoadingAI(false); }
    };

    const handleSaveNewDrug = async () => {
        if(!newDrugForm.name) return;
        const drug: Drug = {
            ...newDrugForm as Drug,
            id: `drug-${Date.now()}`,
            indications: (newDrugForm.indications as any || '').split(','),
            sideEffects: (newDrugForm.sideEffects as any || '').split(','),
        };
        await DrugService.add(drug);
        await loadCustomDrugs();
        setShowNewDrugModal(false);
        setNewDrugForm({ name: '', group: 'General', brandNames: '', presentation: '', dilution: '', administrationRoute: 'IV', monitoring: '', safetyAlert: 'N/A' });
    };

    const handleDeleteDrug = async (id: string) => {
        if(confirm("¿Eliminar fármaco del vademécum personal?")) {
            await DrugService.delete(id);
            await loadCustomDrugs();
            setSelectedDrug(null);
        }
    };

    return (
        <div className="flex flex-col lg:flex-row h-full bg-slate-100 overflow-hidden font-sans">

            {/* --- LISTA LATERAL (Buscador) --- */}
            <div className={`lg:w-96 bg-white border-r border-slate-200 flex flex-col shrink-0 z-20 shadow-xl ${selectedDrug || loadingAI ? 'hidden lg:flex' : 'flex w-full'}`}>
                <div className="p-4 bg-slate-900 text-white sticky top-0 shadow-lg">
                    <div className="flex justify-between items-center mb-4">
                        <h2 className="font-black text-xs uppercase tracking-widest text-emerald-400 flex items-center"><Pill className="w-4 h-4 mr-2"/> Vademécum v22</h2>
                        <button onClick={() => setShowNewDrugModal(true)} className="p-1.5 bg-emerald-600 rounded-lg hover:bg-emerald-700 transition-colors"><Plus className="w-4 h-4 text-white"/></button>
                    </div>
                    <div className="relative group mb-3">
                        <Search className="absolute left-3 top-2.5 text-slate-500 w-4 h-4"/>
                        <input value={query} onChange={e => setQuery(e.target.value)} placeholder="Buscar principio activo..." className="w-full pl-9 p-2.5 rounded-lg bg-slate-800 border border-slate-700 text-sm text-white outline-none focus:ring-2 focus:ring-emerald-500 font-medium"/>
                    </div>
                    <div className="flex items-center gap-2 text-[9px] font-bold text-slate-500 uppercase tracking-widest px-1">
                        <span className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-emerald-500"></div> Local</span>
                        <span className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-indigo-500"></div> IA Cloud</span>
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar bg-white">
                    {Object.keys(organizedList).sort().map(key => (
                        <div key={key}>
                            <div className="sticky top-0 bg-slate-100/95 backdrop-blur z-20 text-slate-500 text-[10px] font-black px-4 py-1.5 border-b border-slate-200 uppercase tracking-widest flex justify-between items-center">
                                {key}
                                <span className="opacity-50">{organizedList[key].length}</span>
                            </div>
                            {organizedList[key].map((item, idx) => (
                                <button key={idx} onClick={() => handleSelectDrug(item)} className={`w-full text-left p-4 hover:bg-slate-50 transition-all border-b border-slate-100 group relative ${selectedDrug?.name === item.name ? 'bg-indigo-50 border-l-4 border-l-indigo-600 shadow-sm' : ''}`}>
                                    <div className="flex justify-between items-start">
                                        <div className="min-w-0 flex-1">
                                            <div className="font-black text-base text-slate-800 truncate">{item.name}</div>
                                            <div className="text-[10px] text-slate-500 font-bold uppercase mt-1 truncate">{item.group}</div>
                                        </div>
                                        <div className={`w-2 h-2 rounded-full mt-2 ${item.isStatic ? 'bg-emerald-400 shadow-[0_0_8px_rgba(52,211,153,0.5)]' : 'bg-indigo-400'}`}></div>
                                    </div>
                                </button>
                            ))}
                        </div>
                    ))}
                </div>
            </div>

            {/* --- DETALLE DEL FÁRMACO --- */}
            <div className={`flex-1 flex flex-col bg-slate-50 h-full relative ${!selectedDrug && !loadingAI ? 'hidden lg:flex' : 'flex'}`}>
                {loadingAI ? (
                    <div className="flex-1 flex flex-col items-center justify-center p-8 bg-slate-50">
                        <div className="relative">
                            <Loader2 className="w-16 h-16 text-indigo-500 animate-spin mb-4"/>
                            <Sparkles className="w-6 h-6 text-indigo-400 absolute top-5 left-5 animate-pulse"/>
                        </div>
                        <h3 className="font-black text-slate-800 text-xl tracking-tight">Compilando Guía Clínica...</h3>
                        <p className="text-sm text-slate-500 font-medium mt-1">Consultando evidencia y protocolos actualizados</p>
                    </div>
                ) : selectedDrug ? (
                    <div className="flex flex-col h-full animate-fade-in bg-white lg:bg-slate-50">
                        {/* Header Ficha */}
                        <div className="bg-white border-b border-slate-200 p-6 sticky top-0 z-10 shadow-sm">
                            <div className="flex gap-4 items-start mb-6">
                                <button onClick={() => setSelectedDrug(null)} className="lg:hidden p-2 bg-slate-100 rounded-full text-slate-500 hover:bg-slate-200"><ArrowLeft className="w-5 h-5"/></button>
                                <div className="flex-1 min-w-0">
                                    <div className="flex items-center gap-2 mb-1">
                                        <span className="text-[9px] font-black px-2 py-0.5 rounded border border-indigo-100 bg-indigo-50 text-indigo-700 uppercase tracking-widest">{selectedDrug.group}</span>
                                        {selectedDrug.safetyAlert.includes('ALTO RIESGO') && <span className="text-[9px] font-black px-2 py-0.5 rounded bg-rose-500 text-white animate-pulse">ALTO RIESGO</span>}
                                    </div>
                                    <h1 className="text-2xl md:text-4xl font-black text-slate-900 leading-tight uppercase tracking-tighter truncate">{selectedDrug.name}</h1>
                                    <p className="text-xs font-bold text-slate-400 uppercase mt-1">{selectedDrug.brandNames || 'Nombre comercial no registrado'}</p>
                                </div>
                                <div className="flex gap-2">
                                    <button className="p-3 bg-slate-50 text-slate-400 rounded-xl border border-slate-200 hover:text-yellow-500"><Star className="w-5 h-5"/></button>
                                    {selectedDrug.id?.startsWith('drug-') && (
                                        <button onClick={() => handleDeleteDrug(selectedDrug.id)} className="p-3 bg-rose-50 text-rose-400 rounded-xl border border-rose-100 hover:text-rose-600"><Trash2 className="w-5 h-5"/></button>
                                    )}
                                </div>
                            </div>
                            <div className="flex gap-2 p-1 bg-slate-100 rounded-xl border border-slate-200 w-fit mx-auto lg:mx-0">
                                {['ADMIN', 'PREP', 'SAFETY'].map(s => (
                                    <button key={s} onClick={() => setActiveSection(s as any)} className={`px-4 py-2 rounded-lg text-xs font-black transition-all ${activeSection === s ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-500 hover:text-slate-800'}`}>
                                        {s === 'ADMIN' ? 'ADMINISTRACIÓN' : s === 'PREP' ? 'PREPARACIÓN' : 'SEGURIDAD'}
                                    </button>
                                ))}
                            </div>
                        </div>

                        {/* Contenido Scrollable */}
                        <div className="flex-1 overflow-y-auto p-6 md:p-10 custom-scrollbar bg-slate-50/50">
                            <div className="max-w-4xl mx-auto space-y-6">

                                {activeSection === 'ADMIN' && (
                                    <div className="grid md:grid-cols-2 gap-4 animate-fade-in">
                                        <div className="bg-white p-5 rounded-3xl border border-slate-200 shadow-sm flex flex-col gap-1">
                                            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Vía Preferente</h4>
                                            <p className="font-black text-slate-800 text-lg">{selectedDrug.administrationRoute}</p>
                                        </div>
                                        <div className="bg-white p-5 rounded-3xl border border-slate-200 shadow-sm flex flex-col gap-1">
                                            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Velocidad / Tiempo</h4>
                                            <p className="font-black text-slate-800 text-lg">{selectedDrug.administrationTime}</p>
                                        </div>
                                        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm col-span-full relative overflow-hidden group">
                                            <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity"><Activity className="w-24 h-24 text-indigo-900"/></div>
                                            <h4 className="text-xs font-black text-indigo-700 uppercase tracking-[0.2em] mb-3 flex items-center"><Monitor className="w-4 h-4 mr-2"/> Monitorización Enfermera</h4>
                                            <p className="text-sm font-bold text-slate-700 leading-relaxed relative z-10">{selectedDrug.monitoring}</p>
                                        </div>
                                        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm col-span-full">
                                            <h4 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-4">Indicaciones Principales</h4>
                                            <div className="flex flex-wrap gap-2">
                                                {selectedDrug.indications?.map((ind, i) => (
                                                    <span key={i} className="px-3 py-1.5 bg-slate-50 text-slate-700 text-[10px] font-black rounded-xl border border-slate-200 uppercase">{ind}</span>
                                                ))}
                                            </div>
                                        </div>
                                    </div>
                                )}

                                {activeSection === 'PREP' && (
                                    <div className="space-y-4 animate-fade-in">
                                        <div className="bg-emerald-900 text-white p-8 rounded-[2.5rem] shadow-2xl shadow-emerald-900/20 relative overflow-hidden">
                                            <div className="absolute -bottom-10 -right-10 w-48 h-48 bg-emerald-800 rounded-full opacity-50 blur-3xl"></div>
                                            <div className="relative z-10">
                                                <h4 className="text-xs font-black text-emerald-400 uppercase tracking-[0.3em] mb-3 flex items-center"><Droplets className="w-4 h-4 mr-2"/> Protocolo de Dilución</h4>
                                                <p className="text-lg md:text-xl font-bold leading-snug">{selectedDrug.dilution}</p>
                                            </div>
                                        </div>
                                        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                                            <h4 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-4">Presentación Hospitalaria</h4>
                                            <p className="text-base font-black text-slate-800">{selectedDrug.presentation}</p>
                                        </div>
                                        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                                            <h4 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-4">Sueros Compatibles</h4>
                                            <div className="flex flex-wrap gap-3">
                                                {selectedDrug.compatibility?.split(',').map((comp, i) => (
                                                    <div key={i} className="flex items-center gap-2 bg-slate-50 px-3 py-2 rounded-2xl border border-slate-100">
                                                        <div className="w-2 h-2 rounded-full bg-emerald-500"></div>
                                                        <span className="text-xs font-bold text-slate-600 uppercase">{comp.trim()}</span>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    </div>
                                )}

                                {activeSection === 'SAFETY' && (
                                    <div className="space-y-4 animate-fade-in">
                                        <div className="bg-rose-50 p-6 rounded-[2.5rem] border border-rose-200 border-l-[16px] border-l-rose-500 shadow-lg relative overflow-hidden">
                                            <div className="absolute top-0 right-0 p-4 opacity-10"><AlertTriangle className="w-32 h-32 text-rose-600"/></div>
                                            <div className="relative z-10">
                                                <h4 className="text-xs font-black text-rose-700 uppercase tracking-[0.3em] mb-2 flex items-center"><ShieldAlert className="w-5 h-5 mr-2 animate-pulse"/> Alerta de Seguridad</h4>
                                                <p className="text-lg font-black text-rose-900 uppercase">{selectedDrug.safetyAlert}</p>
                                            </div>
                                        </div>
                                        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                                            <h4 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-4">Efectos Adversos (RAM)</h4>
                                            <div className="grid grid-cols-2 md:grid-cols-3 gap-2">
                                                {selectedDrug.sideEffects?.map((eff, i) => (
                                                    <div key={i} className="bg-slate-50 p-3 rounded-2xl border border-slate-100 flex items-center gap-2">
                                                        <div className="w-1.5 h-1.5 rounded-full bg-rose-300"></div>
                                                        <span className="text-[10px] font-bold text-slate-600 uppercase truncate">{eff}</span>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                        <div className="grid md:grid-cols-2 gap-4">
                                            <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                                                <h4 className="text-xs font-black text-slate-400 uppercase mb-3 flex items-center"><Baby className="w-4 h-4 mr-2 text-indigo-500"/> Embarazo (FDA)</h4>
                                                <div className="flex items-center gap-4">
                                                    <div className="w-12 h-12 rounded-2xl bg-indigo-600 text-white flex items-center justify-center text-xl font-black shadow-lg">{selectedDrug.pregnancy || 'N/A'}</div>
                                                    <p className="text-[10px] font-bold text-slate-500 leading-tight uppercase">Categoría de riesgo según guías farmacológicas.</p>
                                                </div>
                                            </div>
                                            <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                                                <h4 className="text-xs font-black text-slate-400 uppercase mb-3 flex items-center"><Timer className="w-4 h-4 mr-2 text-indigo-500"/> Farmacocinética</h4>
                                                <div className="space-y-2">
                                                    <div className="flex justify-between text-[10px] font-black uppercase"><span className="text-slate-400">Inicio</span> <span className="text-slate-800">{selectedDrug.pharmacokinetics?.onset || '--'}</span></div>
                                                    <div className="flex justify-between text-[10px] font-black uppercase"><span className="text-slate-400">Duración</span> <span className="text-slate-800">{selectedDrug.pharmacokinetics?.duration || '--'}</span></div>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                )}

                            </div>
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-slate-300 p-8 select-none bg-slate-50/50">
                        <div className="relative mb-6">
                            <div className="w-32 h-32 bg-white rounded-full flex items-center justify-center shadow-xl border border-slate-100">
                                <Pill className="w-14 h-14 text-slate-200"/>
                            </div>
                            <div className="absolute -bottom-2 -right-2 bg-indigo-500 text-white p-3 rounded-2xl shadow-lg animate-bounce">
                                <Search className="w-5 h-5"/>
                            </div>
                        </div>
                        <h3 className="font-black text-2xl uppercase tracking-tighter text-slate-400">Vademécum Profesional</h3>
                        <p className="text-sm font-medium text-slate-400 mt-2 max-w-xs text-center">Seleccione un principio activo para consultar dosis, preparación y alertas de seguridad v22.</p>
                    </div>
                )}
            </div>

            {/* --- MODAL NUEVO FÁRMACO --- */}
            {showNewDrugModal && (
                <div className="fixed inset-0 z-[100] bg-slate-900/80 backdrop-blur-sm flex items-center justify-center p-4">
                    <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-hidden flex flex-col animate-fade-in-up">
                        <div className="bg-slate-900 p-6 flex justify-between items-center shrink-0">
