                                    <input value={newDrugForm.brandNames} onChange={e => setNewDrugForm({...newDrugForm, brandNames: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-sm font-bold outline-none" placeholder="Ej: Pipetazo"/>
                                </div>
