export const Pharmacology: React.FC<{initialQuery?: string}> = ({ initialQuery }) => {
    const [query, setQuery] = useState(initialQuery || '');
    const [selectedDrug, setSelectedDrug] = useState<Drug | null>(null);
    const [loadingAI, setLoadingAI] = useState(false);
    const [activeSection, setActiveSection] = useState<'ADMIN' | 'PREP' | 'SAFETY'>('ADMIN');
    const [customDrugs, setCustomDrugs] = useState<Drug[]>([]);
    const [showNewDrugModal, setShowNewDrugModal] = useState(false);

    // Form for new drug
    const [newDrugForm, setNewDrugForm] = useState<Partial<Drug>>({
        name: '', group: 'General', brandNames: '', presentation: '', dilution: '', administrationRoute: 'IV', monitoring: '', safetyAlert: 'N/A'
    });

    const loadCustomDrugs = async () => {
        const drugs = await DrugService.getAll();
        setCustomDrugs(drugs);
    };

    useEffect(() => { loadCustomDrugs(); }, []);

    useEffect(() => {
        if (initialQuery) {
            setQuery(initialQuery);
            handleSelectDrug({ name: initialQuery });
        }
    }, [initialQuery]);

    const organizedList = useMemo(() => {
        const q = (query || '').toLowerCase().trim();
        let allItems: any[] = [];

        // 1. Static items from catalog (only names)
        RAW_DRUG_CATALOG.forEach(cat => {
            cat.items.forEach(item => {
                allItems.push({ name: item, group: cat.category, isStatic: false, type: 'CATALOG' });
            });
        });

        // 2. Full detail static drugs
        STATIC_DRUGS.forEach(d => {
            if (!allItems.some(i => i.name.toLowerCase() === d.name.toLowerCase())) {
                allItems.push({ name: d.name, group: d.group, isStatic: true, drug: d, type: 'STATIC' });
            } else {
                // Update catalog item to static if detail exists
                const idx = allItems.findIndex(i => i.name.toLowerCase() === d.name.toLowerCase());
                allItems[idx] = { ...allItems[idx], isStatic: true, drug: d, type: 'STATIC' };
            }
        });

        // 3. Custom user drugs
        customDrugs.forEach(d => {
            allItems.push({ name: d.name, group: d.group, isStatic: true, drug: d, type: 'CUSTOM' });
        });

        let filtered = allItems.filter(item => {
            const matchesSearch = !q || item.name.toLowerCase().includes(q) || (item.drug?.brandNames || '').toLowerCase().includes(q);
            return matchesSearch;
        }).sort((a,b) => a.name.localeCompare(b.name));

        const groups: Record<string, any[]> = {};
        filtered.forEach(item => {
            const letter = item.name.charAt(0).toUpperCase();
            if(!groups[letter]) groups[letter] = [];
            groups[letter].push(item);
        });
        return groups;
    }, [query, customDrugs]);

    const handleSelectDrug = async (item: any) => {
        if (item.drug) { setSelectedDrug(item.drug); return; }
        setLoadingAI(true);
        try {
            const newDrug = await generateDrugDetails(item.name);
            setSelectedDrug(newDrug);
        } catch (e) { console.error(e); }
        finally { setLoadingAI(false); }
    };

    const handleSaveNewDrug = async () => {
        if(!newDrugForm.name) return;
        const drug: Drug = {
            ...newDrugForm as Drug,
            id: `drug-${Date.now()}`,
            indications: (newDrugForm.indications as any || '').split(','),
            sideEffects: (newDrugForm.sideEffects as any || '').split(','),
        };
        await DrugService.add(drug);
        await loadCustomDrugs();
        setShowNewDrugModal(false);
        setNewDrugForm({ name: '', group: 'General', brandNames: '', presentation: '', dilution: '', administrationRoute: 'IV', monitoring: '', safetyAlert: 'N/A' });
    };

    const handleDeleteDrug = async (id: string) => {
        if(confirm("¿Eliminar fármaco del vademécum personal?")) {
            await DrugService.delete(id);
            await loadCustomDrugs();
            setSelectedDrug(null);
        }
    };

    return (
        <div className="flex flex-col lg:flex-row h-full bg-slate-100 overflow-hidden font-sans">

            {/* --- LISTA LATERAL (Buscador) --- */}
            <div className={`lg:w-96 bg-white border-r border-slate-200 flex flex-col shrink-0 z-20 shadow-xl ${selectedDrug || loadingAI ? 'hidden lg:flex' : 'flex w-full'}`}>
                <div className="p-4 bg-slate-900 text-white sticky top-0 shadow-lg">
                    <div className="flex justify-between items-center mb-4">
                        <h2 className="font-black text-xs uppercase tracking-widest text-emerald-400 flex items-center"><Pill className="w-4 h-4 mr-2"/> Vademécum v22</h2>
                        <button onClick={() => setShowNewDrugModal(true)} className="p-1.5 bg-emerald-600 rounded-lg hover:bg-emerald-700 transition-colors"><Plus className="w-4 h-4 text-white"/></button>
                    </div>
                    <div className="relative group mb-3">
                        <Search className="absolute left-3 top-2.5 text-slate-500 w-4 h-4"/>
                        <input value={query} onChange={e => setQuery(e.target.value)} placeholder="Buscar principio activo..." className="w-full pl-9 p-2.5 rounded-lg bg-slate-800 border border-slate-700 text-sm text-white outline-none focus:ring-2 focus:ring-emerald-500 font-medium"/>
                    </div>
                    <div className="flex items-center gap-2 text-[9px] font-bold text-slate-500 uppercase tracking-widest px-1">
                        <span className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-emerald-500"></div> Local</span>
                        <span className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-indigo-500"></div> IA Cloud</span>
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar bg-white">
                    {Object.keys(organizedList).sort().map(key => (
                        <div key={key}>
                            <div className="sticky top-0 bg-slate-100/95 backdrop-blur z-20 text-slate-500 text-[10px] font-black px-4 py-1.5 border-b border-slate-200 uppercase tracking-widest flex justify-between items-center">
                                {key}
                                <span className="opacity-50">{organizedList[key].length}</span>
                            </div>
                            {organizedList[key].map((item, idx) => (
                                <button key={idx} onClick={() => handleSelectDrug(item)} className={`w-full text-left p-4 hover:bg-slate-50 transition-all border-b border-slate-100 group relative ${selectedDrug?.name === item.name ? 'bg-indigo-50 border-l-4 border-l-indigo-600 shadow-sm' : ''}`}>
                                    <div className="flex justify-between items-start">
                                        <div className="min-w-0 flex-1">
                                            <div className="font-black text-base text-slate-800 truncate">{item.name}</div>
                                            <div className="text-[10px] text-slate-500 font-bold uppercase mt-1 truncate">{item.group}</div>
                                        </div>
                                        <div className={`w-2 h-2 rounded-full mt-2 ${item.isStatic ? 'bg-emerald-400 shadow-[0_0_8px_rgba(52,211,153,0.5)]' : 'bg-indigo-400'}`}></div>
                                    </div>
                                </button>
                            ))}
                        </div>
                    ))}
                </div>
            </div>

            {/* --- DETALLE DEL FÁRMACO --- */}
            <div className={`flex-1 flex flex-col bg-slate-50 h-full relative ${!selectedDrug && !loadingAI ? 'hidden lg:flex' : 'flex'}`}>
                {loadingAI ? (
                    <div className="flex-1 flex flex-col items-center justify-center p-8 bg-slate-50">
                        <div className="relative">
                            <Loader2 className="w-16 h-16 text-indigo-500 animate-spin mb-4"/>
                            <Sparkles className="w-6 h-6 text-indigo-400 absolute top-5 left-5 animate-pulse"/>
                        </div>
                        <h3 className="font-black text-slate-800 text-xl tracking-tight">Compilando Guía Clínica...</h3>
                        <p className="text-sm text-slate-500 font-medium mt-1">Consultando evidencia y protocolos actualizados</p>
                    </div>
                ) : selectedDrug ? (
                    <div className="flex flex-col h-full animate-fade-in bg-white lg:bg-slate-50">
                        {/* Header Ficha */}
                        <div className="bg-white border-b border-slate-200 p-6 sticky top-0 z-10 shadow-sm">
                            <div className="flex gap-4 items-start mb-6">
                                <button onClick={() => setSelectedDrug(null)} className="lg:hidden p-2 bg-slate-100 rounded-full text-slate-500 hover:bg-slate-200"><ArrowLeft className="w-5 h-5"/></button>
                                <div className="flex-1 min-w-0">
                                    <div className="flex items-center gap-2 mb-1">
                                        <span className="text-[9px] font-black px-2 py-0.5 rounded border border-indigo-100 bg-indigo-50 text-indigo-700 uppercase tracking-widest">{selectedDrug.group}</span>
                                        {selectedDrug.safetyAlert.includes('ALTO RIESGO') && <span className="text-[9px] font-black px-2 py-0.5 rounded bg-rose-500 text-white animate-pulse">ALTO RIESGO</span>}
                                    </div>
                                    <h1 className="text-2xl md:text-4xl font-black text-slate-900 leading-tight uppercase tracking-tighter truncate">{selectedDrug.name}</h1>
                                    <p className="text-xs font-bold text-slate-400 uppercase mt-1">{selectedDrug.brandNames || 'Nombre comercial no registrado'}</p>
                                </div>
                                <div className="flex gap-2">
                                    <button className="p-3 bg-slate-50 text-slate-400 rounded-xl border border-slate-200 hover:text-yellow-500"><Star className="w-5 h-5"/></button>
                                    {selectedDrug.id?.startsWith('drug-') && (
                                        <button onClick={() => handleDeleteDrug(selectedDrug.id)} className="p-3 bg-rose-50 text-rose-400 rounded-xl border border-rose-100 hover:text-rose-600"><Trash2 className="w-5 h-5"/></button>
                                    )}
                                </div>
                            </div>
                            <div className="flex gap-2 p-1 bg-slate-100 rounded-xl border border-slate-200 w-fit mx-auto lg:mx-0">
                                {['ADMIN', 'PREP', 'SAFETY'].map(s => (
                                    <button key={s} onClick={() => setActiveSection(s as any)} className={`px-4 py-2 rounded-lg text-xs font-black transition-all ${activeSection === s ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-500 hover:text-slate-800'}`}>
                                        {s === 'ADMIN' ? 'ADMINISTRACIÓN' : s === 'PREP' ? 'PREPARACIÓN' : 'SEGURIDAD'}
                                    </button>
                                ))}
                            </div>
                        </div>

                        {/* Contenido Scrollable */}
                        <div className="flex-1 overflow-y-auto p-6 md:p-10 custom-scrollbar bg-slate-50/50">
                            <div className="max-w-4xl mx-auto space-y-6">

                                {activeSection === 'ADMIN' && (
                                    <div className="grid md:grid-cols-2 gap-4 animate-fade-in">
                                        <div className="bg-white p-5 rounded-3xl border border-slate-200 shadow-sm flex flex-col gap-1">
                                            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Vía Preferente</h4>
                                            <p className="font-black text-slate-800 text-lg">{selectedDrug.administrationRoute}</p>
                                        </div>
                                        <div className="bg-white p-5 rounded-3xl border border-slate-200 shadow-sm flex flex-col gap-1">
                                            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Velocidad / Tiempo</h4>
                                            <p className="font-black text-slate-800 text-lg">{selectedDrug.administrationTime}</p>
                                        </div>
                                        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm col-span-full relative overflow-hidden group">
                                            <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity"><Activity className="w-24 h-24 text-indigo-900"/></div>
                                            <h4 className="text-xs font-black text-indigo-700 uppercase tracking-[0.2em] mb-3 flex items-center"><Monitor className="w-4 h-4 mr-2"/> Monitorización Enfermera</h4>
                                            <p className="text-sm font-bold text-slate-700 leading-relaxed relative z-10">{selectedDrug.monitoring}</p>
                                        </div>
                                        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm col-span-full">
                                            <h4 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-4">Indicaciones Principales</h4>
                                            <div className="flex flex-wrap gap-2">
                                                {selectedDrug.indications?.map((ind, i) => (
                                                    <span key={i} className="px-3 py-1.5 bg-slate-50 text-slate-700 text-[10px] font-black rounded-xl border border-slate-200 uppercase">{ind}</span>
                                                ))}
                                            </div>
                                        </div>
                                    </div>
                                )}

                                {activeSection === 'PREP' && (
                                    <div className="space-y-4 animate-fade-in">
                                        <div className="bg-emerald-900 text-white p-8 rounded-[2.5rem] shadow-2xl shadow-emerald-900/20 relative overflow-hidden">
                                            <div className="absolute -bottom-10 -right-10 w-48 h-48 bg-emerald-800 rounded-full opacity-50 blur-3xl"></div>
                                            <div className="relative z-10">
                                                <h4 className="text-xs font-black text-emerald-400 uppercase tracking-[0.3em] mb-3 flex items-center"><Droplets className="w-4 h-4 mr-2"/> Protocolo de Dilución</h4>
                                                <p className="text-lg md:text-xl font-bold leading-snug">{selectedDrug.dilution}</p>
                                            </div>
                                        </div>
                                        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                                            <h4 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-4">Presentación Hospitalaria</h4>
                                            <p className="text-base font-black text-slate-800">{selectedDrug.presentation}</p>
                                        </div>
                                        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                                            <h4 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-4">Sueros Compatibles</h4>
                                            <div className="flex flex-wrap gap-3">
                                                {selectedDrug.compatibility?.split(',').map((comp, i) => (
                                                    <div key={i} className="flex items-center gap-2 bg-slate-50 px-3 py-2 rounded-2xl border border-slate-100">
                                                        <div className="w-2 h-2 rounded-full bg-emerald-500"></div>
                                                        <span className="text-xs font-bold text-slate-600 uppercase">{comp.trim()}</span>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    </div>
                                )}

                                {activeSection === 'SAFETY' && (
                                    <div className="space-y-4 animate-fade-in">
                                        <div className="bg-rose-50 p-6 rounded-[2.5rem] border border-rose-200 border-l-[16px] border-l-rose-500 shadow-lg relative overflow-hidden">
                                            <div className="absolute top-0 right-0 p-4 opacity-10"><AlertTriangle className="w-32 h-32 text-rose-600"/></div>
                                            <div className="relative z-10">
                                                <h4 className="text-xs font-black text-rose-700 uppercase tracking-[0.3em] mb-2 flex items-center"><ShieldAlert className="w-5 h-5 mr-2 animate-pulse"/> Alerta de Seguridad</h4>
                                                <p className="text-lg font-black text-rose-900 uppercase">{selectedDrug.safetyAlert}</p>
                                            </div>
                                        </div>
                                        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                                            <h4 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-4">Efectos Adversos (RAM)</h4>
                                            <div className="grid grid-cols-2 md:grid-cols-3 gap-2">
                                                {selectedDrug.sideEffects?.map((eff, i) => (
                                                    <div key={i} className="bg-slate-50 p-3 rounded-2xl border border-slate-100 flex items-center gap-2">
                                                        <div className="w-1.5 h-1.5 rounded-full bg-rose-300"></div>
                                                        <span className="text-[10px] font-bold text-slate-600 uppercase truncate">{eff}</span>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                        <div className="grid md:grid-cols-2 gap-4">
                                            <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                                                <h4 className="text-xs font-black text-slate-400 uppercase mb-3 flex items-center"><Baby className="w-4 h-4 mr-2 text-indigo-500"/> Embarazo (FDA)</h4>
                                                <div className="flex items-center gap-4">
                                                    <div className="w-12 h-12 rounded-2xl bg-indigo-600 text-white flex items-center justify-center text-xl font-black shadow-lg">{selectedDrug.pregnancy || 'N/A'}</div>
                                                    <p className="text-[10px] font-bold text-slate-500 leading-tight uppercase">Categoría de riesgo según guías farmacológicas.</p>
                                                </div>
                                            </div>
                                            <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                                                <h4 className="text-xs font-black text-slate-400 uppercase mb-3 flex items-center"><Timer className="w-4 h-4 mr-2 text-indigo-500"/> Farmacocinética</h4>
                                                <div className="space-y-2">
                                                    <div className="flex justify-between text-[10px] font-black uppercase"><span className="text-slate-400">Inicio</span> <span className="text-slate-800">{selectedDrug.pharmacokinetics?.onset || '--'}</span></div>
                                                    <div className="flex justify-between text-[10px] font-black uppercase"><span className="text-slate-400">Duración</span> <span className="text-slate-800">{selectedDrug.pharmacokinetics?.duration || '--'}</span></div>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                )}

                            </div>
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-slate-300 p-8 select-none bg-slate-50/50">
                        <div className="relative mb-6">
                            <div className="w-32 h-32 bg-white rounded-full flex items-center justify-center shadow-xl border border-slate-100">
                                <Pill className="w-14 h-14 text-slate-200"/>
                            </div>
                            <div className="absolute -bottom-2 -right-2 bg-indigo-500 text-white p-3 rounded-2xl shadow-lg animate-bounce">
                                <Search className="w-5 h-5"/>
                            </div>
                        </div>
                        <h3 className="font-black text-2xl uppercase tracking-tighter text-slate-400">Vademécum Profesional</h3>
                        <p className="text-sm font-medium text-slate-400 mt-2 max-w-xs text-center">Seleccione un principio activo para consultar dosis, preparación y alertas de seguridad v22.</p>
                    </div>
                )}
            </div>

            {/* --- MODAL NUEVO FÁRMACO --- */}
            {showNewDrugModal && (
                <div className="fixed inset-0 z-[100] bg-slate-900/80 backdrop-blur-sm flex items-center justify-center p-4">
                    <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-hidden flex flex-col animate-fade-in-up">
                        <div className="bg-slate-900 p-6 flex justify-between items-center shrink-0">
                            <div className="flex items-center gap-3">
                                <div className="bg-emerald-500 p-2 rounded-xl text-white shadow-lg"><Plus className="w-6 h-6"/></div>
                                <div>
                                    <h3 className="text-xl font-black text-white tracking-tight">Nuevo Fármaco Personalizado</h3>
                                    <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">Añadir al vademécum local</p>
                                </div>
                            </div>
                            <button onClick={() => setShowNewDrugModal(false)} className="text-slate-400 hover:text-white bg-slate-800 p-2 rounded-full"><X className="w-5 h-5"/></button>
                        </div>
                        <div className="flex-1 overflow-y-auto p-6 md:p-8 space-y-6 custom-scrollbar">
                            <div className="grid md:grid-cols-2 gap-4">
                                <div className="col-span-full">
                                    <label className="text-[10px] font-black text-slate-500 uppercase block mb-1">Nombre del Principio Activo</label>
                                    <input value={newDrugForm.name} onChange={e => setNewDrugForm({...newDrugForm, name: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-sm font-bold outline-none focus:ring-2 focus:ring-indigo-500" placeholder="Ej: Piperacilina-Tazobactam"/>
                                </div>
                                <div>
                                    <label className="text-[10px] font-black text-slate-500 uppercase block mb-1">Familia / Grupo</label>
                                    <input value={newDrugForm.group} onChange={e => setNewDrugForm({...newDrugForm, group: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-sm font-bold outline-none" placeholder="Ej: Antibiótico"/>
                                </div>
                                <div>
                                    <label className="text-[10px] font-black text-slate-500 uppercase block mb-1">Nombre Comercial</label>
                                    <input value={newDrugForm.brandNames} onChange={e => setNewDrugForm({...newDrugForm, brandNames: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-sm font-bold outline-none" placeholder="Ej: Pipetazo"/>
                                </div>
                                <div className="col-span-full">
                                    <label className="text-[10px] font-black text-slate-500 uppercase block mb-1">Protocolo de Dilución</label>
                                    <textarea value={newDrugForm.dilution} onChange={e => setNewDrugForm({...newDrugForm, dilution: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-sm font-medium h-24 outline-none" placeholder="Especificar SF, SG5%, tiempos..."/>
                                </div>
                                <div>
                                    <label className="text-[10px] font-black text-slate-500 uppercase block mb-1">Vía de Admin.</label>
                                    <select value={newDrugForm.administrationRoute} onChange={e => setNewDrugForm({...newDrugForm, administrationRoute: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-sm font-bold outline-none">
                                        <option value="IV">IV (Intravenosa)</option>
                                        <option value="IM">IM (Intramuscular)</option>
                                        <option value="VO">VO (Vía Oral)</option>
                                        <option value="SC">SC (Subcutánea)</option>
                                        <option value="NEB">Nebulizado</option>
                                    </select>
                                </div>
                                <div>
                                    <label className="text-[10px] font-black text-rose-500 uppercase block mb-1">Alerta de Seguridad</label>
                                    <input value={newDrugForm.safetyAlert} onChange={e => setNewDrugForm({...newDrugForm, safetyAlert: e.target.value})} className="w-full bg-rose-50 border border-rose-200 rounded-xl p-3 text-sm font-bold text-rose-700 outline-none" placeholder="Ej: ALTO RIESGO"/>
                                </div>
                            </div>
                        </div>
                        <div className="p-6 bg-slate-50 border-t border-slate-200 shrink-0">
                            <button onClick={handleSaveNewDrug} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase tracking-widest shadow-xl active:scale-95 transition-all">Guardar en Vademécum</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Patient, Evolution, ClinicalAnalysis, ChatMessage } from '../types';
import { analyzeClinicalNote, generateChatReply, FlorenceResponse } from '../services/geminiService';
import { PatientService } from '../services/firebaseMock';
import { ClipboardList, Search, User, AlertCircle, Monitor, Pill, BookOpen, FlaskConical, Cable, Megaphone, Ruler, PenTool, Activity, ShieldAlert, ArrowLeft, Bot, Send, X, Globe, Sparkles, Loader2, ChevronRight, Camera, Mic, Volume2, ShieldCheck, ExternalLink, Calendar, Clock, AlertTriangle, UserPlus, CheckCircle2 } from 'lucide-react';
import { VoiceInput } from './VoiceInput';
import { CameraCapture } from './CameraCapture';
import { WoundAnalysis } from './WoundAnalysis';
import { MedicationSheet } from './MedicationSheet';
import { VitalSigns } from './VitalSigns';
import { AccessManager } from './AccessManager';
import { LabResults } from './LabResults';
import { CarePlanManager } from './CarePlanManager';
import { ShiftHandoff } from './ShiftHandoff';
import { AdmissionModal } from './AdmissionModal';

const CLINICAL_MODULES = [
    { id: 'NOTES', label: 'Evolución', icon: PenTool, color: 'text-indigo-600' },
    { id: 'MONITOR', label: 'Monitor', icon: Monitor, color: 'text-emerald-600' },
    { id: 'MEDS', label: 'Fármacos', icon: Pill, color: 'text-blue-600' },
    { id: 'PAE', label: 'PAE', icon: BookOpen, color: 'text-violet-600' },
    { id: 'LABS', label: 'Laboratorio', icon: FlaskConical, color: 'text-purple-600' },
    { id: 'ACCESS', label: 'Disp.', icon: Cable, color: 'text-orange-600' },
    { id: 'WOUNDS', label: 'Heridas', icon: Ruler, color: 'text-rose-600' },
    { id: 'HANDOFF', label: 'Pase', icon: Megaphone, color: 'text-amber-600' },
] as const;

export const ClinicalFollowUp: React.FC = () => {
    const [patients, setPatients] = useState<Patient[]>([]);
    const [selectedPatientId, setSelectedPatientId] = useState<string | null>(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [detailTab, setDetailTab] = useState<string>('NOTES');
    const [isFlorenceOpen, setIsFlorenceOpen] = useState(false);

    const [showCamera, setShowCamera] = useState(false);
    const [showAdmissionModal, setShowAdmissionModal] = useState(false);
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [analysisResult, setAnalysisResult] = useState<ClinicalAnalysis | null>(null);
    const [noteText, setNoteText] = useState('');

    const [florenceMessages, setFlorenceMessages] = useState<ChatMessage[]>([]);
    const [florenceInput, setFlorenceInput] = useState('');
    const [isFlorenceTyping, setIsFlorenceTyping] = useState(false);

    const loadData = async () => {
        const data = await PatientService.getAll();
        setPatients(data);
    };

    useEffect(() => { loadData(); }, []);

    const selectedPatient = useMemo(() => patients.find(p => p.id === selectedPatientId), [patients, selectedPatientId]);

    const filteredPatients = useMemo(() => {
        const term = (searchTerm || '').toLowerCase().trim();
        return patients.filter(p => 
            (p.name || '').toLowerCase().includes(term) || 
            (p.bed || '').toLowerCase().includes(term) ||
            (p.diagnosis || '').toLowerCase().includes(term)
        );
    }, [patients, searchTerm]);

    const groupedHistory = useMemo(() => {
        if (!selectedPatient?.history) return {};
        const groups: Record<string, Evolution[]> = {};
        selectedPatient.history.forEach(h => {
            let label = new Date(h.timestamp).toLocaleDateString([], {day: 'numeric', month: 'long'});
            if (new Date(h.timestamp).toDateString() === new Date().toDateString()) label = 'Hoy';
            if (!groups[label]) groups[label] = [];
            groups[label].push(h);
        });
        return groups;
    }, [selectedPatient]);

    const handleSaveNote = async () => {
        if (!selectedPatientId || !noteText.trim()) return;
        const newNote: Evolution = {
            id: `ev-${Date.now()}`,
            timestamp: new Date().toISOString(),
            note: noteText,
            type: 'EVOLUTION',
            analysis: analysisResult || undefined
        };
        await PatientService.addEvolution(selectedPatientId, newNote);
        await loadData();
        setNoteText('');
        setAnalysisResult(null);
    };

    const handleAnalyzeNote = async () => {
        if (!noteText.trim()) return;
        setIsAnalyzing(true);
        try {
            const result = await analyzeClinicalNote(noteText);
            setAnalysisResult(result);
        } catch(e) { console.error(e); }
        finally { setIsAnalyzing(false); }
    };

    const handleFlorenceSend = async (textOverride?: string) => {
        const text = textOverride || florenceInput;
        if(!text.trim() || !selectedPatient) return;

        const userMsg: ChatMessage = { id: Date.now().toString(), userId: 'me', userName: 'Yo', role: 'NURSE', text: text, timestamp: new Date().toISOString() };
        setFlorenceMessages(prev => [...prev, userMsg]);
        setFlorenceInput('');
        setIsFlorenceTyping(true);

        try {
            const response = await generateChatReply(text, 'MENTOR', selectedPatient);
            const aiMsg: ChatMessage = {
                id: 'ai-' + Date.now(), userId: 'florence', userName: 'Florence AI', role: 'ADMIN',
                text: JSON.stringify(response), timestamp: new Date().toISOString(), isSystem: true
            };
            setFlorenceMessages(prev => [...prev, aiMsg]);
        } catch(e) { console.error(e); }
        finally { setIsFlorenceTyping(false); }
    };

    return (
        <div className="flex h-full flex-col bg-slate-100 overflow-hidden font-sans">
            <header className="bg-slate-900 text-white border-b border-slate-800 px-6 py-4 flex justify-between items-center z-20 shadow-xl shrink-0">
                <div className="flex items-center gap-3">
                    <div className="bg-indigo-600 p-2 rounded-xl"><ClipboardList className="w-5 h-5"/></div>
                    <div>
                        <h1 className="text-lg font-black tracking-tight uppercase">Hospital OS <span className="text-indigo-400">Clinical v22</span></h1>
                        <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Unidad de Vigilancia</p>
                    </div>
                </div>
                <button onClick={() => setShowAdmissionModal(true)} className="bg-emerald-600 hover:bg-emerald-700 text-white px-5 py-2.5 rounded-xl text-xs font-black shadow-lg transition-all active:scale-95 border border-emerald-500">
                    <UserPlus className="w-4 h-4 mr-2"/> ADMITIR
                </button>
            </header>

            <div className="flex-1 flex overflow-hidden">
                <div className={`${selectedPatientId ? 'hidden lg:flex w-96' : 'flex w-full'} flex-col bg-white border-r border-slate-200 z-10 shadow-xl shrink-0`}>
                    <div className="p-5 border-b border-slate-100 bg-white">
                        <div className="relative">
                            <Search className="absolute left-4 top-3.5 w-4 h-4 text-slate-400"/>
                            <input value={searchTerm} onChange={e => setSearchTerm(e.target.value)} placeholder="Buscar por nombre o cama..." className="w-full pl-11 pr-4 py-3 rounded-2xl bg-slate-50 border border-slate-200 text-sm font-bold focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all"/>
                        </div>
                    </div>
                    <div className="flex-1 overflow-y-auto p-3 space-y-3 bg-slate-50/50 custom-scrollbar">
                        {filteredPatients.map(patient => (
                            <button key={patient.id} onClick={() => setSelectedPatientId(patient.id)} className={`w-full text-left p-4 rounded-2xl border transition-all flex items-center justify-between ${selectedPatientId === patient.id ? 'bg-white border-indigo-500 ring-2 ring-indigo-50 shadow-xl' : 'bg-white border-slate-200 hover:border-indigo-300 shadow-sm'}`}>
                                <div className="flex-1 min-w-0">
                                    <div className="flex justify-between items-center mb-1">
                                        <span className="font-black text-sm text-slate-800 truncate pr-2 uppercase">{patient.name}</span>
                                        <span className="text-[10px] font-black bg-slate-900 text-white px-2 py-0.5 rounded">{patient.bed}</span>
                                    </div>
                                    <p className="text-[10px] text-slate-500 font-bold uppercase truncate">{patient.diagnosis}</p>
                                    <div className={`mt-2 inline-block px-2 py-0.5 rounded text-[9px] font-black uppercase ${patient.risk === 'HIGH' ? 'bg-rose-50 text-rose-600' : 'bg-emerald-50 text-emerald-600'}`}>NEWS2 {patient.news2}</div>
                                </div>
                                <ChevronRight className="w-5 h-5 text-slate-300 ml-3"/>
                            </button>
                        ))}
                    </div>
                </div>

                {selectedPatient ? (
                    <div className="flex-1 flex flex-col bg-slate-50 relative overflow-hidden h-full">
                        <div className="bg-white border-b border-slate-200 shadow-sm p-4 md:p-6 shrink-0 z-10">
                            <div className="flex justify-between items-start gap-4">
                                <div className="flex items-center gap-4 min-w-0">
                                    <button onClick={() => setSelectedPatientId(null)} className="lg:hidden p-2.5 bg-slate-100 rounded-full text-slate-500"><ArrowLeft className="w-5 h-5"/></button>
                                    <div>
                                        <div className="flex items-center gap-3"><h2 className="text-xl md:text-2xl font-black text-slate-900 uppercase tracking-tighter truncate">{selectedPatient.name}</h2><span className="bg-indigo-600 text-white text-[10px] font-black px-2 py-1 rounded-lg">{selectedPatient.bed}</span></div>
                                        <div className="flex gap-3 text-xs font-bold text-slate-400 uppercase mt-1"><span>{selectedPatient.age} Años</span><span>{selectedPatient.weight} kg</span><span className="text-rose-500 flex items-center gap-1"><ShieldAlert className="w-3.5 h-3.5"/> {selectedPatient.allergies}</span></div>
                                    </div>
                                </div>
                                <button onClick={() => setIsFlorenceOpen(true)} className="bg-gradient-to-tr from-violet-600 to-indigo-700 text-white p-3 rounded-2xl shadow-xl active:scale-95 transition-all"><Bot className="w-7 h-7"/></button>
                            </div>
                            <div className="flex gap-2 mt-6 overflow-x-auto no-scrollbar scroll-smooth">{CLINICAL_MODULES.map(m => (
                                <button key={m.id} onClick={() => setDetailTab(m.id)} className={`px-4 py-2.5 rounded-xl text-xs font-black uppercase tracking-wider transition-all flex items-center whitespace-nowrap border-2 ${detailTab === m.id ? `bg-slate-900 text-white border-slate-900 shadow-xl` : 'bg-white text-slate-500 border-slate-100 hover:border-slate-200 hover:bg-slate-50'}`}>
                                    <m.icon className={`w-4 h-4 mr-2 ${detailTab === m.id ? 'text-indigo-400' : m.color}`}/> {m.label}
                                </button>
                            ))}</div>
                        </div>

                        <div className="flex-1 overflow-y-auto p-4 md:p-8 bg-slate-50/50 custom-scrollbar pb-32">
                            <div className="max-w-5xl mx-auto">
                                {detailTab === 'NOTES' && (
                                    <div className="space-y-8 animate-fade-in">
                                        <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-xl relative overflow-hidden">
                                            <div className="flex justify-between items-center mb-6"><h3 className="text-xs font-black text-slate-800 uppercase tracking-widest flex items-center"><PenTool className="w-4 h-4 mr-2 text-indigo-600"/> Evolución Enfermera</h3><div className="flex gap-2"><VoiceInput onTranscript={t => setNoteText(prev => prev + " " + t)} isCompact /><button onClick={() => setShowCamera(true)} className="p-2 bg-slate-100 rounded-full text-slate-500 hover:text-indigo-600"><Camera className="w-5 h-5"/></button></div></div>
                                            <textarea value={noteText} onChange={e => setNoteText(e.target.value)} placeholder="Registre el estado del paciente..." className="w-full min-h-[160px] bg-slate-50/50 border-2 border-transparent rounded-3xl p-6 text-base font-bold text-slate-700 focus:bg-white focus:border-indigo-500/30 outline-none resize-none transition-all mb-6"/>
                                            <div className="flex justify-between items-center pt-6 border-t border-slate-100">
                                                <button onClick={handleAnalyzeNote} disabled={!noteText.trim() || isAnalyzing} className="text-xs font-black text-indigo-600 flex items-center hover:bg-indigo-50 px-6 py-3 rounded-2xl transition-all disabled:opacity-50">{isAnalyzing ? <Loader2 className="w-5 h-5 animate-spin mr-2"/> : <Sparkles className="w-5 h-5 mr-2"/>} ANÁLISIS IA</button>
                                                <button onClick={handleSaveNote} disabled={!noteText.trim()} className="bg-slate-900 text-white px-10 py-4 rounded-2xl text-xs font-black uppercase tracking-widest shadow-2xl active:scale-95 transition-all">REGISTRAR EVOLUCIÓN</button>
                                            </div>
                                        </div>
                                        <div className="space-y-8">{Object.entries(groupedHistory).map(([date, entries]) => (
                                            <div key={date} className="relative">
                                                <div className="sticky top-0 z-10 py-3 mb-6 bg-slate-50/90 backdrop-blur-xl flex items-center gap-4"><div className="bg-slate-200 px-3 py-1 rounded-xl text-[10px] font-black text-slate-600 uppercase tracking-widest border border-slate-300">{date}</div><div className="h-px bg-slate-300 flex-1"></div></div>
                                                <div className="space-y-6 relative ml-4 border-l-4 border-slate-200 pl-10">
                                                    {entries.map(h => (
                                                        <div key={h.id} className="relative bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm group">
                                                            <div className="absolute -left-[45px] top-6 w-5 h-5 bg-white border-4 border-indigo-600 rounded-full z-10 shadow-md"></div>
                                                            <div className="flex justify-between items-start mb-3"><span className="text-[11px] font-black text-indigo-600 uppercase bg-indigo-50 px-2 py-1 rounded-lg flex items-center gap-1.5"><Clock className="w-4 h-4"/> {new Date(h.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span></div>
                                                            <p className="text-sm font-medium text-slate-700 leading-relaxed whitespace-pre-wrap">{h.note}</p>
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                        ))}</div>
                                    </div>
                                )}
                                {detailTab === 'MONITOR' && <VitalSigns history={selectedPatient.history} />}
                                {detailTab === 'MEDS' && <MedicationSheet prescriptions={selectedPatient.prescriptions || []} onUpdate={p => PatientService.updatePatient(selectedPatient.id, {prescriptions: p}).then(loadData)} />}
                                {detailTab === 'PAE' && <CarePlanManager carePlans={selectedPatient.activePae || []} onUpdate={p => PatientService.updatePatient(selectedPatient.id, {activePae: p}).then(loadData)} />}
                                {detailTab === 'LABS' && <LabResults reports={selectedPatient.labReports || []} />}
                                {detailTab === 'ACCESS' && <AccessManager devices={selectedPatient.activeDevices || []} onUpdate={d => PatientService.updatePatient(selectedPatient.id, {activeDevices: d}).then(loadData)} />}
                                {detailTab === 'WOUNDS' && <WoundAnalysis wounds={selectedPatient.wounds || []} onAddWound={w => PatientService.updatePatient(selectedPatient.id, {wounds: [w, ...(selectedPatient.wounds||[])]}).then(loadData)} />}
                                {detailTab === 'HANDOFF' && <ShiftHandoff patient={selectedPatient} onSendToChat={handleFlorenceSend} />}
                            </div>
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 hidden md:flex flex-col items-center justify-center bg-slate-50/50 text-slate-300">
                        <div className="w-40 h-40 bg-white rounded-full flex items-center justify-center shadow-2xl mb-6"><User className="w-20 h-20 opacity-10"/></div>
                        <p className="text-sm font-black uppercase tracking-[0.4em]">Seleccione un Paciente</p>
                    </div>
                )}
            </div>

            {isFlorenceOpen && selectedPatient && (
                <div className="fixed inset-0 z-50 flex justify-end">
                    <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm transition-opacity" onClick={() => setIsFlorenceOpen(false)}></div>
                    <div className="w-full md:w-[600px] bg-slate-50 h-full shadow-2xl relative flex flex-col animate-slide-in-right border-l border-white/10">
                        <div className="p-6 bg-slate-900 text-white flex justify-between items-center shadow-2xl shrink-0">
                            <div className="flex items-center gap-4"><img src="https://ui-avatars.com/api/?name=Florence+AI&background=7c3aed&color=fff" className="w-12 h-12 rounded-2xl" alt="AI"/><div><h3 className="font-black text-xl tracking-tight uppercase">Florence AI <span className="text-indigo-400 text-xs ml-2 border border-indigo-500/50 px-2 py-0.5 rounded-full">v3.0</span></h3><div className="flex items-center text-[10px] font-black text-indigo-300 bg-indigo-500/20 px-2 py-1 rounded-full border border-indigo-500/30 w-fit mt-1"><Globe className="w-3.5 h-3.5 mr-2"/> EVIDENCE GROUNDING</div></div></div>
                            <button onClick={() => setIsFlorenceOpen(false)} className="p-2 hover:bg-white/10 rounded-full transition-colors"><X className="w-6 h-6"/></button>
                        </div>
                        <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar bg-slate-100/30">
                            {florenceMessages.map((msg, i) => {
                                const isMe = msg.userId === 'me';
                                let data: FlorenceResponse | null = null;
                                if (!isMe) { try { data = msg.text?.trim().startsWith('{') ? JSON.parse(msg.text) : null; } catch(e) { data = null; } }
                                const text = data ? data.answer : msg.text;
                                if (!text) return null;
                                return (
                                    <div key={i} className={`flex ${isMe ? 'justify-end' : 'justify-start'} animate-fade-in-up`}>
                                        <div className={`max-w-[90%] p-5 rounded-[2rem] text-sm shadow-xl relative border ${isMe ? 'bg-indigo-600 text-white rounded-br-none border-indigo-500' : 'bg-white border-slate-200 text-slate-800 rounded-bl-none shadow-slate-200/50'}`}>
                                            {!isMe && data && (
                                                <div className="flex items-center justify-between mb-3 pb-2 border-b border-slate-100"><span className="text-[10px] font-black text-violet-600 flex items-center gap-2 uppercase tracking-widest"><ShieldCheck className="w-4 h-4"/> JUICIO CLÍNICO</span><span className={`text-[8px] font-black px-2 py-0.5 rounded border ${data.confidence === 'HIGH' ? 'bg-emerald-50 text-emerald-700' : 'bg-amber-50 text-amber-700'}`}>FIABILIDAD: {data.confidence}</span></div>
                                            )}
                                            <div className="whitespace-pre-wrap leading-relaxed font-medium">
                                                {/* Fix: safely split text and cast to string[] to ensure 'map' property is recognized correctly */}
                                                {(text?.split(/(\*\*.*?\*\*)/g) || []).map((part: string, i: number) => 
                                                    part && part.startsWith('**') && part.endsWith('**') ? (
                                                        <strong key={i} className={isMe ? "text-white" : "text-slate-900 dark:text-white font-black"}>
                                                            {part.slice(2, -2)}
                                                        </strong>
                                                    ) : (
                                                        part
                                                    )
                                                )}
                                            </div>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                        <div className="p-6 bg-white border-t border-slate-200 shadow-2xl"><form onSubmit={(e) => { e.preventDefault(); handleFlorenceSend(); }} className="flex items-center gap-3"><div className="flex-1 bg-slate-100 rounded-[2rem] p-1.5 flex items-center border-2 border-transparent focus-within:border-indigo-500/20 focus-within:bg-white transition-all shadow-inner"><button type="button" className="p-2.5 text-slate-400 hover:text-indigo-600 transition-colors"><Mic className="w-5 h-5"/></button><input className="flex-1 bg-transparent border-none focus:ring-0 outline-none text-sm font-bold text-slate-700 px-2" placeholder="Consulte guías v22..." value={florenceInput} onChange={e => setFlorenceInput(e.target.value)}/></div><button type="submit" disabled={!florenceInput.trim() || isFlorenceTyping} className="p-4 bg-slate-900 text-white rounded-full shadow-2xl hover:bg-black transition-all active:scale-95 disabled:opacity-50"><Send className="w-6 h-6"/></button></form></div>
                    </div>
                </div>
            )}

            {showAdmissionModal && <AdmissionModal onClose={() => setShowAdmissionModal(false)} onSave={async (p) => { await PatientService.admitPatient(p); await loadData(); setShowAdmissionModal(false); }} />}
            {showCamera && <CameraCapture mode="PHOTO" onCapture={url => alert("Imagen capturada: " + url)} onClose={() => setShowCamera(false)} />}
        </div>
    );
};

