export const Pharmacology: React.FC<{initialQuery?: string}> = ({ initialQuery }) => {
    const [query, setQuery] = useState(initialQuery || '');
    const [selectedDrug, setSelectedDrug] = useState<Drug | null>(null);
    const [loadingAI, setLoadingAI] = useState(false);
    const [activeSection, setActiveSection] = useState<'ADMIN' | 'PREP' | 'SAFETY'>('ADMIN');
    const [customDrugs, setCustomDrugs] = useState<Drug[]>([]);
    const [showNewDrugModal, setShowNewDrugModal] = useState(false);

    const [newDrugForm, setNewDrugForm] = useState<Partial<Drug>>({
        name: '', group: 'General', brandNames: '', presentation: '', dilution: '', administrationRoute: 'IV', monitoring: '', safetyAlert: 'ESTÁNDAR', 
        indications: [], sideEffects: []
    });

    const loadCustomDrugs = async () => {
        const drugs = await DrugService.getAll();
        setCustomDrugs(drugs);
    };

    useEffect(() => { loadCustomDrugs(); }, []);

    useEffect(() => {
        if (initialQuery) {
            setQuery(initialQuery);
            handleSelectDrug({ name: initialQuery });
        }
    }, [initialQuery]);

    const organizedList = useMemo(() => {
        const q = (query || '').toLowerCase().trim();
        let allItems: any[] = [];

        RAW_DRUG_CATALOG.forEach(cat => {
            cat.items.forEach(item => {
                allItems.push({ name: item, group: cat.category, isStatic: false, type: 'CATALOG' });
            });
        });

        STATIC_DRUGS.forEach(d => {
            const existingIdx = allItems.findIndex(i => i.name.toLowerCase() === d.name.toLowerCase());
            if (existingIdx !== -1) {
                allItems[existingIdx] = { ...allItems[existingIdx], isStatic: true, drug: d, type: 'STATIC' };
            } else {
                allItems.push({ name: d.name, group: d.group, isStatic: true, drug: d, type: 'STATIC' });
            }
        });

        customDrugs.forEach(d => {
            allItems.push({ name: d.name, group: d.group, isStatic: true, drug: d, type: 'CUSTOM' });
        });

        let filtered = allItems.filter(item => {
            const matchesSearch = !q || item.name.toLowerCase().includes(q) || (item.drug?.brandNames || '').toLowerCase().includes(q);
            return matchesSearch;
        }).sort((a,b) => a.name.localeCompare(b.name));

        const groups: Record<string, any[]> = {};
        filtered.forEach(item => {
            const letter = item.name.charAt(0).toUpperCase();
            if(!groups[letter]) groups[letter] = [];
            groups[letter].push(item);
        });
        return groups;
    }, [query, customDrugs]);

    const handleSelectDrug = async (item: any) => {
        if (item.drug) { 
            setSelectedDrug(item.drug); 
            setActiveSection('ADMIN');
            return; 
        }
        setLoadingAI(true);
        setActiveSection('ADMIN');
        try {
            const newDrug = await generateDrugDetails(item.name);
            setSelectedDrug(newDrug);
        } catch (e) { console.error(e); }
        finally { setLoadingAI(false); }
    };

    const handleSaveNewDrug = async () => {
        if(!newDrugForm.name) return;
        const drug: Drug = {
            ...newDrugForm as Drug,
            id: `drug-${Date.now()}`,
            indications: typeof newDrugForm.indications === 'string' ? (newDrugForm.indications as string).split(',') : newDrugForm.indications || [],
            sideEffects: typeof newDrugForm.sideEffects === 'string' ? (newDrugForm.sideEffects as string).split(',') : newDrugForm.sideEffects || [],
        };
        await DrugService.add(drug);
        await loadCustomDrugs();
        setShowNewDrugModal(false);
        setNewDrugForm({ name: '', group: 'General', brandNames: '', presentation: '', dilution: '', administrationRoute: 'IV', monitoring: '', safetyAlert: 'ESTÁNDAR', indications: [], sideEffects: [] });
    };

    const handleDeleteDrug = async (id: string) => {
        if(confirm("¿Eliminar fármaco del vademécum personal?")) {
            await DrugService.delete(id);
            await loadCustomDrugs();
            setSelectedDrug(null);
        }
    };

    return (
        <div className="flex flex-col lg:flex-row h-full bg-slate-100 overflow-hidden font-sans">
            <div className={`lg:w-96 bg-white border-r border-slate-200 flex flex-col shrink-0 z-20 shadow-xl ${selectedDrug || loadingAI ? 'hidden lg:flex' : 'flex w-full'}`}>
                <div className="p-5 bg-slate-900 text-white sticky top-0 shadow-lg">
                    <div className="flex items-center justify-between mb-4">
                        <h2 className="font-black text-xs uppercase tracking-widest text-emerald-400 flex items-center">
                            <Pill className="w-4 h-4 mr-2"/> Vademécum PRO v22
                        </h2>
                        <button onClick={() => setShowNewDrugModal(true)} className="bg-emerald-600 hover:bg-emerald-700 text-white p-2 rounded-xl transition-all shadow-lg active:scale-95 flex items-center gap-1">
                            <Plus className="w-4 h-4"/><span className="text-[10px] font-black uppercase pr-1">Nuevo</span>
                        </button>
                    </div>
                    <div className="relative group">
                        <Search className="absolute left-3 top-3 text-slate-500 w-4 h-4 group-focus-within:text-emerald-500 transition-colors"/>
                        <input value={query} onChange={e => setQuery(e.target.value)} placeholder="Buscar en +450 principios..." className="w-full pl-10 p-3 rounded-xl bg-slate-800 border border-slate-700 text-sm text-white outline-none focus:ring-2 focus:ring-emerald-500/30 transition-all font-medium placeholder:text-slate-500"/>
                    </div>
                    <div className="flex items-center gap-3 mt-4 px-1">
                        <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-emerald-500"></div><span className="text-[9px] font-bold text-slate-400 uppercase tracking-tighter">Local</span></div>
                        <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-indigo-500"></div><span className="text-[9px] font-bold text-slate-400 uppercase tracking-tighter">Florence Cloud</span></div>
                    </div>
                </div>
                <div className="flex-1 overflow-y-auto custom-scrollbar bg-slate-50">
                    {Object.keys(organizedList).sort().map(key => (
                        <div key={key}>
                            <div className="sticky top-0 bg-slate-100/95 backdrop-blur z-10 py-1.5 px-5 text-[10px] font-black text-slate-500 uppercase tracking-widest border-b border-slate-200 mb-2 flex justify-between items-center">
                                <span>{key}</span><span className="opacity-50">{organizedList[key].length}</span>
                            </div>
                            {organizedList[key].map((item, idx) => (
                                <button key={idx} onClick={() => handleSelectDrug(item)} className={`w-full text-left p-5 hover:bg-white transition-all border-b border-slate-100 flex items-center justify-between group ${selectedDrug?.name === item.name ? 'bg-indigo-50 border-l-4 border-l-indigo-600 shadow-sm' : 'bg-transparent'}`}>
                                    <div className="min-w-0">
                                        <div className={`font-black text-base truncate ${selectedDrug?.name === item.name ? 'text-indigo-600' : 'text-slate-800 group-hover:text-indigo-500'}`}>{item.name}</div>
