                                    </div>
                                    <div className={`w-2 h-2 rounded-full transition-all ${item.isStatic ? 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.4)]' : 'bg-indigo-400'}`}></div>
                                </button>
                            ))}
                        </div>
                    ))}
                </div>
            </div>

            <div className={`flex-1 flex flex-col bg-slate-50 h-full relative overflow-hidden ${!selectedDrug && !loadingAI ? 'hidden lg:flex' : 'flex'}`}>
                {loadingAI ? (
                    <div className="flex-1 flex flex-col items-center justify-center p-8 bg-slate-50 animate-fade-in">
