                                <div><h3 className="text-xl font-black text-white tracking-tight">Registro de Fármaco PRO</h3><p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em]">Personalización de vademécum local</p></div>
                            </div>
                            <button onClick={() => setShowNewDrugModal(false)} className="text-slate-400 hover:text-white bg-slate-800 p-2.5 rounded-full transition-colors"><X className="w-5 h-5"/></button>
                        </div>
                        <div className="flex-1 overflow-y-auto p-8 space-y-8 custom-scrollbar">
                            <div className="grid md:grid-cols-2 gap-6">
                                <div className="col-span-full"><label className="text-[10px] font-black text-indigo-500 uppercase block mb-2 tracking-widest">Principio Activo</label><input value={newDrugForm.name} onChange={e => setNewDrugForm({...newDrugForm, name: e.target.value})} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-4 text-base font-bold outline-none focus:bg-white focus:border-indigo-500/30 transition-all shadow-inner" placeholder="Ej: Piperacilina-Tazobactam"/></div>
                                <div><label className="text-[10px] font-black text-slate-400 uppercase block mb-2 tracking-widest">Familia</label><input value={newDrugForm.group} onChange={e => setNewDrugForm({...newDrugForm, group: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-sm font-bold outline-none" placeholder="Antibiótico"/></div>
                                <div><label className="text-[10px] font-black text-slate-400 uppercase block mb-2 tracking-widest">Comercial</label><input value={newDrugForm.brandNames} onChange={e => setNewDrugForm({...newDrugForm, brandNames: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-sm font-bold outline-none" placeholder="Pipetazo"/></div>
                                <div className="col-span-full"><label className="text-[10px] font-black text-slate-400 uppercase block mb-2">Dilución y Administración</label><textarea value={newDrugForm.dilution} onChange={e => setNewDrugForm({...newDrugForm, dilution: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-2xl p-4 text-sm font-medium h-24 outline-none resize-none" placeholder="Ej: Diluir 4g en 100ml SF, pasar en 30min..."/></div>
                                <div><label className="text-[10px] font-black text-rose-500 uppercase block mb-2">Riesgo</label><select value={newDrugForm.safetyAlert} onChange={e => setNewDrugForm({...newDrugForm, safetyAlert: e.target.value})} className="w-full bg-rose-50 border border-rose-100 rounded-xl p-3 text-sm font-bold text-rose-700 outline-none"><option value="ESTÁNDAR">Riesgo Estándar</option><option value="ALTO RIESGO">⚠️ ALTO RIESGO</option></select></div>
                                <div><label className="text-[10px] font-black text-slate-400 uppercase block mb-2">Monitorización</label><input value={newDrugForm.monitoring} onChange={e => setNewDrugForm({...newDrugForm, monitoring: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-sm font-bold outline-none" placeholder="TA, FC..."/></div>
                            </div>
                        </div>
                        <div className="p-6 bg-slate-50 border-t border-slate-200 shrink-0">
                            <button onClick={handleSaveNewDrug} className="w-full bg-slate-900 hover:bg-black text-white py-5 rounded-3xl font-black uppercase tracking-widest shadow-2xl active:scale-95 transition-all flex items-center justify-center gap-3"><Save className="w-5 h-5 text-emerald-400"/> GUARDAR EN SISTEMA</button>
