                                    </div>
                                    <div className="grid md:grid-cols-2 gap-6">
                                        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                                            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center"><Activity className="w-4 h-4 mr-2 text-rose-500"/> Etiología / Causas</h3>
                                            <p className="text-sm font-bold text-slate-700 leading-relaxed">{selectedPathology.generalInfo?.etiology}</p>
                                        </div>
                                        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                                            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center"><Eye className="w-4 h-4 mr-2 text-cyan-500"/> Signos y Síntomas</h3>
                                            <div className="flex flex-wrap gap-2">
                                                {selectedPathology.generalInfo?.signsSymptoms?.map((s,i) => <span key={i} className="px-3 py-1.5 bg-slate-50 text-slate-700 text-[10px] font-black rounded-xl border border-slate-200 uppercase tracking-tight">• {s}</span>)}
                                            </div>
                                        </div>
                                    </div>
                                    {selectedPathology.generalInfo?.redFlags && (
                                        <div className="bg-rose-50 border border-rose-200 p-6 rounded-3xl flex items-start gap-4">
                                            <AlertTriangle className="w-6 h-6 text-rose-600 shrink-0 animate-pulse"/>
                                            <div>
                                                <h4 className="text-xs font-black text-rose-900 uppercase mb-1">Criterios de Gravedad</h4>
                                                <p className="text-sm font-bold text-rose-700">{selectedPathology.generalInfo.redFlags}</p>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            )}
                            {activeTab === 'PHARMA' && (
                                <div className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden animate-fade-in shadow-xl">
                                    <div className="bg-slate-900 px-8 py-5 border-b border-slate-800 flex justify-between items-center">
                                        <h3 className="text-xs font-black text-emerald-400 uppercase tracking-widest flex items-center"><Pill className="w-4 h-4 mr-2"/> Terapia Farmacológica</h3>
                                        <span className="text-[9px] font-black text-slate-500 uppercase">{selectedPathology.pharmacology?.length || 0} pautas sugeridas</span>
                                    </div>
                                    <div className="divide-y divide-slate-100">{selectedPathology.pharmacology?.map((p,i) => (
