                            </div>
                            <div className="col-span-full">
                                <label className="text-[10px] font-black text-slate-400 uppercase block mb-2">Definición</label>
                                <textarea value={newPathologyForm.generalInfo?.definition} onChange={e => setNewPathologyForm({...newPathologyForm, generalInfo: { ...newPathologyForm.generalInfo!, definition: e.target.value }})} className="w-full bg-slate-50 border border-slate-200 rounded-2xl p-4 text-sm font-medium h-24 outline-none resize-none" placeholder="Descripción breve de la patología..."/>
                            </div>
