                <ChevronRight className="w-4 h-4 text-slate-300 group-hover:text-indigo-500"/>
            </div>
        </button>
    );
});

export const Pathologies: React.FC<PathologiesProps> = ({ initialQuery, initialCategory, onNavigate }) => {
  const [query, setQuery] = useState(initialQuery || '');
  const [filterQuery, setFilterQuery] = useState(initialQuery || '');
  const [selectedCategory, setSelectedCategory] = useState<string>(initialCategory || 'ALL');
  const [selectedPathology, setSelectedPathology] = useState<Pathology | null>(null);
  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState<'CLINICAL' | 'PHARMA' | 'PAE'>('CLINICAL');
  const [viewMode, setViewMode] = useState<'AZ' | 'GROUP'>('GROUP');
  const [customPathologies, setCustomPathologies] = useState<Pathology[]>([]);
  const [showNewModal, setShowNewModal] = useState(false);
  const [newPathologyForm, setNewPathologyForm] = useState<Partial<Pathology>>({
      name: '', family: 'General', generalInfo: { definition: '', etiology: '', signsSymptoms: [] }
  });

  const loadCustomData = async () => {
      const data = await PathologyService.getAll();
      setCustomPathologies(data);
  };

  useEffect(() => { loadCustomData(); }, []);

  useEffect(() => {
      const timer = setTimeout(() => setFilterQuery(query), 300);
      return () => clearTimeout(timer);
  }, [query]);

  const organizedList = useMemo(() => {
      const q = (filterQuery || '').toLowerCase().trim();
      let activeItems = [...FLATTENED_STATIC_CATALOG];

      customPathologies.forEach(p => {
          activeItems.push({
              name: p.name,
              category: p.family || 'Personalizado',
              icon: BookOpen,
              color: 'text-indigo-600',
              bg: 'bg-indigo-50',
              isCustom: true,
              score: 0,
              pathology: p
          } as any);
      });

      let filtered = activeItems;
      if (q) {
          filtered = activeItems.reduce((acc: any[], item) => {
              let score = 0;
              const n = (item.name || '').toLowerCase();
              if (n === q) score = 100;
              else if (n.startsWith(q)) score = 80;
              else if (n.includes(q)) score = 50;
              if (score > 0) acc.push({ ...item, score });
              return acc;
          }, []).sort((a: any, b: any) => b.score - a.score);
      } else if (selectedCategory !== 'ALL') {
          filtered = activeItems.filter(i => i.category === selectedCategory);
      }

      const grouped: Record<string, any[]> = {};
      if (viewMode === 'AZ') {
          filtered.sort((a,b) => (a.name || '').localeCompare(b.name || '')).forEach(item => {
              const letter = (item.name || '#').charAt(0).toUpperCase();
              if(!grouped[letter]) grouped[letter] = [];
              grouped[letter].push(item);
          });
      } else {
          filtered.forEach(item => {
              const cat = item.category || 'Otros';
              if(!grouped[cat]) grouped[cat] = [];
              grouped[cat].push(item);
          });
      }
      return grouped;
  }, [filterQuery, selectedCategory, viewMode, customPathologies]);

  const sortedKeys = Object.keys(organizedList).sort();

  const handleSelectPathology = async (item: any) => {
      if (item.pathology) {
          setSelectedPathology(item.pathology);
          setActiveTab('CLINICAL');
          return;
      }
      setLoading(true);
      try {
          const result = await generatePathology(item.name);
          setSelectedPathology(result);
          setActiveTab('CLINICAL');
      } catch (e) { console.error(e); }
      finally { setLoading(false); }
  };

  const handleSaveNewPathology = async () => {
      if (!newPathologyForm.name) return;
      const path: Pathology = {
          ...newPathologyForm as Pathology,
          id: `path-${Date.now()}`,
          pae: newPathologyForm.pae || { nanda: [], nic: [], noc: [] },
          pharmacology: newPathologyForm.pharmacology || []
      };
      await PathologyService.add(path);
      await loadCustomData();
      setShowNewModal(false);
      setNewPathologyForm({ name: '', family: 'General', generalInfo: { definition: '', etiology: '', signsSymptoms: [] } });
  };

  const handleDelete = async (id: string) => {
      if (confirm("¿Eliminar esta guía de la biblioteca personal?")) {
          await PathologyService.delete(id);
          await loadCustomData();
          setSelectedPathology(null);
      }
  };

  return (
    <div className="flex h-full bg-slate-100 overflow-hidden font-sans">
        {/* Sidebar */}
        <div className={`w-full md:w-[450px] bg-white border-r border-slate-200 flex flex-col h-full shrink-0 z-10 shadow-xl ${selectedPathology || loading ? 'hidden md:flex' : 'flex'}`}>
            <div className="p-4 bg-slate-900 text-white shrink-0">
                <div className="flex justify-between items-center mb-4">
                    <h2 className="font-black text-xs uppercase tracking-widest text-emerald-400 flex items-center"><BookOpen className="w-4 h-4 mr-2"/> Biblioteca v22</h2>
                    <button onClick={() => setShowNewModal(true)} className="bg-indigo-600 hover:bg-indigo-700 text-white p-2 rounded-xl transition-all shadow-lg active:scale-95 flex items-center gap-1">
                        <Plus className="w-4 h-4"/><span className="text-[10px] font-black uppercase pr-1">Nueva</span>
                    </button>
                </div>
                <div className="relative group">
                    <Search className="absolute left-3 top-3 text-slate-500 w-4 h-4"/>
                    <input 
                        type="text" 
                        value={query}
                        onChange={e => setQuery(e.target.value)}
                        placeholder="Buscar patología..." 
                        className="w-full pl-10 pr-10 py-3 bg-slate-800 border border-slate-700 rounded-xl text-sm font-bold text-white focus:border-emerald-500 outline-none transition-all"
                    />
                </div>
            </div>
            <div className="flex-1 overflow-y-auto custom-scrollbar p-2 bg-slate-50">
                {sortedKeys.map(key => (
                    <div key={key} className="mb-4">
                        <div className="sticky top-0 bg-slate-100/95 backdrop-blur z-10 py-1.5 px-2 text-[10px] font-black text-slate-500 uppercase tracking-widest border-b border-slate-200 mb-2 flex justify-between items-center">
                            <span>{key}</span>
                            <span className="opacity-50">{organizedList[key].length}</span>
                        </div>
                        <div className="space-y-2">
                            {organizedList[key].map((item, idx) => (
                                <PathologyRow key={idx} item={item} isSelected={selectedPathology?.name === item.name} onClick={handleSelectPathology} />
                            ))}
                        </div>
                    </div>
                ))}
            </div>
        </div>

        {/* Content Area */}
        <div className={`flex-1 bg-white flex flex-col h-full overflow-hidden ${!selectedPathology && !loading ? 'hidden md:flex' : 'flex'}`}>
            {loading ? (
                <div className="flex-1 flex flex-col items-center justify-center p-8 bg-slate-50 animate-fade-in">
                    <div className="relative">
                        <Loader2 className="w-16 h-16 text-emerald-500 animate-spin mb-4"/>
                        <Sparkles className="w-6 h-6 text-indigo-500 absolute top-5 left-5 animate-pulse"/>
                    </div>
                    <h3 className="font-black text-slate-800 text-xl tracking-tight">Compilando Guía Clínica...</h3>
                    <p className="text-sm text-slate-400 font-medium mt-1">Soporte IA PAESYS habilitado</p>
                </div>
            ) : selectedPathology ? (
                <div className="flex flex-col h-full animate-fade-in bg-slate-50">
                    <div className="bg-white border-b border-slate-200 p-6 shadow-sm sticky top-0 z-10">
                        <div className="flex items-start gap-4">
                            <button onClick={() => setSelectedPathology(null)} className="md:hidden p-2 bg-slate-100 rounded-full"><ArrowLeft className="w-5 h-5"/></button>
                            <div className="flex-1 min-w-0">
                                <div className="flex items-center gap-2 mb-2">
                                    <span className="bg-indigo-50 text-indigo-700 text-[9px] font-black px-2 py-0.5 rounded border border-indigo-100 uppercase inline-block">{selectedPathology.family || 'Clínica General'}</span>
                                    {selectedPathology.id?.startsWith('path-') && <span className="bg-emerald-50 text-emerald-700 text-[9px] font-black px-2 py-0.5 rounded border border-emerald-100 uppercase inline-block">LOCAL</span>}
                                </div>
                                <h1 className="text-2xl md:text-4xl font-black text-slate-900 leading-tight uppercase tracking-tighter truncate">{selectedPathology.name}</h1>
                            </div>
                            {selectedPathology.id?.startsWith('path-') && (
                                <button onClick={() => handleDelete(selectedPathology.id!)} className="p-3 bg-rose-50 text-rose-400 rounded-xl border border-rose-100 hover:text-rose-600 transition-colors">
                                    <Trash2 className="w-5 h-5"/>
                                </button>
                            )}
                        </div>
                        <div className="flex gap-2 mt-6 overflow-x-auto no-scrollbar">
                            {['CLINICAL', 'PHARMA', 'PAE'].map(t => (
                                <button key={t} onClick={() => setActiveTab(t as any)} className={`px-5 py-2.5 rounded-xl text-[10px] font-black transition-all border-2 uppercase tracking-widest whitespace-nowrap ${activeTab === t ? 'bg-slate-900 text-white border-slate-900 shadow-xl' : 'bg-white text-slate-500 border-slate-100 hover:border-slate-200 hover:bg-slate-50'}`}>
                                    {t === 'CLINICAL' ? 'Fisiopatología' : t === 'PHARMA' ? 'Tratamiento' : 'Plan de Cuidados'}
                                </button>
                            ))}
                        </div>
                    </div>
                    <div className="flex-1 overflow-y-auto p-6 md:p-10 custom-scrollbar bg-slate-50/50 pb-32">
                        <div className="max-w-4xl mx-auto space-y-8">
                            {activeTab === 'CLINICAL' && (
                                <div className="space-y-6 animate-fade-in">
                                    <div className="bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-sm relative overflow-hidden group">
                                        <div className="absolute top-0 right-0 p-8 opacity-5 group-hover:opacity-10 transition-opacity"><BookOpen className="w-24 h-24 text-indigo-900"/></div>
                                        <h3 className="text-xs font-black text-indigo-700 uppercase tracking-[0.2em] mb-4 flex items-center"><GraduationCap className="w-4 h-4 mr-2"/> Definición Clínica</h3>
                                        <p className="text-base font-bold text-slate-700 leading-relaxed relative z-10">{selectedPathology.generalInfo?.definition}</p>
                                    </div>
                                    <div className="grid md:grid-cols-2 gap-6">
                                        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                                            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center"><Activity className="w-4 h-4 mr-2 text-rose-500"/> Etiología / Causas</h3>
                                            <p className="text-sm font-bold text-slate-700 leading-relaxed">{selectedPathology.generalInfo?.etiology}</p>
                                        </div>
                                        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                                            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center"><Eye className="w-4 h-4 mr-2 text-cyan-500"/> Signos y Síntomas</h3>
                                            <div className="flex flex-wrap gap-2">
                                                {selectedPathology.generalInfo?.signsSymptoms?.map((s,i) => <span key={i} className="px-3 py-1.5 bg-slate-50 text-slate-700 text-[10px] font-black rounded-xl border border-slate-200 uppercase tracking-tight">• {s}</span>)}
                                            </div>
                                        </div>
                                    </div>
                                    {selectedPathology.generalInfo?.redFlags && (
                                        <div className="bg-rose-50 border border-rose-200 p-6 rounded-3xl flex items-start gap-4">
                                            {/* AlertTriangle used here, was missing from imports */}
                                            <AlertTriangle className="w-6 h-6 text-rose-600 shrink-0 animate-pulse"/>
                                            <div>
                                                <h4 className="text-xs font-black text-rose-900 uppercase mb-1">Criterios de Gravedad</h4>
                                                <p className="text-sm font-bold text-rose-700">{selectedPathology.generalInfo.redFlags}</p>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            )}
                            {activeTab === 'PHARMA' && (
                                <div className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden animate-fade-in shadow-xl">
                                    <div className="bg-slate-900 px-8 py-5 border-b border-slate-800 flex justify-between items-center">
                                        <h3 className="text-xs font-black text-emerald-400 uppercase tracking-widest flex items-center"><Pill className="w-4 h-4 mr-2"/> Terapia Farmacológica</h3>
                                        <span className="text-[9px] font-black text-slate-500 uppercase">{selectedPathology.pharmacology?.length || 0} pautas sugeridas</span>
                                    </div>
                                    <div className="divide-y divide-slate-100">{selectedPathology.pharmacology?.map((p,i) => (
                                        <div key={i} className="p-6 flex flex-col md:flex-row gap-6 hover:bg-slate-50 transition-colors">
                                            <div className="md:w-1/3">
                                                <div className="text-[9px] font-black text-indigo-500 uppercase mb-1 tracking-widest">{p.group}</div>
                                                <div className="text-base font-black text-slate-800">{p.drug}</div>
                                            </div>
                                            <div className="flex-1 bg-slate-100/50 p-4 rounded-2xl border border-slate-200/50">
                                                <div className="text-[9px] font-black text-slate-400 uppercase mb-2">Efecto / Mecanismo</div>
                                                <div className="text-sm font-bold text-slate-600 italic leading-relaxed">"{p.effect}"</div>
                                            </div>
                                        </div>
                                    ))}</div>
                                </div>
                            )}
                            {activeTab === 'PAE' && (
                                <div className="space-y-6 animate-fade-in">
                                    {selectedPathology.pae?.nanda?.map((dx, i) => (
                                        <div key={i} className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden">
                                            <div className="bg-indigo-600 text-white p-6 shadow-lg shadow-indigo-600/20">
                                                <div className="flex items-center gap-2 mb-2">
                                                    <span className="text-[9px] font-black uppercase text-white/70 tracking-widest border border-white/20 px-2 py-0.5 rounded">NANDA {dx.code}</span>
                                                </div>
                                                <h4 className="font-black text-lg md:text-xl tracking-tight leading-tight">{dx.label}</h4>
                                                <p className="text-xs text-indigo-100 font-bold mt-2 italic opacity-80">r/c {dx.relatedTo}</p>
                                            </div>
                                            <div className="grid md:grid-cols-2 divide-y md:divide-y-0 md:divide-x divide-slate-100">
                                                <div className="p-6">
                                                    <h5 className="text-[10px] font-black text-indigo-600 uppercase mb-4 flex items-center tracking-widest"><Target className="w-3.5 h-3.5 mr-2"/> NOC (Resultados)</h5>
                                                    <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                                                        <p className="text-sm font-bold text-slate-700 leading-relaxed">{selectedPathology.pae?.noc[i]?.result}</p>
                                                    </div>
                                                </div>
                                                <div className="p-6 bg-emerald-50/20">
                                                    <h5 className="text-[10px] font-black text-emerald-600 uppercase mb-4 flex items-center tracking-widest"><CheckCircle2 className="w-3.5 h-3.5 mr-2"/> NIC (Actividades)</h5>
                                                    <ul className="space-y-3">
                                                        {selectedPathology.pae?.nic[i]?.activities?.map((a,idx) => (
                                                            <li key={idx} className="text-xs text-slate-600 font-bold flex gap-3 bg-white p-3 rounded-xl shadow-sm border border-emerald-100">
                                                                <span className="text-emerald-500 mt-0.5">•</span> {a}
                                                            </li>
                                                        ))}
                                                    </ul>
                                                </div>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            ) : (
                <div className="flex-1 flex flex-col items-center justify-center text-slate-300 p-8 select-none bg-white">
                    <div className="relative mb-6">
                        <div className="w-32 h-32 bg-slate-50 rounded-full flex items-center justify-center shadow-inner border border-slate-100">
                            <BookOpen className="w-14 h-14 text-slate-200"/>
                        </div>
                        <div className="absolute -bottom-2 -right-2 bg-emerald-500 text-white p-3 rounded-2xl shadow-lg animate-bounce">
                            <Search className="w-5 h-5"/>
                        </div>
                    </div>
                    <h3 className="text-2xl font-black uppercase tracking-tighter text-slate-400">Biblioteca Clínica v22</h3>
                    <p className="text-sm font-medium text-slate-400 mt-2 text-center max-w-xs">Búsqueda científica avanzada en protocolos de enfermería basados en evidencia.</p>
                </div>
            )}
        </div>

        {/* New Pathology Modal */}
        {showNewModal && (
            <div className="fixed inset-0 z-[100] bg-slate-900/80 backdrop-blur-sm flex items-center justify-center p-4">
                <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-3xl max-h-[90vh] overflow-hidden flex flex-col animate-fade-in-up">
                    <div className="bg-slate-900 p-6 flex justify-between items-center shrink-0 border-b border-white/5">
                        <div className="flex items-center gap-4">
                            <div className="bg-indigo-600 p-3 rounded-2xl text-white shadow-xl shadow-indigo-900/20"><Plus className="w-6 h-6"/></div>
                            <div><h3 className="text-xl font-black text-white tracking-tight">Registro de Patología</h3><p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em]">Personalización de biblioteca local</p></div>
                        </div>
                        <button onClick={() => setShowNewModal(false)} className="text-slate-400 hover:text-white bg-slate-800 p-2.5 rounded-full transition-colors"><X className="w-5 h-5"/></button>
                    </div>
                    <div className="flex-1 overflow-y-auto p-8 space-y-8 custom-scrollbar">
                        <div className="grid md:grid-cols-2 gap-6">
                            <div className="col-span-full">
                                <label className="text-[10px] font-black text-indigo-500 uppercase block mb-2 tracking-widest">Nombre de la Patología</label>
                                <input value={newPathologyForm.name} onChange={e => setNewPathologyForm({...newPathologyForm, name: e.target.value})} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-4 text-base font-bold outline-none focus:bg-white focus:border-indigo-500/30 transition-all shadow-inner" placeholder="Ej: Insuficiencia Cardíaca"/>
                            </div>
                            <div>
                                <label className="text-[10px] font-black text-slate-400 uppercase block mb-2 tracking-widest">Familia / Especialidad</label>
                                <input value={newPathologyForm.family} onChange={e => setNewPathologyForm({...newPathologyForm, family: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-sm font-bold outline-none" placeholder="Cardiología"/>
                            </div>
                            <div>
                                <label className="text-[10px] font-black text-slate-400 uppercase block mb-2 tracking-widest">CIE-10 (Opcional)</label>
                                <input value={newPathologyForm.cie10} onChange={e => setNewPathologyForm({...newPathologyForm, cie10: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-sm font-bold outline-none" placeholder="I50.9"/>
                            </div>
                            <div className="col-span-full">
                                <label className="text-[10px] font-black text-slate-400 uppercase block mb-2">Definición</label>
                                <textarea value={newPathologyForm.generalInfo?.definition} onChange={e => setNewPathologyForm({...newPathologyForm, generalInfo: { ...newPathologyForm.generalInfo!, definition: e.target.value }})} className="w-full bg-slate-50 border border-slate-200 rounded-2xl p-4 text-sm font-medium h-24 outline-none resize-none" placeholder="Descripción breve de la patología..."/>
                            </div>
                        </div>
                    </div>
                    <div className="p-6 bg-slate-50 border-t border-slate-200 shrink-0">
                        <button onClick={handleSaveNewPathology} className="w-full bg-slate-900 hover:bg-black text-white py-5 rounded-3xl font-black uppercase tracking-widest shadow-2xl active:scale-95 transition-all flex items-center justify-center gap-3"><Save className="w-5 h-5 text-emerald-400"/> GUARDAR EN BIBLIOTECA</button>
                    </div>
                </div>
            </div>
        )}
    </div>
  );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Patient, Evolution, ClinicalAnalysis, ChatMessage } from '../types';
import { analyzeClinicalNote, generateChatReply, FlorenceResponse } from '../services/geminiService';
import { PatientService } from '../services/firebaseMock';
import { ClipboardList, Search, User, AlertCircle, Monitor, Pill, BookOpen, FlaskConical, Cable, Megaphone, Ruler, PenTool, Activity, ShieldAlert, ArrowLeft, Bot, Send, X, Globe, Sparkles, Loader2, ChevronRight, Camera, Mic, Volume2, ShieldCheck, ExternalLink, Calendar, Clock, AlertTriangle, UserPlus, CheckCircle2 } from 'lucide-react';
import { VoiceInput } from './VoiceInput';
import { CameraCapture } from './CameraCapture';
import { WoundAnalysis } from './WoundAnalysis';
import { MedicationSheet } from './MedicationSheet';
import { VitalSigns } from './VitalSigns';
import { AccessManager } from './AccessManager';
import { LabResults } from './LabResults';
import { CarePlanManager } from './CarePlanManager';
import { ShiftHandoff } from './ShiftHandoff';
import { AdmissionModal } from './AdmissionModal';

const CLINICAL_MODULES = [
    { id: 'NOTES', label: 'Evolución', icon: PenTool, color: 'text-indigo-600' },
    { id: 'MONITOR', label: 'Monitor', icon: Monitor, color: 'text-emerald-600' },
    { id: 'MEDS', label: 'Fármacos', icon: Pill, color: 'text-blue-600' },
    { id: 'PAE', label: 'PAE', icon: BookOpen, color: 'text-violet-600' },
    { id: 'LABS', label: 'Laboratorio', icon: FlaskConical, color: 'text-purple-600' },
    { id: 'ACCESS', label: 'Disp.', icon: Cable, color: 'text-orange-600' },
    { id: 'WOUNDS', label: 'Heridas', icon: Ruler, color: 'text-rose-600' },
    { id: 'HANDOFF', label: 'Pase', icon: Megaphone, color: 'text-amber-600' },
] as const;

export const ClinicalFollowUp: React.FC = () => {
    const [patients, setPatients] = useState<Patient[]>([]);
    const [selectedPatientId, setSelectedPatientId] = useState<string | null>(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [detailTab, setDetailTab] = useState<string>('NOTES');
    const [isFlorenceOpen, setIsFlorenceOpen] = useState(false);

    const [showCamera, setShowCamera] = useState(false);
    const [showAdmissionModal, setShowAdmissionModal] = useState(false);
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [analysisResult, setAnalysisResult] = useState<ClinicalAnalysis | null>(null);
    const [noteText, setNoteText] = useState('');

    const [florenceMessages, setFlorenceMessages] = useState<ChatMessage[]>([]);
    const [florenceInput, setFlorenceInput] = useState('');
    const [isFlorenceTyping, setIsFlorenceTyping] = useState(false);

    const loadData = async () => {
        const data = await PatientService.getAll();
        setPatients(data);
    };

    useEffect(() => { loadData(); }, []);

    const selectedPatient = useMemo(() => patients.find(p => p.id === selectedPatientId), [patients, selectedPatientId]);

    const filteredPatients = useMemo(() => {
        const term = (searchTerm || '').toLowerCase().trim();
        return patients.filter(p => 
            (p.name || '').toLowerCase().includes(term) || 
            (p.bed || '').toLowerCase().includes(term) ||
            (p.diagnosis || '').toLowerCase().includes(term)
        );
    }, [patients, searchTerm]);

    const groupedHistory = useMemo(() => {
        if (!selectedPatient?.history) return {};
        const groups: Record<string, Evolution[]> = {};
        selectedPatient.history.forEach(h => {
            let label = new Date(h.timestamp).toLocaleDateString([], {day: 'numeric', month: 'long'});
            if (new Date(h.timestamp).toDateString() === new Date().toDateString()) label = 'Hoy';
            if (!groups[label]) groups[label] = [];
            groups[label].push(h);
        });
        return groups;
    }, [selectedPatient]);

    const handleSaveNote = async () => {
        if (!selectedPatientId || !noteText.trim()) return;
        const newNote: Evolution = {
            id: `ev-${Date.now()}`,
            timestamp: new Date().toISOString(),
            note: noteText,
            type: 'EVOLUTION',
            analysis: analysisResult || undefined
        };
        await PatientService.addEvolution(selectedPatientId, newNote);
        await loadData();
        setNoteText('');
        setAnalysisResult(null);
    };

    const handleAnalyzeNote = async () => {
        if (!noteText.trim()) return;
        setIsAnalyzing(true);
        try {
            const result = await analyzeClinicalNote(noteText);
            setAnalysisResult(result);
        } catch(e) { console.error(e); }
        finally { setIsAnalyzing(false); }
    };

    const handleFlorenceSend = async (textOverride?: string) => {
        const text = textOverride || florenceInput;
        if(!text.trim() || !selectedPatient) return;

        const userMsg: ChatMessage = { id: Date.now().toString(), userId: 'me', userName: 'Yo', role: 'NURSE', text: text, timestamp: new Date().toISOString() };
        setFlorenceMessages(prev => [...prev, userMsg]);
        setFlorenceInput('');
        setIsFlorenceTyping(true);

        try {
            const response = await generateChatReply(text, 'MENTOR', selectedPatient);
            const aiMsg: ChatMessage = {
                id: 'ai-' + Date.now(), userId: 'florence', userName: 'Florence AI', role: 'ADMIN',
                text: JSON.stringify(response), timestamp: new Date().toISOString(), isSystem: true
            };
            setFlorenceMessages(prev => [...prev, aiMsg]);
        } catch(e) { console.error(e); }
        finally { setIsFlorenceTyping(false); }
    };

    return (
        <div className="flex h-full flex-col bg-slate-100 overflow-hidden font-sans">
            <header className="bg-slate-900 text-white border-b border-slate-800 px-6 py-4 flex justify-between items-center z-20 shadow-xl shrink-0">
                <div className="flex items-center gap-3">
                    <div className="bg-indigo-600 p-2 rounded-xl"><ClipboardList className="w-5 h-5"/></div>
                    <div>
                        <h1 className="text-lg font-black tracking-tight uppercase">Hospital OS <span className="text-indigo-400">Clinical v22</span></h1>
                        <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Unidad de Vigilancia</p>
                    </div>
                </div>
                <button onClick={() => setShowAdmissionModal(true)} className="bg-emerald-600 hover:bg-emerald-700 text-white px-5 py-2.5 rounded-xl text-xs font-black shadow-lg transition-all active:scale-95 border border-emerald-500">
                    <UserPlus className="w-4 h-4 mr-2"/> ADMITIR
                </button>
            </header>

            <div className="flex-1 flex overflow-hidden">
                <div className={`${selectedPatientId ? 'hidden lg:flex w-96' : 'flex w-full'} flex-col bg-white border-r border-slate-200 z-10 shadow-xl shrink-0`}>
                    <div className="p-5 border-b border-slate-100 bg-white">
                        <div className="relative">
                            <Search className="absolute left-4 top-3.5 w-4 h-4 text-slate-400"/>
                            <input value={searchTerm} onChange={e => setSearchTerm(e.target.value)} placeholder="Buscar por nombre o cama..." className="w-full pl-11 pr-4 py-3 rounded-2xl bg-slate-50 border border-slate-200 text-sm font-bold focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all"/>
                        </div>
                    </div>
                    <div className="flex-1 overflow-y-auto p-3 space-y-3 bg-slate-50/50 custom-scrollbar">
                        {filteredPatients.map(patient => (
                            <button key={patient.id} onClick={() => setSelectedPatientId(patient.id)} className={`w-full text-left p-4 rounded-2xl border transition-all flex items-center justify-between ${selectedPatientId === patient.id ? 'bg-white border-indigo-500 ring-2 ring-indigo-50 shadow-xl' : 'bg-white border-slate-200 hover:border-indigo-300 shadow-sm'}`}>
                                <div className="flex-1 min-w-0">
                                    <div className="flex justify-between items-center mb-1">
                                        <span className="font-black text-sm text-slate-800 truncate pr-2 uppercase">{patient.name}</span>
                                        <span className="text-[10px] font-black bg-slate-900 text-white px-2 py-0.5 rounded">{patient.bed}</span>
                                    </div>
                                    <p className="text-[10px] text-slate-500 font-bold uppercase truncate">{patient.diagnosis}</p>
                                    <div className={`mt-2 inline-block px-2 py-0.5 rounded text-[9px] font-black uppercase ${patient.risk === 'HIGH' ? 'bg-rose-50 text-rose-600' : 'bg-emerald-50 text-emerald-600'}`}>NEWS2 {patient.news2}</div>
                                </div>
                                <ChevronRight className="w-5 h-5 text-slate-300 ml-3"/>
                            </button>
                        ))}
                    </div>
                </div>

                {selectedPatient ? (
                    <div className="flex-1 flex flex-col bg-slate-50 relative overflow-hidden h-full">
                        <div className="bg-white border-b border-slate-200 shadow-sm p-4 md:p-6 shrink-0 z-10">
                            <div className="flex justify-between items-start gap-4">
                                <div className="flex items-center gap-4 min-w-0">
                                    <button onClick={() => setSelectedPatientId(null)} className="lg:hidden p-2.5 bg-slate-100 rounded-full text-slate-500"><ArrowLeft className="w-5 h-5"/></button>
                                    <div>
                                        <div className="flex items-center gap-3"><h2 className="text-xl md:text-2xl font-black text-slate-900 uppercase tracking-tighter truncate">{selectedPatient.name}</h2><span className="bg-indigo-600 text-white text-[10px] font-black px-2 py-1 rounded-lg">{selectedPatient.bed}</span></div>
                                        <div className="flex gap-3 text-xs font-bold text-slate-400 uppercase mt-1"><span>{selectedPatient.age} Años</span><span>{selectedPatient.weight} kg</span><span className="text-rose-500 flex items-center gap-1"><ShieldAlert className="w-3.5 h-3.5"/> {selectedPatient.allergies}</span></div>
                                    </div>
                                </div>
                                <button onClick={() => setIsFlorenceOpen(true)} className="bg-gradient-to-tr from-violet-600 to-indigo-700 text-white p-3 rounded-2xl shadow-xl active:scale-95 transition-all"><Bot className="w-7 h-7"/></button>
                            </div>
                            <div className="flex gap-2 mt-6 overflow-x-auto no-scrollbar scroll-smooth">{CLINICAL_MODULES.map(m => (
                                <button key={m.id} onClick={() => setDetailTab(m.id)} className={`px-4 py-2.5 rounded-xl text-xs font-black uppercase tracking-wider transition-all flex items-center whitespace-nowrap border-2 ${detailTab === m.id ? `bg-slate-900 text-white border-slate-900 shadow-xl` : 'bg-white text-slate-500 border-slate-100 hover:border-slate-200 hover:bg-slate-50'}`}>
                                    <m.icon className={`w-4 h-4 mr-2 ${detailTab === m.id ? 'text-indigo-400' : m.color}`}/> {m.label}
                                </button>
                            ))}</div>
                        </div>

                        <div className="flex-1 overflow-y-auto p-4 md:p-8 bg-slate-50/50 custom-scrollbar pb-32">
                            <div className="max-w-5xl mx-auto">
                                {detailTab === 'NOTES' && (
                                    <div className="space-y-8 animate-fade-in">
                                        <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-xl relative overflow-hidden">
                                            <div className="flex justify-between items-center mb-6"><h3 className="text-xs font-black text-slate-800 uppercase tracking-widest flex items-center"><PenTool className="w-4 h-4 mr-2 text-indigo-600"/> Evolución Enfermera</h3><div className="flex gap-2"><VoiceInput onTranscript={t => setNoteText(prev => prev + " " + t)} isCompact /><button onClick={() => setShowCamera(true)} className="p-2 bg-slate-100 rounded-full text-slate-500 hover:text-indigo-600"><Camera className="w-5 h-5"/></button></div></div>
                                            <textarea value={noteText} onChange={e => setNoteText(e.target.value)} placeholder="Registre el estado del paciente..." className="w-full min-h-[160px] bg-slate-50/50 border-2 border-transparent rounded-3xl p-6 text-base font-bold text-slate-700 focus:bg-white focus:border-indigo-500/30 outline-none resize-none transition-all mb-6"/>
                                            <div className="flex justify-between items-center pt-6 border-t border-slate-100">
                                                <button onClick={handleAnalyzeNote} disabled={!noteText.trim() || isAnalyzing} className="text-xs font-black text-indigo-600 flex items-center hover:bg-indigo-50 px-6 py-3 rounded-2xl transition-all disabled:opacity-50">{isAnalyzing ? <Loader2 className="w-5 h-5 animate-spin mr-2"/> : <Sparkles className="w-5 h-5 mr-2"/>} ANÁLISIS IA</button>
                                                <button onClick={handleSaveNote} disabled={!noteText.trim()} className="bg-slate-900 text-white px-10 py-4 rounded-2xl text-xs font-black uppercase tracking-widest shadow-2xl active:scale-95 transition-all">REGISTRAR EVOLUCIÓN</button>
                                            </div>
                                        </div>
                                        <div className="space-y-8">{Object.entries(groupedHistory).map(([date, entries]) => (
                                            <div key={date} className="relative">
                                                <div className="sticky top-0 z-10 py-3 mb-6 bg-slate-50/90 backdrop-blur-xl flex items-center gap-4"><div className="bg-slate-200 px-3 py-1 rounded-xl text-[10px] font-black text-slate-600 uppercase tracking-widest border border-slate-300">{date}</div><div className="h-px bg-slate-300 flex-1"></div></div>
                                                <div className="space-y-6 relative ml-4 border-l-4 border-slate-200 pl-10">
                                                    {entries.map(h => (
                                                        <div key={h.id} className="relative bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm group">
                                                            <div className="absolute -left-[45px] top-6 w-5 h-5 bg-white border-4 border-indigo-600 rounded-full z-10 shadow-md"></div>
                                                            <div className="flex justify-between items-start mb-3"><span className="text-[11px] font-black text-indigo-600 uppercase bg-indigo-50 px-2 py-1 rounded-lg flex items-center gap-1.5"><Clock className="w-4 h-4"/> {new Date(h.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span></div>
                                                            <p className="text-sm font-medium text-slate-700 leading-relaxed whitespace-pre-wrap">{h.note}</p>
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                        ))}</div>
                                    </div>
                                )}
                                {detailTab === 'MONITOR' && <VitalSigns history={selectedPatient.history} />}
                                {detailTab === 'MEDS' && <MedicationSheet prescriptions={selectedPatient.prescriptions || []} onUpdate={p => PatientService.updatePatient(selectedPatient.id, {prescriptions: p}).then(loadData)} />}
                                {detailTab === 'PAE' && <CarePlanManager carePlans={selectedPatient.activePae || []} onUpdate={p => PatientService.updatePatient(selectedPatient.id, {activePae: p}).then(loadData)} />}
                                {detailTab === 'LABS' && <LabResults reports={selectedPatient.labReports || []} />}
                                {detailTab === 'ACCESS' && <AccessManager devices={selectedPatient.activeDevices || []} onUpdate={d => PatientService.updatePatient(selectedPatient.id, {activeDevices: d}).then(loadData)} />}
                                {detailTab === 'WOUNDS' && <WoundAnalysis wounds={selectedPatient.wounds || []} onAddWound={w => PatientService.updatePatient(selectedPatient.id, {wounds: [w, ...(selectedPatient.wounds||[])]}).then(loadData)} />}
                                {detailTab === 'HANDOFF' && <ShiftHandoff patient={selectedPatient} onSendToChat={handleFlorenceSend} />}
                            </div>
                        </div>
