            )}

            {showAdmissionModal && <AdmissionModal onClose={() => setShowAdmissionModal(false)} onSave={async (p) => { await PatientService.admitPatient(p); await loadData(); setShowAdmissionModal(false); }} />}
            {showCamera && <CameraCapture mode="PHOTO" onCapture={url => alert("Imagen capturada: " + url)} onClose={() => setShowCamera(false)} />}
        </div>
    );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Patient, Evolution, ClinicalAnalysis, ChatMessage } from '../types';
import { analyzeClinicalNote, generateChatReply, FlorenceResponse } from '../services/geminiService';
import { PatientService } from '../services/firebaseMock';
import { ClipboardList, Search, User, AlertCircle, Monitor, Pill, BookOpen, FlaskConical, Cable, Megaphone, Ruler, PenTool, Activity, ShieldAlert, ArrowLeft, Bot, Send, X, Globe, Sparkles, Loader2, ChevronRight, Camera, Mic, Volume2, ShieldCheck, ExternalLink, Calendar, Clock, AlertTriangle, UserPlus, CheckCircle2 } from 'lucide-react';
import { VoiceInput } from './VoiceInput';
import { CameraCapture } from './CameraCapture';
