            </div>
            <div className="ml-2 bg-slate-50 p-2 rounded-lg group-hover:bg-indigo-100 transition-colors">
                <ChevronRight className="w-4 h-4 text-slate-300 group-hover:text-indigo-500"/>
            </div>
        </button>
    );
});

export const Pathologies: React.FC<PathologiesProps> = ({ initialQuery, initialCategory, onNavigate }) => {
  const [query, setQuery] = useState(initialQuery || '');
  const [filterQuery, setFilterQuery] = useState(initialQuery || '');
  const [selectedCategory, setSelectedCategory] = useState<string>(initialCategory || 'ALL');
  const [selectedPathology, setSelectedPathology] = useState<Pathology | null>(null);
  const [loading, setLoading] = useState(false);
  const [isGeneratingInModal, setIsGeneratingInModal] = useState(false);
  const [activeTab, setActiveTab] = useState<'CLINICAL' | 'PHARMA' | 'PAE'>('CLINICAL');
  const [viewMode, setViewMode] = useState<'AZ' | 'GROUP'>('GROUP');
  const [customPathologies, setCustomPathologies] = useState<Pathology[]>([]);
  const [showNewModal, setShowNewModal] = useState(false);
  const [newPathologyForm, setNewPathologyForm] = useState<Partial<Pathology>>({
      name: '', family: 'General', generalInfo: { definition: '', etiology: '', signsSymptoms: [] }
  });

  const loadCustomData = async () => {
      const data = await PathologyService.getAll();
      setCustomPathologies(data);
  };

  useEffect(() => { loadCustomData(); }, []);

  useEffect(() => {
      const timer = setTimeout(() => setFilterQuery(query), 300);
      return () => clearTimeout(timer);
  }, [query]);

  const organizedList = useMemo(() => {
      const q = (filterQuery || '').toLowerCase().trim();
      let activeItems = [...FLATTENED_STATIC_CATALOG];

      customPathologies.forEach(p => {
          activeItems.push({
              name: p.name,
              category: p.family || 'Personalizado',
              icon: BookOpen,
              color: 'text-indigo-600',
              bg: 'bg-indigo-50',
              isCustom: true,
              score: 0,
              pathology: p
          } as any);
      });

      let filtered = activeItems;
      if (q) {
          filtered = activeItems.reduce((acc: any[], item) => {
              let score = 0;
              const n = (item.name || '').toLowerCase();
              if (n === q) score = 100;
              else if (n.startsWith(q)) score = 80;
              else if (n.includes(q)) score = 50;
              if (score > 0) acc.push({ ...item, score });
              return acc;
          }, []).sort((a: any, b: any) => b.score - a.score);
      } else if (selectedCategory !== 'ALL') {
          filtered = activeItems.filter(i => i.category === selectedCategory);
      }

      const grouped: Record<string, any[]> = {};
      if (viewMode === 'AZ') {
          filtered.sort((a,b) => (a.name || '').localeCompare(b.name || '')).forEach(item => {
              const letter = (item.name || '#').charAt(0).toUpperCase();
              if(!grouped[letter]) grouped[letter] = [];
              grouped[letter].push(item);
          });
      } else {
          filtered.forEach(item => {
              const cat = item.category || 'Otros';
              if(!grouped[cat]) grouped[cat] = [];
              grouped[cat].push(item);
          });
      }
      return grouped;
  }, [filterQuery, selectedCategory, viewMode, customPathologies]);

  const sortedKeys = Object.keys(organizedList).sort();

  const handleSelectPathology = async (item: any) => {
      if (item.pathology) {
          setSelectedPathology(item.pathology);
          setActiveTab('CLINICAL');
          return;
      }
      setLoading(true);
      try {
          const result = await generatePathology(item.name);
          setSelectedPathology(result);
          setActiveTab('CLINICAL');
      } catch (e) { console.error(e); }
      finally { setLoading(false); }
  };

  const handleGeneratePathologyWithAI = async () => {
    if (!newPathologyForm.name) return;
    setIsGeneratingInModal(true);
    try {
        const result = await generatePathology(newPathologyForm.name);
        setNewPathologyForm({
            ...result,
            name: newPathologyForm.name
        });
    } catch (e) {
        console.error("AI Generation failed", e);
    } finally {
        setIsGeneratingInModal(false);
    }
  };

  const handleSaveNewPathology = async () => {
      if (!newPathologyForm.name) return;
      const path: Pathology = {
          ...newPathologyForm as Pathology,
          id: `path-${Date.now()}`,
          pae: newPathologyForm.pae || { nanda: [], nic: [], noc: [] },
          pharmacology: newPathologyForm.pharmacology || []
      };
      await PathologyService.add(path);
      await loadCustomData();
      setShowNewModal(false);
      setNewPathologyForm({ name: '', family: 'General', generalInfo: { definition: '', etiology: '', signsSymptoms: [] } });
  };

  const handleDelete = async (id: string) => {
      if (confirm("¿Eliminar esta guía de la biblioteca personal?")) {
          await PathologyService.delete(id);
          await loadCustomData();
          setSelectedPathology(null);
      }
  };

  return (
    <div className="flex h-full bg-slate-100 overflow-hidden font-sans">
        <div className={`w-full md:w-[450px] bg-white border-r border-slate-200 flex flex-col h-full shrink-0 z-10 shadow-xl ${selectedPathology || loading ? 'hidden md:flex' : 'flex'}`}>
            <div className="p-4 bg-slate-900 text-white shrink-0">
                <div className="flex justify-between items-center mb-4">
                    <h2 className="font-black text-xs uppercase tracking-widest text-emerald-400 flex items-center"><BookOpen className="w-4 h-4 mr-2"/> Biblioteca v22</h2>
                    <button onClick={() => setShowNewModal(true)} className="bg-indigo-600 hover:bg-indigo-700 text-white p-2 rounded-xl transition-all shadow-lg active:scale-95 flex items-center gap-1">
                        <Plus className="w-4 h-4"/><span className="text-[10px] font-black uppercase pr-1">Nueva</span>
                    </button>
                </div>
                <div className="relative group">
                    <Search className="absolute left-3 top-3 text-slate-500 w-4 h-4"/>
                    <input 
                        type="text" 
                        value={query}
                        onChange={e => setQuery(e.target.value)}
                        placeholder="Buscar patología..." 
                        className="w-full pl-10 pr-10 py-3 bg-slate-800 border border-slate-700 rounded-xl text-sm font-bold text-white focus:border-emerald-500 outline-none transition-all"
                    />
                </div>
            </div>
            <div className="flex-1 overflow-y-auto custom-scrollbar p-2 bg-slate-50">
                {sortedKeys.map(key => (
                    <div key={key} className="mb-4">
                        <div className="sticky top-0 bg-slate-100/95 backdrop-blur z-10 py-1.5 px-2 text-[10px] font-black text-slate-500 uppercase tracking-widest border-b border-slate-200 mb-2 flex justify-between items-center">
                            <span>{key}</span>
                            <span className="opacity-50">{organizedList[key].length}</span>
                        </div>
                        <div className="space-y-2">
                            {organizedList[key].map((item, idx) => (
                                <PathologyRow key={idx} item={item} isSelected={selectedPathology?.name === item.name} onClick={handleSelectPathology} />
                            ))}
                        </div>
                    </div>
                ))}
            </div>
        </div>

        <div className={`flex-1 bg-white flex flex-col h-full overflow-hidden ${!selectedPathology && !loading ? 'hidden md:flex' : 'flex'}`}>
            {loading ? (
                <div className="flex-1 flex flex-col items-center justify-center p-8 bg-slate-50 animate-fade-in">
                    <div className="relative">
                        <Loader2 className="w-16 h-16 text-emerald-500 animate-spin mb-4"/>
                        <Sparkles className="w-6 h-6 text-indigo-500 absolute top-5 left-5 animate-pulse"/>
                    </div>
                    <h3 className="font-black text-slate-800 text-xl tracking-tight">Compilando Guía Clínica...</h3>
                    <p className="text-sm text-slate-400 font-medium mt-1">Soporte IA PAESYS habilitado</p>
                </div>
            ) : selectedPathology ? (
                <div className="flex flex-col h-full animate-fade-in bg-slate-50">
                    <div className="bg-white border-b border-slate-200 p-6 shadow-sm sticky top-0 z-10">
                        <div className="flex items-start gap-4">
                            <button onClick={() => setSelectedPathology(null)} className="md:hidden p-2 bg-slate-100 rounded-full"><ArrowLeft className="w-5 h-5"/></button>
                            <div className="flex-1 min-w-0">
                                <div className="flex items-center gap-2 mb-2">
                                    <span className="bg-indigo-50 text-indigo-700 text-[9px] font-black px-2 py-0.5 rounded border border-indigo-100 uppercase inline-block">{selectedPathology.family || 'Clínica General'}</span>
                                    {selectedPathology.id?.startsWith('path-') && <span className="bg-emerald-50 text-emerald-700 text-[9px] font-black px-2 py-0.5 rounded border border-emerald-100 uppercase inline-block">LOCAL</span>}
                                </div>
                                <h1 className="text-2xl md:text-4xl font-black text-slate-900 leading-tight uppercase tracking-tighter truncate">{selectedPathology.name}</h1>
                            </div>
                            {selectedPathology.id?.startsWith('path-') && (
                                <button onClick={() => handleDelete(selectedPathology.id!)} className="p-3 bg-rose-50 text-rose-400 rounded-xl border border-rose-100 hover:text-rose-600 transition-colors">
                                    <Trash2 className="w-5 h-5"/>
                                </button>
                            )}
                        </div>
                        <div className="flex gap-2 mt-6 overflow-x-auto no-scrollbar">
                            {['CLINICAL', 'PHARMA', 'PAE'].map(t => (
                                <button key={t} onClick={() => setActiveTab(t as any)} className={`px-5 py-2.5 rounded-xl text-[10px] font-black transition-all border-2 uppercase tracking-widest whitespace-nowrap ${activeTab === t ? 'bg-slate-900 text-white border-slate-900 shadow-xl' : 'bg-white text-slate-500 border-slate-100 hover:border-slate-200 hover:bg-slate-50'}`}>
                                    {t === 'CLINICAL' ? 'Fisiopatología' : t === 'PHARMA' ? 'Tratamiento' : 'Plan de Cuidados'}
                                </button>
                            ))}
                        </div>
                    </div>
                    <div className="flex-1 overflow-y-auto p-6 md:p-10 custom-scrollbar bg-slate-50/50 pb-32">
                        <div className="max-w-4xl mx-auto space-y-8">
                            {activeTab === 'CLINICAL' && (
                                <div className="space-y-6 animate-fade-in">
                                    <div className="bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-sm relative overflow-hidden group">
                                        <div className="absolute top-0 right-0 p-8 opacity-5 group-hover:opacity-10 transition-opacity"><BookOpen className="w-24 h-24 text-indigo-900"/></div>
                                        <h3 className="text-xs font-black text-indigo-700 uppercase tracking-[0.2em] mb-4 flex items-center"><GraduationCap className="w-4 h-4 mr-2"/> Definición Clínica</h3>
                                        <p className="text-base font-bold text-slate-700 leading-relaxed relative z-10">{selectedPathology.generalInfo?.definition}</p>
                                    </div>
                                    <div className="grid md:grid-cols-2 gap-6">
                                        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                                            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center"><Activity className="w-4 h-4 mr-2 text-rose-500"/> Etiología / Causas</h3>
                                            <p className="text-sm font-bold text-slate-700 leading-relaxed">{selectedPathology.generalInfo?.etiology}</p>
                                        </div>
                                        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                                            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center"><Eye className="w-4 h-4 mr-2 text-cyan-500"/> Signos y Síntomas</h3>
                                            <div className="flex flex-wrap gap-2">
                                                {selectedPathology.generalInfo?.signsSymptoms?.map((s,i) => <span key={i} className="px-3 py-1.5 bg-slate-50 text-slate-700 text-[10px] font-black rounded-xl border border-slate-200 uppercase tracking-tight">• {s}</span>)}
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            )}
                            {activeTab === 'PHARMA' && (
                                <div className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden animate-fade-in shadow-xl">
                                    <div className="bg-slate-900 px-8 py-5 border-b border-slate-800 flex justify-between items-center">
                                        <h3 className="text-xs font-black text-emerald-400 uppercase tracking-widest flex items-center"><Pill className="w-4 h-4 mr-2"/> Terapia Farmacológica</h3>
                                        <span className="text-[9px] font-black text-slate-500 uppercase">{selectedPathology.pharmacology?.length || 0} pautas sugeridas</span>
                                    </div>
                                    <div className="divide-y divide-slate-100">{selectedPathology.pharmacology?.map((p,i) => (
                                        <div key={i} className="p-6 flex flex-col md:flex-row gap-6 hover:bg-slate-50 transition-colors">
                                            <div className="md:w-1/3">
                                                <div className="text-[9px] font-black text-indigo-500 uppercase mb-1 tracking-widest">{p.group}</div>
                                                <div className="text-base font-black text-slate-800">{p.drug}</div>
                                            </div>
                                            <div className="flex-1 bg-slate-100/50 p-4 rounded-2xl border border-slate-200/50">
                                                <div className="text-[9px] font-black text-slate-400 uppercase mb-2">Efecto / Mecanismo</div>
                                                <div className="text-sm font-bold text-slate-600 italic leading-relaxed">"{p.effect}"</div>
                                            </div>
                                        </div>
                                    ))}</div>
                                </div>
                            )}
                            {activeTab === 'PAE' && (
                                <div className="space-y-6 animate-fade-in">
                                    {selectedPathology.pae?.nanda?.map((dx, i) => (
                                        <div key={i} className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden">
                                            <div className="bg-indigo-600 text-white p-6 shadow-lg shadow-indigo-600/20">
                                                <div className="flex items-center gap-2 mb-2">
                                                    <span className="text-[9px] font-black uppercase text-white/70 tracking-widest border border-white/20 px-2 py-0.5 rounded">NANDA {dx.code}</span>
                                                </div>
                                                <h4 className="font-black text-lg md:text-xl tracking-tight leading-tight">{dx.label}</h4>
                                                <p className="text-xs text-indigo-100 font-bold mt-2 italic opacity-80">r/c {dx.relatedTo}</p>
                                            </div>
                                            <div className="grid md:grid-cols-2 divide-y md:divide-y-0 md:divide-x divide-slate-100">
