import { TeamChat } from './TeamChat';

interface LayoutProps {
  children: React.ReactNode;
  currentView: ViewState;
  onChangeView: (view: ViewState, params?: ViewParams) => void;
  onBack: () => void;
  currentUser: User | null; 
