                                                >
                                                    <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center mr-4 shrink-0 transition-colors ${isChecked ? 'bg-emerald-500 border-emerald-500 text-white shadow-sm' : 'border-slate-300 group-hover:border-emerald-400'}`}>
                                                        {isChecked && <CheckSquare className="w-4 h-4"/>}
