                                                    <span className={`text-sm font-black transition-colors ${isChecked ? 'text-emerald-800 line-through opacity-60' : 'text-slate-700'}`}>{mat}</span>

                                                    {isChecked && (
                                                        <div className="absolute right-4 text-[10px] font-black text-emerald-400 uppercase tracking-widest animate-fade-in">Listo</div>
                                                    )}
                                                </button>
                                            );
                                        })}
                                    </div>

                                    <div className="bg-slate-900 text-white p-6 rounded-3xl shadow-xl relative overflow-hidden group">
