                                        <button 
                                            onClick={() => setActiveDetailTab('STEPS')}
                                            className="w-full bg-emerald-600 hover:bg-emerald-700 text-white py-3 rounded-xl font-black text-xs uppercase tracking-widest shadow-lg active:scale-95 transition-all flex items-center justify-center gap-2"
                                        >
                                            <ArrowRight className="w-4 h-4"/> Iniciar Intervención
                                        </button>
                                    </div>
                                </div>
                            )}

                            {/* 2. STEPS VIEW */}
