                                                {selectedProcedure.redFlags.map((flag, i) => (
                                                    <li key={i} className="text-xs font-bold text-rose-800 flex items-start gap-3">
                                                        <AlertTriangle className="w-4 h-4 mt-0.5 shrink-0 text-rose-500"/> {flag}
                                                    </li>
                                                ))}
                                            </ul>
                                        </div>
                                    )}

                                    {/* Description */}
