  const organizedList = useMemo(() => {
      const q = (filterQuery || '').toLowerCase().trim();
      let activeItems = [...FLATTENED_STATIC_CATALOG];

      customPathologies.forEach(p => {
          activeItems.push({
              name: p.name,
              category: p.family || 'Personalizado',
              icon: User,
              color: 'text-indigo-600',
              bg: 'bg-indigo-50',
              isCustom: true,
              score: 0,
              pathology: p
          } as any);
      });

      let filtered = activeItems;
      if (q) {
          filtered = activeItems.reduce((acc: any[], item) => {
              let score = 0;
              const n = (item.name || '').toLowerCase();
              const c = (item.category || '').toLowerCase();
              if (n === q) score = 100;
              else if (n.startsWith(q)) score = 80;
              else if (n.includes(q)) score = 50;
              else if (c.includes(q)) score = 20;

              if (score > 0) acc.push({ ...item, score });
              return acc;
          }, []).sort((a: any, b: any) => b.score - a.score);
      } else if (selectedCategory !== 'ALL') {
          filtered = activeItems.filter(i => i.category === selectedCategory);
      }

      const grouped: Record<string, any[]> = {};
      if (viewMode === 'AZ') {
          filtered.sort((a,b) => (a.name || '').localeCompare(b.name || '')).forEach(item => {
              const letter = (item.name || '#').charAt(0).toUpperCase();
              if(!grouped[letter]) grouped[letter] = [];
              grouped[letter].push(item);
          });
      } else {
          filtered.forEach(item => {
              const cat = item.category || 'Otros';
              if(!grouped[cat]) grouped[cat] = [];
              grouped[cat].push(item);
          });
      }
      return grouped;
  }, [filterQuery, selectedCategory, viewMode, customPathologies]);

  const sortedKeys = Object.keys(organizedList).sort();

  const handleSelectPathology = async (item: any) => {
      if (item.pathology) {
          setSelectedPathology(item.pathology);
          setActiveTab('CLINICAL');
          return;
      }
      setLoading(true);
      try {
          const result = await generatePathology(item.name);
          setSelectedPathology(result);
          setActiveTab('CLINICAL');
      } catch (e) { 
          alert("Error generando ficha. Intente de nuevo.");
      } finally { 
          setLoading(false); 
      }
  };

  const handleGeneratePathologyWithAI = async () => {
    if (!newPathologyForm.name) return;
    setIsGeneratingInModal(true);
    try {
        const result = await generatePathology(newPathologyForm.name);
        setNewPathologyForm({
            ...result,
            name: newPathologyForm.name
        });
    } catch (e) {
        console.error("AI Generation failed", e);
    } finally {
        setIsGeneratingInModal(false);
    }
  };

  const handleSaveNewPathology = async () => {
