export const Pathologies: React.FC<PathologiesProps> = ({ initialQuery, initialCategory, onNavigate }) => {
  const [query, setQuery] = useState(initialQuery || '');
  const [filterQuery, setFilterQuery] = useState(initialQuery || '');
  const [selectedCategory, setSelectedCategory] = useState<string>(initialCategory || 'ALL');
  const [selectedPathology, setSelectedPathology] = useState<Pathology | null>(null);
  const [loading, setLoading] = useState(false);
  const [isGeneratingInModal, setIsGeneratingInModal] = useState(false);
  const [activeTab, setActiveTab] = useState<'CLINICAL' | 'PHARMA' | 'PAE'>('CLINICAL');
  const [viewMode, setViewMode] = useState<'AZ' | 'GROUP'>('GROUP');
  const [customPathologies, setCustomPathologies] = useState<Pathology[]>([]);
  const [showNewModal, setShowNewModal] = useState(false);
  const [newPathologyForm, setNewPathologyForm] = useState<Partial<Pathology>>({
      name: '', family: 'General', generalInfo: { definition: '', etiology: '', signsSymptoms: [] }
  });

  const loadCustomData = async () => {
      const data = await PathologyService.getAll();
      setCustomPathologies(data);
  };

  useEffect(() => { loadCustomData(); }, []);

  useEffect(() => {
      const timer = setTimeout(() => setFilterQuery(query), 200);
      return () => clearTimeout(timer);
  }, [query]);

  const organizedList = useMemo(() => {
      const q = (filterQuery || '').toLowerCase().trim();
      let activeItems = [...FLATTENED_STATIC_CATALOG];

      customPathologies.forEach(p => {
          activeItems.push({
              name: p.name,
              category: p.family || 'Personalizado',
              icon: User,
              color: 'text-indigo-600',
              bg: 'bg-indigo-50',
              isCustom: true,
              score: 0,
              pathology: p
          } as any);
      });

      let filtered = activeItems;
      if (q) {
          filtered = activeItems.reduce((acc: any[], item) => {
              let score = 0;
              const n = (item.name || '').toLowerCase();
              const c = (item.category || '').toLowerCase();
              if (n === q) score = 100;
              else if (n.startsWith(q)) score = 80;
              else if (n.includes(q)) score = 50;
              else if (c.includes(q)) score = 20;

              if (score > 0) acc.push({ ...item, score });
              return acc;
          }, []).sort((a: any, b: any) => b.score - a.score);
      } else if (selectedCategory !== 'ALL') {
          filtered = activeItems.filter(i => i.category === selectedCategory);
      }

      const grouped: Record<string, any[]> = {};
      if (viewMode === 'AZ') {
          filtered.sort((a,b) => (a.name || '').localeCompare(b.name || '')).forEach(item => {
              const letter = (item.name || '#').charAt(0).toUpperCase();
              if(!grouped[letter]) grouped[letter] = [];
              grouped[letter].push(item);
          });
      } else {
          filtered.forEach(item => {
              const cat = item.category || 'Otros';
              if(!grouped[cat]) grouped[cat] = [];
              grouped[cat].push(item);
          });
      }
      return grouped;
  }, [filterQuery, selectedCategory, viewMode, customPathologies]);

  const sortedKeys = Object.keys(organizedList).sort();

  const handleSelectPathology = async (item: any) => {
      if (item.pathology) {
          setSelectedPathology(item.pathology);
          setActiveTab('CLINICAL');
          return;
      }
      setLoading(true);
      try {
          const result = await generatePathology(item.name);
          setSelectedPathology(result);
          setActiveTab('CLINICAL');
      } catch (e) { 
          alert("Error generando ficha. Intente de nuevo.");
      } finally { 
          setLoading(false); 
      }
  };

  const handleGeneratePathologyWithAI = async () => {
    if (!newPathologyForm.name) return;
    setIsGeneratingInModal(true);
    try {
        const result = await generatePathology(newPathologyForm.name);
        setNewPathologyForm({
            ...result,
            name: newPathologyForm.name
        });
    } catch (e) {
        console.error("AI Generation failed", e);
    } finally {
        setIsGeneratingInModal(false);
    }
  };

  const handleSaveNewPathology = async () => {
      if (!newPathologyForm.name) return;
      const path: Pathology = {
          ...newPathologyForm as Pathology,
          id: `path-${Date.now()}`,
          pae: newPathologyForm.pae || { nanda: [], nic: [], noc: [] },
          pharmacology: newPathologyForm.pharmacology || []
      };
      await PathologyService.add(path);
      await loadCustomData();
      setShowNewModal(false);
      setNewPathologyForm({ name: '', family: 'General', generalInfo: { definition: '', etiology: '', signsSymptoms: [] } });
  };

  const handleDelete = async (id: string) => {
      if (confirm("¿Eliminar esta guía de la biblioteca personal?")) {
          await PathologyService.delete(id);
          await loadCustomData();
          setSelectedPathology(null);
      }
  };

  return (
    <div className="flex h-full bg-slate-100 overflow-hidden font-sans relative">
        {/* PANEL LATERAL: LISTADO */}
        <div className={`w-full md:w-[450px] bg-white border-r border-slate-200 flex flex-col h-full shrink-0 z-20 shadow-xl transition-all duration-300 ${selectedPathology || loading ? 'hidden md:flex' : 'flex'}`}>
            <div className="p-4 bg-slate-900 text-white shrink-0">
                <div className="flex justify-between items-center mb-4">
                    <div className="flex items-center gap-2">
                        <Library className="w-5 h-5 text-emerald-400"/>
                        <h2 className="font-black text-xs uppercase tracking-[0.2em] text-white">Manual Clínico v22</h2>
                    </div>
                    <button onClick={() => setShowNewModal(true)} className="bg-indigo-600 hover:bg-indigo-700 text-white p-2 rounded-xl transition-all shadow-lg active:scale-95 flex items-center gap-1 group">
                        <Plus className="w-4 h-4 group-hover:rotate-90 transition-transform"/><span className="text-[10px] font-black uppercase pr-1">Nueva</span>
                    </button>
                </div>
                <div className="relative group">
                    <Search className="absolute left-3 top-3.5 text-slate-500 w-4 h-4 group-focus-within:text-emerald-500 transition-colors"/>
                    <input 
                        type="text" 
                        value={query}
                        onChange={e => setQuery(e.target.value)}
                        placeholder="Buscar en +250 patologías..." 
                        className="w-full pl-10 pr-10 py-3.5 bg-slate-800 border border-slate-700 rounded-2xl text-sm font-bold text-white focus:border-emerald-500 focus:ring-4 focus:ring-emerald-500/10 outline-none transition-all placeholder-slate-500"
