const FLATTENED_STATIC_CATALOG = RAW_CATALOG.flatMap(cat => 
    cat.items.map(item => ({
        name: item,
        category: cat.category,
        icon: cat.icon,
        color: cat.color,
        bg: cat.bg,
        isCustom: false,
        score: 0
    }))
);

interface PathologiesProps {
    initialQuery?: string;
    initialCategory?: string;
    onNavigate: (view: ViewState, params?: any) => void;
}

const PathologyRow = React.memo(({ item, isSelected, onClick }: { item: any, isSelected: boolean, onClick: (i: any) => void }) => {
    return (
        <button 
            onClick={() => onClick(item)} 
            className={`w-full text-left bg-white p-4 rounded-xl border transition-all flex items-center group relative overflow-hidden active:scale-[0.98] ${isSelected ? 'border-indigo-500 ring-1 ring-indigo-500 bg-indigo-50' : 'border-slate-200 hover:border-indigo-300'}`}
        >
            <div className={`p-3 rounded-lg mr-3 shrink-0 ${item.bg || 'bg-slate-50'} ${item.color || 'text-slate-600'} shadow-sm group-hover:scale-110 transition-transform relative`}>
                {item.icon ? <item.icon className="w-5 h-5"/> : <BookOpen className="w-5 h-5"/>}
                {item.isCustom && <div className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-emerald-500 rounded-full border-2 border-white shadow-sm"></div>}
            </div>
            <div className="flex-1 min-w-0">
                <div className={`text-sm font-bold text-slate-800 truncate group-hover:text-indigo-700 ${isSelected ? 'text-indigo-700' : ''}`}>
                    {item.name}
                </div>
                <div className="text-[10px] text-slate-500 font-bold uppercase tracking-wide mt-0.5">{item.category}</div>
            </div>
            <div className={`ml-2 p-2 rounded-lg transition-colors ${isSelected ? 'bg-indigo-600 text-white shadow-md' : 'bg-slate-50 group-hover:bg-indigo-100 group-hover:text-indigo-500'}`}>
                <ChevronRight className="w-4 h-4"/>
