        </button>
    );
});

export const Pathologies: React.FC<PathologiesProps> = ({ initialQuery, initialCategory, onNavigate }) => {
  const [query, setQuery] = useState(initialQuery || '');
  const [filterQuery, setFilterQuery] = useState(initialQuery || '');
  const [selectedCategory, setSelectedCategory] = useState<string>(initialCategory || 'ALL');
  const [selectedPathology, setSelectedPathology] = useState<Pathology | null>(null);
  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState<'CLINICAL' | 'PHARMA' | 'PAE'>('CLINICAL');
  const [customPathologies, setCustomPathologies] = useState<Pathology[]>([]);
  const [isSaving, setIsSaving] = useState(false);

  const loadCustomData = async () => {
      const data = await PathologyService.getAll();
      setCustomPathologies(data);
  };

  useEffect(() => { loadCustomData(); }, []);

  useEffect(() => {
      const timer = setTimeout(() => setFilterQuery(query), 200);
      return () => clearTimeout(timer);
  }, [query]);

  const organizedList = useMemo(() => {
      const q = (filterQuery || '').toLowerCase().trim();
      let activeItems = [...FLATTENED_STATIC_CATALOG];

      // Merge saved pathologies with distinctive icon
      customPathologies.forEach(p => {
          // Check if already in static catalog to avoid dupes, or update them
          const existingIdx = activeItems.findIndex(i => i.name.toLowerCase() === p.name.toLowerCase());
          if (existingIdx !== -1) {
              activeItems[existingIdx] = { 
                  ...activeItems[existingIdx], 
                  isCustom: true, 
                  pathology: p 
              } as any;
          } else {
              activeItems.push({
                  name: p.name,
                  category: p.family || 'Biblioteca Local',
                  icon: Bookmark,
                  color: 'text-indigo-600',
                  bg: 'bg-indigo-50',
                  isCustom: true,
                  score: 0,
                  pathology: p
              } as any);
          }
      });

      let filtered = activeItems;
      if (q) {
          filtered = activeItems.reduce((acc: any[], item) => {
              let score = 0;
              const n = (item.name || '').toLowerCase();
              const c = (item.category || '').toLowerCase();
              if (n === q) score = 100;
              else if (n.startsWith(q)) score = 80;
              else if (n.includes(q)) score = 50;
              else if (c.includes(q)) score = 20;

              if (score > 0) acc.push({ ...item, score });
              return acc;
          }, []).sort((a: any, b: any) => b.score - a.score);
      } else if (selectedCategory !== 'ALL') {
          filtered = activeItems.filter(i => i.category === selectedCategory);
      }

      const grouped: Record<string, any[]> = {};
      filtered.forEach(item => {
          const cat = item.category || 'Otros';
          if(!grouped[cat]) grouped[cat] = [];
          grouped[cat].push(item);
      });
      return grouped;
  }, [filterQuery, selectedCategory, customPathologies]);

  const sortedKeys = Object.keys(organizedList).sort();

  const handleSelectPathology = async (item: any) => {
      if (item.pathology) {
          setSelectedPathology(item.pathology);
          setActiveTab('CLINICAL');
          return;
      }
      setLoading(true);
      try {
          const result = await generatePathology(item.name);
          setSelectedPathology(result);
          setActiveTab('CLINICAL');
      } catch (e) { 
          alert("Error generando ficha técnica. Intente nuevamente.");
      } finally { 
          setLoading(false); 
      }
  };

  const handleSaveToLibrary = async () => {
      if (!selectedPathology) return;
      setIsSaving(true);
      try {
          const toSave = { ...selectedPathology, id: `path-${Date.now()}` };
          await PathologyService.add(toSave);
          await loadCustomData();
          setSelectedPathology(toSave); // Update state with local ID
          alert("Patología guardada permanentemente en tu biblioteca local.");
      } catch (e) {
          console.error(e);
      } finally {
          setIsSaving(false);
      }
  };

  const isSaved = useMemo(() => {
      if (!selectedPathology) return false;
      return customPathologies.some(p => p.name.toLowerCase() === selectedPathology.name.toLowerCase());
  }, [selectedPathology, customPathologies]);

  const handleDelete = async (id: string) => {
      if (confirm("¿Eliminar esta patología de tu biblioteca personal?")) {
          await PathologyService.delete(id);
          await loadCustomData();
          setSelectedPathology(null);
      }
  };

  return (
    <div className="flex h-full bg-slate-100 overflow-hidden font-sans relative">
        {/* PANEL LATERAL: LISTADO */}
        <div className={`w-full md:w-[450px] bg-white border-r border-slate-200 flex flex-col h-full shrink-0 z-20 shadow-xl transition-all duration-300 ${selectedPathology || loading ? 'hidden md:flex' : 'flex'}`}>
            <div className="p-4 bg-slate-900 text-white shrink-0">
                <div className="flex justify-between items-center mb-4">
                    <div className="flex items-center gap-2">
                        <Library className="w-5 h-5 text-emerald-400"/>
                        <h2 className="font-black text-xs uppercase tracking-[0.2em] text-white">Manual Clínico v22</h2>
                    </div>
                </div>
                <div className="relative group">
                    <Search className="absolute left-3 top-3.5 text-slate-500 w-4 h-4 group-focus-within:text-emerald-500 transition-colors"/>
                    <input 
                        type="text" 
                        value={query}
                        onChange={e => setQuery(e.target.value)}
                        placeholder="Buscar en +400 patologías..." 
                        className="w-full pl-10 pr-10 py-3.5 bg-slate-800 border border-slate-700 rounded-2xl text-sm font-bold text-white focus:border-emerald-500 focus:ring-4 focus:ring-emerald-500/10 outline-none transition-all placeholder-slate-500"
                    />
                    {query && <button onClick={() => setQuery('')} className="absolute right-3 top-3.5 text-slate-500 hover:text-white"><X className="w-4 h-4"/></button>}
                </div>

                <div className="flex gap-2 mt-4 overflow-x-auto no-scrollbar pb-1">
                    <button onClick={() => setSelectedCategory('ALL')} className={`px-3 py-1.5 rounded-lg text-[9px] font-black uppercase whitespace-nowrap border transition-all ${selectedCategory === 'ALL' ? 'bg-white text-slate-900 border-white shadow-md' : 'bg-slate-800/50 text-slate-400 border-transparent hover:bg-slate-800'}`}>TODAS</button>
                    {RAW_CATALOG.map(cat => (
                        <button key={cat.category} onClick={() => setSelectedCategory(cat.category)} className={`px-3 py-1.5 rounded-lg text-[9px] font-black uppercase whitespace-nowrap border transition-all ${selectedCategory === cat.category ? 'bg-white text-slate-900 border-white shadow-md' : 'bg-slate-800/50 text-slate-400 border-transparent hover:bg-slate-800'}`}>{cat.category}</button>
                    ))}
                    {customPathologies.length > 0 && (
                        <button onClick={() => setSelectedCategory('Biblioteca Local')} className={`px-3 py-1.5 rounded-lg text-[9px] font-black uppercase whitespace-nowrap border transition-all ${selectedCategory === 'Biblioteca Local' ? 'bg-indigo-600 text-white border-indigo-400 shadow-md' : 'bg-indigo-900/50 text-indigo-300 border-indigo-800 hover:bg-indigo-800'}`}>MIS GUARDADOS</button>
                    )}
                </div>
            </div>

            <div className="flex-1 overflow-y-auto custom-scrollbar p-2 bg-slate-50 space-y-1">
                {sortedKeys.length > 0 ? sortedKeys.map(key => (
                    <div key={key} className="mb-4">
                        <div className="sticky top-0 bg-slate-100/95 backdrop-blur z-10 py-2 px-3 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-200 mb-2 flex justify-between items-center rounded-lg shadow-sm">
                            <span className="flex items-center gap-2"><div className={`w-1.5 h-1.5 rounded-full ${key === 'Biblioteca Local' ? 'bg-indigo-500' : 'bg-slate-400'}`}></div> {key}</span>
                            <span className="bg-slate-200 text-slate-600 px-1.5 py-0.5 rounded-full text-[9px] font-bold">{organizedList[key].length}</span>
                        </div>
                        <div className="space-y-2 px-1">
                            {organizedList[key].map((item, idx) => (
                                <PathologyRow key={idx} item={item} isSelected={selectedPathology?.name === item.name} onClick={handleSelectPathology} />
                            ))}
                        </div>
                    </div>
                )) : (
                    <div className="flex flex-col items-center justify-center py-20 text-slate-400">
                        <Ghost className="w-12 h-12 opacity-20 mb-4"/>
                        <p className="text-xs font-black uppercase tracking-widest">Sin coincidencias</p>
                    </div>
                )}
            </div>
        </div>

        {/* PANEL DERECHO: DETALLE */}
        <div className={`flex-1 bg-white flex flex-col h-full overflow-hidden ${!selectedPathology && !loading ? 'hidden md:flex' : 'flex'}`}>
            {loading ? (
                <div className="flex-1 flex flex-col items-center justify-center p-8 bg-slate-50 animate-fade-in relative">
                    <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-5 pointer-events-none"></div>
                    <div className="relative">
                        <div className="w-24 h-24 border-4 border-indigo-100 border-t-indigo-600 rounded-full animate-spin"></div>
                        <Sparkles className="w-8 h-8 text-emerald-500 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 animate-pulse"/>
                    </div>
                    <h3 className="font-black text-slate-900 text-2xl tracking-tighter mt-8 uppercase">Florence Engine v22</h3>
                    <p className="text-sm text-slate-500 font-bold mt-2 text-center max-w-xs uppercase tracking-widest">Compilando guía clínica basada en evidencia y protocolos NANDA/NIC/NOC...</p>
                </div>
            ) : selectedPathology ? (
                <div className="flex flex-col h-full animate-fade-in bg-slate-50 relative">
                    <div className="bg-white border-b border-slate-200 p-6 shadow-sm sticky top-0 z-30">
                        <div className="flex items-start gap-5">
                            <button onClick={() => setSelectedPathology(null)} className="md:hidden p-2.5 bg-slate-100 rounded-full text-slate-600 hover:bg-slate-200 transition-colors active:scale-95 shadow-sm"><ArrowLeft className="w-5 h-5"/></button>
