                                >
                                    <div className={`p-2.5 rounded-lg mr-3 shrink-0 ${item.bg} ${item.color} shadow-sm group-hover:scale-110 transition-transform`}>
                                        <item.icon className="w-5 h-5"/>
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <div className={`text-sm font-bold truncate group-hover:text-indigo-700 ${selectedPathology?.name === item.name ? 'text-indigo-700' : 'text-slate-800'}`}>{item.name}</div>
                                        <div className="text-[9px] text-slate-400 font-bold uppercase tracking-tight">{item.category}</div>
                                    </div>
                                    {item.isSaved && (
                                        <div className="ml-2 bg-emerald-100 p-1 rounded-full text-emerald-600 shadow-sm" title="Guardado en biblioteca local">
                                            <Bookmark className="w-3 h-3 fill-current"/>
                                        </div>
                                    )}
                                    <ChevronRight className="w-4 h-4 text-slate-300 ml-2 group-hover:text-indigo-400"/>
                                </button>
                            ))}
                        </div>
                    </div>
                ))}
                {Object.keys(organizedList).length === 0 && (
                    <div className="flex flex-col items-center justify-center py-20 opacity-30">
                        <Ghost className="w-12 h-12 mb-4"/>
                        <p className="text-xs font-black uppercase">Sin resultados</p>
                    </div>
                )}
            </div>
        </div>

        {/* PANEL DERECHO: DETALLE BENTO */}
        <div className={`flex-1 bg-white flex flex-col h-full overflow-hidden ${!selectedPathology && !loading ? 'hidden md:flex' : 'flex'}`}>
            {loading ? (
                <div className="flex-1 flex flex-col items-center justify-center p-8 animate-fade-in">
                    <div className="relative">
                        <div className="w-24 h-24 border-4 border-indigo-100 border-t-indigo-600 rounded-full animate-spin"></div>
                        <Sparkles className="w-8 h-8 text-indigo-400 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 animate-pulse"/>
                    </div>
                    <h3 className="font-black text-slate-900 text-2xl tracking-tighter mt-8 uppercase">Florence Engine v22</h3>
                    <p className="text-sm text-slate-500 font-bold mt-2 text-center max-w-xs">Consultando bases de datos de evidencia NANDA/NIC/NOC y protocolos actualizados...</p>
                </div>
            ) : selectedPathology ? (
                <div className="flex flex-col h-full animate-fade-in bg-slate-50/50">

                    {/* Header Bento */}
                    <div className="bg-white border-b border-slate-200 p-6 shadow-sm sticky top-0 z-30">
                        <div className="max-w-6xl mx-auto flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                            <div className="flex items-start gap-5">
                                <button onClick={() => setSelectedPathology(null)} className="md:hidden p-2.5 bg-slate-100 rounded-full text-slate-500 hover:bg-slate-200 transition-colors shadow-sm"><ArrowLeft className="w-5 h-5"/></button>
                                <div>
                                    <div className="flex flex-wrap items-center gap-2 mb-2">
                                        <span className="bg-indigo-600 text-white text-[10px] font-black px-2.5 py-1 rounded-lg uppercase tracking-widest shadow-lg shadow-indigo-900/20">{selectedPathology.family || 'Manual Clínico'}</span>
                                        {selectedPathology.cie10 && <span className="bg-slate-900 text-white text-[10px] font-black px-2 py-1 rounded-lg border border-slate-700">CIE-10: {selectedPathology.cie10}</span>}
                                        {isCurrentSaved && <span className="bg-emerald-500 text-white text-[9px] font-black px-2 py-1 rounded-lg shadow-sm flex items-center gap-1"><ShieldCheck className="w-3 h-3"/> BIBLIOTECA LOCAL</span>}
                                    </div>
                                    <h1 className="text-2xl md:text-5xl font-black text-slate-900 leading-tight uppercase tracking-tighter drop-shadow-sm">{selectedPathology.name}</h1>
                                </div>
                            </div>
                            <div className="flex gap-3 w-full md:w-auto">
                                {!isCurrentSaved ? (
                                    <button 
