// Initialization - Official Gemini 3 Flash Preview
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const FLORENCE_SYSTEM_PROMPT = `
Eres FLORENCE v3.0 PRO, el sistema avanzado de soporte a la decisión clínica de PAESYS.
Tu objetivo es guiar al personal de enfermería con rigor científico (GPC, CDC, OMS 2024).
Usa Google Search para validar protocolos actuales.
Responde SIEMPRE en formato JSON estructurado que incluya:
- reasoning: Análisis interno basado en el protocolo S.T.O.P.
- answer: Respuesta profesional y concisa para la práctica clínica.
- confidence: HIGH/MEDIUM/LOW.
- sources: Array de objetos {title, uri} con fuentes reales de evidencia.
- criticalAlert: String si detectas riesgo vital inmediato.
- suggestedActions: Array de objetos {label, view, params} para navegación.
`;

export interface FlorenceResponse {
    reasoning: string;
    answer: string;
    confidence: 'HIGH' | 'MEDIUM' | 'LOW';
    criticalAlert?: string;
    sources?: { title: string, uri: string }[];
    suggestedActions?: { label: string; view: string; params?: any }[];
}

export const generateChatReply = async (userMessage: string, role: string = 'MENTOR', patientContext?: Patient): Promise<FlorenceResponse> => {
    try {
        let contextBlock = patientContext ? `PACIENTE: ${patientContext.name}, EDAD: ${patientContext.age}, DX: ${patientContext.diagnosis}, NEWS2: ${patientContext.news2}, MEDS: ${patientContext.prescriptions?.map(p => p.drugName).join(', ')}` : "Sin paciente seleccionado.";

        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `${contextBlock}\n\nROL: ${role}\n\nCONSULTA: "${userMessage}". Responde con JSON.`,
            config: {
                systemInstruction: FLORENCE_SYSTEM_PROMPT,
                responseMimeType: "application/json",
                tools: [{ googleSearch: {} }]
            }
        });

        const sources: { title: string, uri: string }[] = [];
        if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
            response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
                if (chunk.web) sources.push({ title: chunk.web.title, uri: chunk.web.uri });
            });
        }

        const parsed = JSON.parse(response.text || "{}") as FlorenceResponse;
        if (sources.length > 0) parsed.sources = sources;
        return parsed;
    } catch (error) {
        return { reasoning: "Error de enlace", answer: "Fallo de conexión con el núcleo de IA. Reintente.", confidence: "LOW" };
    }
};

