);

export const Pathologies: React.FC<{initialQuery?: string, initialCategory?: string, onNavigate: any}> = ({ initialQuery, initialCategory, onNavigate }) => {
  const [query, setQuery] = useState(initialQuery || '');
  const [selectedPathology, setSelectedPathology] = useState<Pathology | null>(null);
  const [loading, setLoading] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [localPathologies, setLocalPathologies] = useState<Pathology[]>([]);
  const [selectedCategory, setSelectedCategory] = useState(initialCategory || 'ALL');

  const contentRef = useRef<HTMLDivElement>(null);
  const [activeSection, setActiveSection] = useState('overview');

  const loadLocalData = async () => {
    const data = await PathologyService.getAll();
    setLocalPathologies(data);
  };

  useEffect(() => { loadLocalData(); }, []);

  const organizedList = useMemo(() => {
    const q = query.toLowerCase().trim();
    let items = [...FLATTENED_CATALOG];

    items = items.map(it => ({
        ...it,
        isSaved: localPathologies.some(lp => lp.name.toLowerCase() === it.name.toLowerCase())
    }));

    localPathologies.forEach(lp => {
        if (!items.some(it => it.name.toLowerCase() === lp.name.toLowerCase())) {
            items.push({
                name: lp.name,
                category: lp.family || 'Biblioteca Personal',
                icon: Bookmark,
                color: 'text-indigo-600',
                bg: 'bg-indigo-50',
                isCustom: true,
                isSaved: true
            } as any);
        }
    });

    let filtered = items;
    if (q) {
        filtered = items.filter(i => i.name.toLowerCase().includes(q) || i.category.toLowerCase().includes(q));
    } else if (selectedCategory !== 'ALL') {
        filtered = items.filter(i => i.category === selectedCategory);
    }

    const grouped: Record<string, any[]> = {};
    filtered.sort((a,b) => a.name.localeCompare(b.name)).forEach(item => {
        const cat = item.category;
        if (!grouped[cat]) grouped[cat] = [];
        grouped[cat].push(item);
    });
    return grouped;
  }, [query, localPathologies, selectedCategory]);

  const handleSelect = async (item: any) => {
    const local = localPathologies.find(lp => lp.name.toLowerCase() === item.name.toLowerCase());
    if (local) {
        setSelectedPathology(local);
        return;
    }

    setLoading(true);
    try {
        const res = await generatePathology(item.name);
        setSelectedPathology(res);
    } catch (e) {
        alert("Error al conectar con Florence Engine.");
    } finally {
        setLoading(false);
    }
  };

  const handleSave = async () => {
    if (!selectedPathology) return;
    setIsSaving(true);
    try {
        const toSave = { ...selectedPathology, id: `loc-${Date.now()}` };
        await PathologyService.add(toSave);
        await loadLocalData();
        setSelectedPathology(toSave);
    } catch (e) {
        console.error(e);
    } finally {
        setIsSaving(false);
    }
  };

  const scrollToSection = (id: string) => {
      const el = document.getElementById(`section-${id}`);
      if (el) {
          el.scrollIntoView({ behavior: 'smooth', block: 'start' });
          setActiveSection(id);
      }
  };

  const isCurrentSaved = selectedPathology?.id?.startsWith('loc-') || localPathologies.some(lp => lp.name.toLowerCase() === selectedPathology?.name.toLowerCase());

  const SECTIONS = [
      { id: 'overview', label: 'Perfil Clínico', icon: Activity },
      { id: 'diagnosis', label: 'Diagnóstico', icon: FlaskConical },
      { id: 'management', label: 'Manejo & Farma', icon: Pill },
      { id: 'pae', label: 'Plan PAE', icon: BookOpen },
      { id: 'education', label: 'Educación', icon: GraduationCap }
  ];

  return (
    <div className="flex h-full bg-slate-100 overflow-hidden font-sans relative">

        {/* SIDEBAR: EXPLORADOR */}
        <div className={`w-full md:w-[380px] bg-white border-r border-slate-200 flex flex-col h-full shrink-0 z-20 shadow-xl transition-all duration-300 ${selectedPathology || loading ? 'hidden md:flex' : 'flex'}`}>
            <div className="p-4 bg-slate-900 text-white shrink-0">
                <div className="flex justify-between items-center mb-4">
                    <div className="flex items-center gap-2">
                        <Library className="w-5 h-5 text-emerald-400"/>
                        <h2 className="font-black text-xs uppercase tracking-[0.2em]">Biblioteca Clínica v22</h2>
                    </div>
                </div>
                <div className="relative">
                    <Search className="absolute left-3 top-3.5 text-slate-500 w-4 h-4"/>
                    <input 
                        type="text" 
                        value={query}
                        onChange={e => setQuery(e.target.value)}
                        placeholder="CIE-10 o Patología..." 
                        className="w-full pl-10 pr-4 py-3 bg-slate-800 border border-slate-700 rounded-2xl text-sm font-bold text-white focus:border-indigo-500 outline-none transition-all placeholder-slate-500"
                    />
                </div>
                <div className="flex gap-2 mt-4 overflow-x-auto no-scrollbar pb-1">
                    <button onClick={() => setSelectedCategory('ALL')} className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase whitespace-nowrap border transition-all ${selectedCategory === 'ALL' ? 'bg-white text-slate-900 border-white' : 'bg-slate-800 text-slate-400 border-transparent hover:bg-slate-700'}`}>Todas</button>
                    {RAW_CATALOG.map(cat => (
                        <button key={cat.category} onClick={() => setSelectedCategory(cat.category)} className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase whitespace-nowrap border transition-all ${selectedCategory === cat.category ? 'bg-white text-slate-900 border-white' : 'bg-slate-800 text-slate-400 border-transparent hover:bg-slate-700'}`}>{cat.category}</button>
                    ))}
                </div>
            </div>

            <div className="flex-1 overflow-y-auto custom-scrollbar p-2 bg-slate-50">
                {Object.keys(organizedList).sort().map(cat => (
                    <div key={cat} className="mb-4">
                        <div className="sticky top-0 bg-slate-100/95 backdrop-blur z-10 py-2 px-3 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-200 mb-2 flex justify-between items-center">
                            <span>{cat}</span>
                            <span className="bg-slate-200 text-slate-500 px-1.5 py-0.5 rounded-full text-[8px]">{organizedList[cat].length}</span>
                        </div>
                        <div className="space-y-1">
                            {organizedList[cat].map((item, idx) => (
                                <button 
                                    key={idx} 
                                    onClick={() => handleSelect(item)}
                                    className={`w-full text-left p-3 rounded-xl border transition-all flex items-center group relative overflow-hidden ${selectedPathology?.name === item.name ? 'bg-white border-indigo-500 shadow-md ring-1 ring-indigo-500' : 'bg-white border-slate-200 hover:border-indigo-300'}`}
                                >
                                    <div className={`p-2.5 rounded-lg mr-3 shrink-0 ${item.bg} ${item.color} shadow-sm group-hover:scale-110 transition-transform`}>
                                        <item.icon className="w-5 h-5"/>
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <div className={`text-sm font-bold truncate group-hover:text-indigo-700 ${selectedPathology?.name === item.name ? 'text-indigo-700' : 'text-slate-800'}`}>{item.name}</div>
                                        <div className="text-[9px] text-slate-400 font-bold uppercase tracking-tight">{item.category}</div>
                                    </div>
                                    {item.isSaved && <Bookmark className="w-3 h-3 text-emerald-500 fill-current ml-2"/>}
                                </button>
                            ))}
                        </div>
                    </div>
                ))}
            </div>
        </div>

        {/* PANEL DERECHO: DETALLE ENORME */}
        <div className={`flex-1 bg-white flex flex-col h-full overflow-hidden ${!selectedPathology && !loading ? 'hidden md:flex' : 'flex'}`}>
            {loading ? (
                <div className="flex-1 flex flex-col items-center justify-center p-8 bg-slate-50 animate-fade-in">
                    <div className="relative mb-8">
                        <div className="w-24 h-24 border-4 border-indigo-100 border-t-indigo-600 rounded-full animate-spin"></div>
                        <Sparkles className="w-8 h-8 text-indigo-400 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 animate-pulse"/>
                    </div>
                    <h3 className="font-black text-slate-900 text-3xl tracking-tighter uppercase mb-2">Compilando Dossier Clínico</h3>
                    <p className="text-sm text-slate-500 font-bold max-w-xs text-center uppercase tracking-widest leading-relaxed">Florence Engine v22 extrayendo evidencia científica GPC, NANDA 2024 y farmacopea hospitalaria...</p>
                </div>
            ) : selectedPathology ? (
                <div className="flex flex-col h-full animate-fade-in bg-white relative">

                    {/* Sticky Professional Header */}
                    <div className="bg-white border-b border-slate-200 p-6 shadow-sm sticky top-0 z-30">
                        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                            <div className="flex items-start gap-5">
                                <button onClick={() => setSelectedPathology(null)} className="md:hidden p-2.5 bg-slate-100 rounded-full text-slate-500 hover:bg-slate-200 transition-colors shadow-sm"><ArrowLeft className="w-5 h-5"/></button>
                                <div>
                                    <div className="flex flex-wrap items-center gap-2 mb-2">
                                        <span className="bg-indigo-600 text-white text-[10px] font-black px-2.5 py-1 rounded-lg uppercase tracking-widest shadow-lg shadow-indigo-900/20">{selectedPathology.family || 'Clínica General'}</span>
                                        {selectedPathology.cie10 && <span className="bg-slate-900 text-white text-[10px] font-black px-2 py-1 rounded-lg border border-slate-700">CIE-10: {selectedPathology.cie10}</span>}
                                        {isCurrentSaved && <span className="bg-emerald-500 text-white text-[9px] font-black px-2 py-1 rounded-lg shadow-sm flex items-center gap-1"><ShieldCheck className="w-3 h-3"/> BIBLIOTECA LOCAL</span>}
                                    </div>
                                    <h1 className="text-2xl md:text-5xl font-black text-slate-900 leading-tight uppercase tracking-tighter drop-shadow-sm">{selectedPathology.name}</h1>
                                </div>
                            </div>
                            <div className="flex gap-3 w-full md:w-auto">
                                {!isCurrentSaved ? (
                                    <button 
                                        onClick={handleSave} 
                                        disabled={isSaving}
                                        className="flex-1 md:flex-none bg-indigo-600 hover:bg-indigo-700 text-white px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl shadow-indigo-600/20 flex items-center justify-center gap-2 active:scale-95 transition-all disabled:opacity-50"
                                    >
                                        {isSaving ? <Loader2 className="w-4 h-4 animate-spin"/> : <Save className="w-5 h-5"/>} 
                                        Indexar en Biblioteca
                                    </button>
                                ) : (
                                    <button className="flex-1 md:flex-none bg-emerald-50 text-emerald-700 px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest border border-emerald-200 flex items-center justify-center gap-2 cursor-default">
                                        <CheckCircle2 className="w-5 h-5"/> Guardado
