                                            <h3 className="text-[10px] font-black text-indigo-300 uppercase tracking-[0.2em] mb-6 flex items-center"><Activity className="w-5 h-5 mr-3"/> Etiología & Causas</h3>
                                            <p className="text-base font-bold text-indigo-50 leading-relaxed relative z-10">{selectedPathology.generalInfo?.etiology}</p>
                                        </div>
                                        {selectedPathology.generalInfo?.redFlags && (
