const db = {
    collection: (name: string) => {
        const getData = () => {
            const data = localStorage.getItem(name);
            if (!data || data === 'null') {
                const initial = name === DB_KEYS.PATIENTS ? INITIAL_PATIENTS_SEED : [];
                localStorage.setItem(name, JSON.stringify(initial));
                return initial;
            }
            try {
                const parsed = JSON.parse(data);
                return Array.isArray(parsed) ? parsed : [];
            } catch (e) {
                return [];
            }
        };

        return {
            get: async () => getData(),
            add: async (doc: any) => {
                const data = getData();
                if (!doc.id) doc.id = `${name.slice(0,3)}_${Date.now()}`;
                const newData = [...data, doc];
                localStorage.setItem(name, JSON.stringify(newData));
                return doc;
            },
            update: async (id: string, updates: any) => {
                const data = getData();
                const idx = data.findIndex((d: any) => d.id === id);
                if (idx !== -1) {
                    data[idx] = { ...data[idx], ...updates };
                    localStorage.setItem(name, JSON.stringify(data));
                }
            },
            delete: async (id: string) => {
                const data = getData();
                const newData = data.filter((d: any) => d.id !== id);
                localStorage.setItem(name, JSON.stringify(newData));
            },
            doc: (id: string) => {
                return {
                    get: async () => getData().find((d: any) => d.id === id),
                    set: async (docData: any) => {
                        const data = getData();
                        const idx = data.findIndex((d: any) => d.id === id);
                        if (idx !== -1) {
                            data[idx] = { ...data[idx], ...docData };
                        } else {
                            data.push({ ...docData, id });
                        }
                        localStorage.setItem(name, JSON.stringify(data));
                    }
                }
            },
            clear: async () => {
                localStorage.removeItem(name);
                return [];
            }
        };
    }
};

export const AuthService = {
    register: async (email: string, password: string, name: string): Promise<User> => {
        const staffList = await db.collection(DB_KEYS.STAFF).get();
        if (staffList.find((u: any) => u.email === email)) throw new Error("Ya registrado.");
        const newStaff: User = {
            id: `uid_${Date.now()}`, email, name, role: 'NURSE', provider: 'EMAIL',
            avatar: `https://ui-avatars.com/api/?name=${encodeURIComponent(name)}&background=random&color=fff`,
            unit: 'General', collegiateNumber: 'PENDIENTE', lastLogin: new Date().toISOString()
        };
        await db.collection(DB_KEYS.STAFF).add({ ...newStaff, password });
        return AuthService.createSession(newStaff);
    },
    login: async (email: string, password: string): Promise<User> => {
        const staffList = await db.collection(DB_KEYS.STAFF).get();
        if (email === 'admin@paesys.com' && password === 'admin') {
            return AuthService.createSession({
                id: 'admin_master', email: 'admin@paesys.com', name: 'Admin Pro', role: 'ADMIN', provider: 'EMAIL',
                avatar: 'https://ui-avatars.com/api/?name=Admin&background=0D9488&color=fff', unit: 'Dirección'
            });
        }
        const userDoc = staffList.find((u: any) => u.email === email && u.password === password);
        if (!userDoc) throw new Error("Credenciales inválidas.");
        return AuthService.createSession(userDoc);
    },
    updateProfile: async (user: User): Promise<User> => {
        await db.collection(DB_KEYS.STAFF).update(user.id, user);
        return AuthService.createSession(user);
    },
    socialLogin: async (provider: 'GOOGLE' | 'APPLE'): Promise<User> => {
        const uid = `${provider}_${Date.now()}`;
        const newStaff: User = {
            id: uid, email: `${provider.toLowerCase()}@paesys.com`, name: `${provider} User`, role: 'NURSE',
            provider, avatar: `https://ui-avatars.com/api/?name=${provider}&background=random&color=fff`,
            unit: 'Rotatorio', lastLogin: new Date().toISOString()
        };
        await db.collection(DB_KEYS.STAFF).doc(uid).set(newStaff);
        return AuthService.createSession(newStaff);
    },
    createSession: (user: User): User => {
        localStorage.setItem(DB_KEYS.SESSION, JSON.stringify(user));
        return user;
    },
    logout: () => localStorage.removeItem(DB_KEYS.SESSION),
    getCurrentUser: (): User | null => {
        const data = localStorage.getItem(DB_KEYS.SESSION);
        if(!data || data === 'null') return null;
        try { return JSON.parse(data); } catch(e) { return null; }
    }
};

